// Version 0.7 Vidu scene production management
const VIDU_STATUSES=['未着手','プロンプト作成','画像準備','生成中','完成','採用','保留'];
const VIDU_PROGRESS={未着手:0,プロンプト作成:20,画像準備:40,生成中:65,完成:85,採用:100,保留:50};
function defaultViduProduction(){const t=now();return{japanesePrompt:'',englishPrompt:'',negativePrompt:'',referenceImages:[],generatedVideos:[],projectUrl:'',model:'',aspectRatio:'',durationSeconds:'',creditsUsed:'',memo:'',status:'未着手',createdAt:t,updatedAt:t}}
function normalizeViduProduction(v={}){const base=defaultViduProduction(),out={...base,...(v||{})};out.referenceImages=Array.isArray(out.referenceImages)?out.referenceImages:parseLines(out.referenceImages);out.generatedVideos=Array.isArray(out.generatedVideos)?out.generatedVideos:parseLines(out.generatedVideos);out.status=VIDU_STATUSES.includes(out.status)?out.status:'未着手';out.createdAt=out.createdAt||out.updatedAt||now();out.updatedAt=out.updatedAt||out.createdAt;return out}
function ensureV07(){ensureV06();(state.scenes||[]).forEach(s=>{s.vidu=normalizeViduProduction(s.vidu);s.completionRate=sceneCompletionRate(s)})}
function parseLines(v){return String(v||'').split('\n').map(x=>x.trim()).filter(Boolean)}
function viduProgress(v){return VIDU_PROGRESS[normalizeViduProduction(v).status]??0}
function sceneCompletionRate(scene){const baseProgress=scene.progress?PROGRESS_FIELDS.reduce((sum,k)=>sum+clampPercent(scene.progress?.[k]),0)/PROGRESS_FIELDS.length:0;const base=clampPercent(baseProgress||Number.parseInt(scene.completionRate)||0);const vp=viduProgress(scene.vidu);return Math.round(base?((base+vp)/2):vp)}
function viduCompletedVideos(v){return normalizeViduProduction(v).generatedVideos.length}
function viduCard(scene){const v=normalizeViduProduction(scene.vidu);return `<details class="vidu-card" open><summary><span>Vidu制作</span><span class="type-pill">${esc(v.status)}</span><span class="meta">完成動画：${viduCompletedVideos(v)} / 更新：${esc(v.updatedAt||'未記録')}</span></summary><div class="vidu-actions">${v.projectUrl?`<button onclick="openViduUrl('${scene.id}')">Viduを開く</button>`:''}<button onclick="editVidu('${scene.id}')">Viduを編集</button></div><div class="stats"><div><b>完成率</b><span>${viduProgress(v)}%</span></div><div><b>使用モデル</b><span>${esc(v.model||'未設定')}</span></div><div><b>アスペクト比</b><span>${esc(v.aspectRatio||'未設定')}</span></div><div><b>動画秒数</b><span>${esc(v.durationSeconds||'未設定')}</span></div><div><b>クレジット</b><span>${esc(v.creditsUsed||'未設定')}</span></div></div><section><h3>日本語プロンプト</h3><p>${esc(v.japanesePrompt||'未入力')}</p></section><section><h3>英語プロンプト</h3><p>${esc(v.englishPrompt||'未入力')}</p></section><section><h3>ネガティブプロンプト</h3><p>${esc(v.negativePrompt||'未入力')}</p></section><div class="vidu-lists"><section><h3>参照画像一覧</h3>${mediaList(v.referenceImages)}</section><section><h3>生成動画一覧</h3>${mediaList(v.generatedVideos)}</section></div><section><h3>制作メモ</h3><p>${esc(v.memo||'未入力')}</p></section><p class="meta">作成：${esc(v.createdAt)} / 更新：${esc(v.updatedAt)}</p></details>`}
function mediaList(items){return items.length?`<ul class="media-list">${items.map(x=>`<li>${isUrl(x)?`<a href="${esc(x)}" target="_blank" rel="noopener">${esc(x)}</a>`:esc(x)}</li>`).join('')}</ul>`:'<p class="meta">未登録</p>'}
function isUrl(x){return /^https?:\/\//i.test(String(x||''))}
function openViduUrl(sceneId){const s=state.scenes.find(x=>x.id===sceneId),url=s?.vidu?.projectUrl;if(url)window.open(url,'_blank','noopener')}
function editVidu(sceneId){const s=state.scenes.find(x=>x.id===sceneId);if(!s)return;const v=normalizeViduProduction(s.vidu);modal(`<h2>Vidu制作管理：${esc(storyTitle('scenes',s))}</h2><form data-dirty="false" oninput="this.dataset.dirty='true'">${group('プロンプト',`<label>日本語プロンプト<textarea id="v_japanesePrompt" rows="5">${esc(v.japanesePrompt)}</textarea></label><label>英語プロンプト<textarea id="v_englishPrompt" rows="5">${esc(v.englishPrompt)}</textarea></label><label>ネガティブプロンプト<textarea id="v_negativePrompt" rows="3">${esc(v.negativePrompt)}</textarea></label>`)}${group('素材・生成物',`<label>参照画像一覧（1行に1件）<textarea id="v_referenceImages" rows="5">${esc(v.referenceImages.join('\n'))}</textarea></label><label>生成動画一覧（1行に1件）<textarea id="v_generatedVideos" rows="5">${esc(v.generatedVideos.join('\n'))}</textarea></label><label>ViduプロジェクトURL<input id="v_projectUrl" value="${esc(v.projectUrl)}"></label>`)}${group('制作設定',`<label>状態<select id="v_status">${VIDU_STATUSES.map(x=>`<option ${v.status===x?'selected':''}>${x}</option>`).join('')}</select></label><label>使用モデル<input id="v_model" value="${esc(v.model)}"></label><label>アスペクト比<input id="v_aspectRatio" value="${esc(v.aspectRatio)}" placeholder="16:9 / 9:16 / 1:1"></label><label>動画秒数<input id="v_durationSeconds" inputmode="numeric" value="${esc(v.durationSeconds)}"></label><label>クレジット使用数<input id="v_creditsUsed" inputmode="decimal" value="${esc(v.creditsUsed)}"></label><label>制作メモ<textarea id="v_memo" rows="5">${esc(v.memo)}</textarea></label>`)}<p class="meta">作成日時：${esc(v.createdAt)} / 更新日時：${esc(v.updatedAt)} / 自動完成率：${viduProgress(v)}%</p><button type="button" onclick="saveVidu('${sceneId}')">保存</button></form>`)}
function saveVidu(sceneId){const s=state.scenes.find(x=>x.id===sceneId);if(!s)return;const before=JSON.stringify(s);const old=normalizeViduProduction(s.vidu);s.vidu={...old,japanesePrompt:$('#v_japanesePrompt').value,englishPrompt:$('#v_englishPrompt').value,negativePrompt:$('#v_negativePrompt').value,referenceImages:parseLines($('#v_referenceImages').value),generatedVideos:parseLines($('#v_generatedVideos').value),projectUrl:$('#v_projectUrl').value,model:$('#v_model').value,aspectRatio:$('#v_aspectRatio').value,durationSeconds:$('#v_durationSeconds').value,creditsUsed:$('#v_creditsUsed').value,memo:$('#v_memo').value,status:$('#v_status').value,createdAt:old.createdAt,updatedAt:now()};s.completionRate=sceneCompletionRate(s);touch(s);recordHistory(s,before);saveState();closeModal();openSceneDetail(sceneId);toast('Vidu制作を保存しました')}
const v07OpenSceneDetail=openSceneDetail;openSceneDetail=function(id){ensureV07();const s=state.scenes.find(x=>x.id===id);if(!s)return v07OpenSceneDetail(id);const scenes=state.scenes.filter(x=>x.episodeId===s.episodeId&&!x.isArchived).sort((a,b)=>(+a.sortOrder||0)-(+b.sortOrder||0));const i=scenes.findIndex(x=>x.id===id),prev=scenes[i-1],next=scenes[i+1];modal(`<h2>${esc(storyTitle('scenes',s))}</h2>${['sceneNumber','title','location','timeOfDay','summary','script','charactersText','termsText','worldsText','memo','completionRate','status'].map(f=>`<section><h3>${esc(FIELD_LABELS[f])}</h3><p>${esc(s[f]||'')}</p></section>`).join('')}${viduCard(s)}<p>${itemTagsHtml(s)}<br>${metaLine(s)}</p><div class="row"><button ${!prev?'disabled':''} onclick="openSceneDetail('${prev?.id||''}')">← 前のシーン</button><button ${!next?'disabled':''} onclick="openSceneDetail('${next?.id||''}')">次のシーン →</button></div><h3>関連リンク</h3>${relatedCards(s)}<button onclick="editStoryItem('scenes','${id}')">編集</button>`)};
const v07SaveStoryItem=saveStoryItem;saveStoryItem=function(collection,id=''){v07SaveStoryItem(collection,id);if(collection==='scenes'){ensureV07();saveState(true)}};
const v07ItemProgress=itemProgress;itemProgress=function(item){const base=v07ItemProgress(item);return item?.type==='scene'||state.scenes?.some(s=>s.id===item?.id)?Math.round((base+viduProgress(item.vidu))/2):base};
const v07SearchableItems=searchableItems;searchableItems=function(){ensureV07();return v07SearchableItems()};
const v07SearchAll=searchAll;searchAll=function(q,show=false){const box=show?$('#searchResults'):null;if(!q){if(box)box.innerHTML='';return}q=q.toLowerCase().trim();let res=searchableItems().filter(({collection,item,type,title})=>[title,item.memo,item.summary,item.description,typeLabel(type),type,item.subtitle,item.chapter,(item.tags||[]).join(' '),item.vidu?.japanesePrompt,item.vidu?.englishPrompt,item.vidu?.negativePrompt,item.vidu?.memo].join(' ').toLowerCase().includes(q));const html=res.map(({collection,item,type,title})=>`<div class="row"><span><b>${esc(typeLabel(type))}</b>：${esc(title)}<br><small>${itemTagsHtml(item)} ${metaLine(item)}</small></span><button onclick="openSearchResult('${collection}','${item.id}')">開く/選択</button></div>`).join('')||'<p>見つかりません。</p>';if(box)box.innerHTML=html;else modal(`<h2>検索結果</h2>${html}`)};
const v07Render=render;render=function(){ensureV07();v07Render()};
ensureV07();saveState(true);

// Version 0.7 production completion management
const NS_STEPS=['script','illustration','vidu','edit','audio','complete'];
const NS_STEP_LABELS={script:'台本',illustration:'イラスト',vidu:'Vidu',edit:'動画編集',audio:'音楽・音声',complete:'完成',publish:'公開'};
const ART_TYPES=['ラフ','線画','完成画像','背景','キャラクター','絵コンテ','その他'];
const ART_FORMATS=['PSD','CLIP','PNG','JPEG','WEBP','その他'];
const WORK_STATUSES=['未着手','制作中','完成'];
const ADOPT_STATUSES=['未選択','採用','保留','没'];
const EDIT_SOFTWARE=['Filmora','Final Cut Pro','Logic Pro','その他'];
const EDIT_STATUSES=['未着手','編集中','確認中','完成'];
const AUDIO_TYPES=['BGM','SE','歌','ナレーション','セリフ音声'];
const YT_STATUSES=['未準備','準備中','予約','公開','非公開'];
function nsTime(v){return v||now()}
function nsItem(prefix,x={}){const t=nsTime(x.createdAt||x.updatedAt);return{id:x.id||uid(prefix),title:x.title||'',type:x.type||'',fileName:x.fileName||'',location:x.location||x.url||'',format:x.format||'',usage:x.usage||'',workStatus:x.workStatus||x.status||'未着手',adoptionStatus:x.adoptionStatus||'未選択',memo:x.memo||x.productionMemo||'',createdAt:t,updatedAt:x.updatedAt||t,...x}}
function normalizeGeneratedVideo(x={}){if(typeof x==='string')x={title:x,location:x};const t=nsTime(x.createdAt||x.updatedAt);return{id:x.id||uid('genvideo'),title:x.title||x.fileName||x.location||'',fileName:x.fileName||'',location:x.location||x.url||'',adoptionStatus:x.adoptionStatus||'未選択',memo:x.memo||'',createdAt:t,updatedAt:x.updatedAt||t}}
function defaultVideoEdit(v={}){const t=nsTime(v.createdAt||v.updatedAt);return{software:v.software||'',projectName:v.projectName||'',projectFileLocation:v.projectFileLocation||'',materials:Array.isArray(v.materials)?v.materials:parseLines(v.materials),exports:(Array.isArray(v.exports)?v.exports:[]).map(normalizeGeneratedVideo),resolution:v.resolution||'',frameRate:v.frameRate||'',aspectRatio:v.aspectRatio||'',workStatus:v.workStatus||'未着手',adoptionStatus:v.adoptionStatus||'未選択',memo:v.memo||'',createdAt:t,updatedAt:v.updatedAt||t}}
function defaultCompletion(v={}){const t=nsTime(v.createdAt||v.updatedAt);return{finalVideo:v.finalVideo||'',reviewStatus:v.reviewStatus||'未確認',revisionMemo:v.revisionMemo||'',approvalStatus:v.approvalStatus||'未承認',completedDate:v.completedDate||'',relatedIllustrations:Array.isArray(v.relatedIllustrations)?v.relatedIllustrations:[],relatedViduVideos:Array.isArray(v.relatedViduVideos)?v.relatedViduVideos:[],relatedAudio:Array.isArray(v.relatedAudio)?v.relatedAudio:[],createdAt:t,updatedAt:v.updatedAt||t}}
function defaultYoutube(v={}){const t=nsTime(v.createdAt||v.updatedAt);return{title:v.title||'',description:v.description||'',tags:Array.isArray(v.tags)?v.tags:parseTags(v.tags),thumbnail:v.thumbnail||'',status:v.status||'未準備',scheduledAt:v.scheduledAt||'',publishedAt:v.publishedAt||'',url:v.url||'',memo:v.memo||'',createdAt:t,updatedAt:v.updatedAt||t}}
function normalizeSceneProduction(s){s.illustrations=(Array.isArray(s.illustrations)?s.illustrations:[]).map(x=>nsItem('art',x));s.vidu=normalizeViduProduction(s.vidu);s.vidu.generatedVideos=(Array.isArray(s.vidu.generatedVideos)?s.vidu.generatedVideos:parseLines(s.vidu.generatedVideos)).map(normalizeGeneratedVideo);s.vidu.referenceImages=Array.isArray(s.vidu.referenceImages)?s.vidu.referenceImages:parseLines(s.vidu.referenceImages);s.videoEdit=defaultVideoEdit(s.videoEdit||{});s.audioItems=(Array.isArray(s.audioItems)?s.audioItems:[]).map(x=>nsItem('audio',x));s.completion=defaultCompletion(s.completion||{});s.youtube=defaultYoutube(s.youtube||{});s.progress=s.progress||{};NS_STEPS.forEach(k=>{if(s.progress[k]===undefined)s.progress[k]=autoStepProgress(s,k)});s.completionRate=sceneCompletionRateFull(s);return s}
function ensureV07Production(){ensureV07();(state.scenes||[]).forEach(normalizeSceneProduction);(state.episodes||[]).forEach(e=>{e.youtube=defaultYoutube(e.youtube||{})});(state.projects||[]).forEach(p=>{p.youtube=defaultYoutube(p.youtube||{})})}
function pctByStatus(status){return status==='完成'||status==='採用'?100:status==='確認中'?80:status==='編集中'||status==='制作中'||status==='生成中'?60:status==='プロンプト作成'||status==='画像準備'?40:status==='保留'?50:0}
function avg(a){return a.length?Math.round(a.reduce((x,y)=>x+y,0)/a.length):0}
function autoStepProgress(s,k){if(k==='script')return s.script?100:0;if(k==='illustration')return avg((s.illustrations||[]).map(x=>pctByStatus(x.workStatus)));if(k==='vidu')return Math.max(viduProgress(s.vidu),(s.vidu?.generatedVideos||[]).some(v=>v.adoptionStatus==='採用')?100:0);if(k==='edit')return Math.max(pctByStatus(s.videoEdit?.workStatus),(s.videoEdit?.exports||[]).some(v=>v.adoptionStatus==='採用')?100:0);if(k==='audio')return avg((s.audioItems||[]).map(x=>pctByStatus(x.workStatus)));if(k==='complete')return s.completion?.finalVideo?(s.completion.approvalStatus==='承認'?100:80):0;return 0}
function sceneCompletionRateFull(s){return avg(NS_STEPS.map(k=>clampPercent(s.progress?.[k]??autoStepProgress(s,k))))}
function linkButton(url,label='開く'){return url?`<button onclick="window.open('${esc(url)}','_blank','noopener')">${label}</button>`:''}
function assetLabel(a){return [a.title,a.fileName,a.location].filter(Boolean).join(' / ')||a.id}
function productionFlow(s){return `<div class="flowbar">${[...NS_STEPS,'publish'].map(k=>`<button onclick="document.getElementById('card_${k}')?.scrollIntoView({behavior:'smooth',block:'start'})"><b>${NS_STEP_LABELS[k]}</b><small>${k==='publish'?s.youtube?.status||'未準備':clampPercent(s.progress?.[k]??autoStepProgress(s,k))+'%'}</small></button>`).join('<span>→</span>')}</div>`}
function progressEditor(s){return `<div class="progress-grid">${NS_STEPS.map(k=>`<label>${NS_STEP_LABELS[k]}<input id="p_${k}" type="number" min="0" max="100" value="${clampPercent(s.progress?.[k]??autoStepProgress(s,k))}"></label>`).join('')}</div><button onclick="saveSceneProgress('${s.id}')">進捗を保存</button>`}
function saveSceneProgress(id){const s=state.scenes.find(x=>x.id===id);NS_STEPS.forEach(k=>s.progress[k]=clampPercent($('#p_'+k).value));s.completionRate=sceneCompletionRateFull(s);touch(s);saveState();openSceneDetail(id);toast('工程進捗を保存しました')}
function itemList(title,items,editFn,filter=false){const shown=filter?items.filter(x=>x.adoptionStatus==='採用'):items;return `<p class="meta">完成:${items.filter(x=>x.workStatus==='完成').length} / 採用:${items.filter(x=>x.adoptionStatus==='採用').length}</p>${shown.map((x,i)=>`<div class="row"><span><b>${esc(assetLabel(x))}</b><br><small>${esc(x.type||'')} / ${esc(x.workStatus||'')} / ${esc(x.adoptionStatus||'')} / ${esc(x.memo||'')}</small></span><span>${linkButton(x.location)}<button onclick="${editFn}('${x.id}')">編集</button>${(title==='art'||title==='audio')?`<button onclick="moveProdItem('${title}','${x.id}',-1)">↑</button><button onclick="moveProdItem('${title}','${x.id}',1)">↓</button>`:''}</span></div>`).join('')||'<p class="meta">未登録</p>'}`}
function moveProdItem(kind,id,dir){const s=currentOpenScene();const arr=kind==='art'?s.illustrations:s.audioItems;const i=arr.findIndex(x=>x.id===id),j=i+dir;if(i<0||j<0||j>=arr.length)return;[arr[i],arr[j]]=[arr[j],arr[i]];touch(s);saveState();openSceneDetail(s.id)}
let nsOpenSceneId='';function currentOpenScene(){return state.scenes.find(x=>x.id===nsOpenSceneId)}
function productionCards(s){const adoptedArts=s.illustrations.filter(x=>x.adoptionStatus==='採用');const adoptedV=(s.vidu.generatedVideos||[]).filter(x=>x.adoptionStatus==='採用');const adoptedAudio=s.audioItems.filter(x=>x.adoptionStatus==='採用');return `${productionFlow(s)}<section id="card_script"><h3>台本</h3><p>${esc(s.script||'未入力')}</p></section><details id="card_illustration" open><summary>イラスト（完成:${s.illustrations.filter(x=>x.workStatus==='完成').length} / 採用:${adoptedArts.length}）</summary><button onclick="editArt('${s.id}')">＋追加</button><button onclick="toggleAdoptFilter()">採用版だけ表示</button><div id="artList">${itemList('art',s.illustrations,'editArt')}</div></details>${viduCardFull(s)}${editCard(s)}${audioCard(s)}${completeCard(s,adoptedArts,adoptedV,adoptedAudio)}${youtubeCard(s.youtube,'scene',s.id)}`}
function toggleAdoptFilter(){const s=currentOpenScene();$('#artList').innerHTML=itemList('art',s.illustrations,'editArt',true)}
function viduCardFull(s){const v=s.vidu;return `<details id="card_vidu" open><summary>Vidu（生成動画:${v.generatedVideos.length} / 採用:${v.generatedVideos.filter(x=>x.adoptionStatus==='採用').length}）</summary><button onclick="editVidu('${s.id}')">編集</button>${v.projectUrl?linkButton(v.projectUrl,'Viduを開く'):''}<p><b>JP:</b>${esc(v.japanesePrompt||'未入力')}<br><b>EN:</b>${esc(v.englishPrompt||'未入力')}<br><b>Negative:</b>${esc(v.negativePrompt||'未入力')}</p><p class="meta">モデル:${esc(v.model||'')} / 比率:${esc(v.aspectRatio||'')} / 秒数:${esc(v.durationSeconds||'')} / Credit:${esc(v.creditsUsed||'')}</p><h4>参照画像</h4>${mediaList(v.referenceImages.map(id=>s.illustrations.find(a=>a.id===id)?.title||id))}<h4>生成動画</h4>${itemList('vidu',v.generatedVideos,'editViduVideo')}</details>`}
function editCard(s){const e=s.videoEdit;return `<details id="card_edit" open><summary>動画編集（${esc(e.workStatus)} / 書き出し:${e.exports.length}）</summary><button onclick="editVideoEdit('${s.id}')">編集</button><p>${esc(e.software)} / ${esc(e.projectName)} / ${esc(e.resolution)} / ${esc(e.frameRate)} / ${esc(e.aspectRatio)}</p>${linkButton(e.projectFileLocation,'プロジェクトを開く')}<h4>書き出し動画</h4>${itemList('edit',e.exports,'editVideoEdit')}</details>`}
function audioCard(s){return `<details id="card_audio" open><summary>音楽・音声（${s.audioItems.length}件）</summary><button onclick="editAudio('${s.id}')">＋追加</button>${itemList('audio',s.audioItems,'editAudio')}</details>`}
function completeCard(s,arts,vids,audios){const c=s.completion;return `<details id="card_complete" open><summary>完成 ${c.finalVideo?'✅':''}</summary><button onclick="editCompletion('${s.id}')">編集</button><p>完成動画:${esc(c.finalVideo||'未指定')} ${linkButton(c.finalVideo)}</p><p>確認:${esc(c.reviewStatus)} / 承認:${esc(c.approvalStatus)} / 完成日:${esc(c.completedDate)}</p><p>修正メモ:${esc(c.revisionMemo||'')}</p><p class="meta">採用イラスト:${arts.map(a=>esc(a.title)).join(', ')||'なし'} / 採用Vidu:${vids.map(a=>esc(a.title)).join(', ')||'なし'} / 採用音声:${audios.map(a=>esc(a.title)).join(', ')||'なし'}</p></details>`}
function youtubeCard(y,scope,id){return `<details id="card_publish" open><summary>YouTube公開（${esc(y.status)}）</summary><button onclick="editYoutube('${scope}','${id}')">編集</button>${y.url?linkButton(y.url,'YouTubeを開く'):''}<p><b>${esc(y.title||'未設定')}</b><br>${esc(y.description||'')}</p><p class="meta">予定:${esc(y.scheduledAt)} / 公開:${esc(y.publishedAt)} / タグ:${esc((y.tags||[]).join(', '))}</p></details>`}
function editArt(sceneId,id=''){const s=state.scenes.find(x=>x.id===sceneId)||currentOpenScene(),a=id?s.illustrations.find(x=>x.id===id):nsItem('art');modal(`<h2>イラスト素材</h2><form data-dirty="false" oninput="this.dataset.dirty='true'">${['title:タイトル','fileName:ファイル名','location:保存場所またはURL','usage:用途','memo:メモ'].map(x=>{let [k,l]=x.split(':');return `<label>${l}<input id="a_${k}" value="${esc(a[k]||'')}"></label>`}).join('')}<label>種類<select id="a_type">${ART_TYPES.map(x=>`<option ${a.type===x?'selected':''}>${x}</option>`).join('')}</select></label><label>形式<select id="a_format">${ART_FORMATS.map(x=>`<option ${a.format===x?'selected':''}>${x}</option>`).join('')}</select></label><label>制作状態<select id="a_workStatus">${WORK_STATUSES.map(x=>`<option ${a.workStatus===x?'selected':''}>${x}</option>`).join('')}</select></label><label>採用状態<select id="a_adoptionStatus">${ADOPT_STATUSES.map(x=>`<option ${a.adoptionStatus===x?'selected':''}>${x}</option>`).join('')}</select></label><button type="button" onclick="saveArt('${s.id}','${id}')">保存</button>${id?`<button type="button" class="danger" onclick="deleteArt('${s.id}','${id}')">削除</button>`:''}</form>`)}
function saveArt(sceneId,id){const s=state.scenes.find(x=>x.id===sceneId),a=id?s.illustrations.find(x=>x.id===id):nsItem('art');['title','fileName','location','usage','memo','type','format','workStatus','adoptionStatus'].forEach(k=>a[k]=$('#a_'+k).value);a.updatedAt=now();if(!id)s.illustrations.push(a);s.progress.illustration=autoStepProgress(s,'illustration');s.completionRate=sceneCompletionRateFull(s);touch(s);saveState();closeModal();openSceneDetail(sceneId)}
function deleteArt(sceneId,id){if(!confirm('このイラスト素材を削除しますか？'))return;const s=state.scenes.find(x=>x.id===sceneId);s.illustrations=s.illustrations.filter(x=>x.id!==id);touch(s);saveState();closeModal();openSceneDetail(sceneId)}
