function normalizeViduTemplate(x={}){const t=viduTime(x.createdAt||x.updatedAt);return{id:x.id||uid('vidutpl'),projectId:x.projectId||currentProject()?.id||'',name:x.name||x.title||'',usage:x.usage||'その他',baseStyle:x.baseStyle||'',camera:x.camera||'',light:x.light||'',motion:x.motion||'',negative:x.negative||'',extra:x.extra||'',tags:Array.isArray(x.tags)?x.tags:parseTags(x.tags),createdAt:t,updatedAt:x.updatedAt||t,favorite:Boolean(x.favorite)}}
function normalizeViduCharacterSettings(x={}){const t=viduTime(x.createdAt||x.updatedAt);return{id:x.id||uid('viduchar'),characterId:x.characterId||'',projectId:x.projectId||'',appearance:x.appearance||'',hair:x.hair||'',eyes:x.eyes||'',costume:x.costume||'',body:x.body||'',importantFeatures:x.importantFeatures||'',mustKeep:x.mustKeep||'',avoidChanges:x.avoidChanges||'',baseStyle:x.baseStyle||'',createdAt:t,updatedAt:x.updatedAt||t}}
function normalizePromptHistory(x={},i=0){const t=viduTime(x.createdAt||x.updatedAt);return{id:x.id||uid('viduprompt'),version:Number(x.version||i+1),japanesePrompt:x.japanesePrompt||'',englishPrompt:x.englishPrompt||'',negativePrompt:x.negativePrompt||'',templateId:x.templateId||'',templateName:x.templateName||'',createdAt:t,updatedAt:x.updatedAt||t,adoptionStatus:VIDU_PROMPT_STATUSES.includes(x.adoptionStatus)?x.adoptionStatus:'作成中',memo:x.memo||'',input:defaultViduPromptInput(x.input||{})}}
function ensureV08(){ensureV07Production();state.viduTemplates=(Array.isArray(state.viduTemplates)?state.viduTemplates:[]).map(normalizeViduTemplate);state.viduCharacterSettings=(Array.isArray(state.viduCharacterSettings)?state.viduCharacterSettings:[]).map(normalizeViduCharacterSettings);(state.scenes||[]).forEach(s=>{s.vidu=normalizeViduProduction(s.vidu);s.vidu.promptInput=defaultViduPromptInput(s.vidu.promptInput||{});s.vidu.promptHistory=(Array.isArray(s.vidu.promptHistory)?s.vidu.promptHistory:[]).map(normalizePromptHistory);s.vidu.generatedVideos=(s.vidu.generatedVideos||[]).map(g=>({...normalizeGeneratedVideo(g),promptId:g.promptId||'',referenceImages:Array.isArray(g.referenceImages)?g.referenceImages:[],model:g.model||s.vidu.model||'',generatedAt:g.generatedAt||g.createdAt||'',adoptionStatus:g.adoptionStatus||'未選択'}))})}
function projectCharacters(){const p=currentProject();return (state.characters||[]).filter(x=>!p||!x.projectId||x.projectId===p.id)}
function projectWorlds(){const p=currentProject();return (state.worlds||[]).filter(x=>!p||!x.projectId||x.projectId===p.id)}
function projectScenes(){const p=currentProject();return (state.scenes||[]).filter(x=>!p||x.projectId===p.id)}
function optList(items,ids,labelFn){return items.map(x=>`<option value="${x.id}" ${(ids||[]).includes(x.id)?'selected':''}>${esc(labelFn?labelFn(x):(x.title||x.name||x.id))}</option>`).join('')}
function templateOptions(selected=''){return `<option value="">使わない</option>`+state.viduTemplates.filter(t=>!currentProject()||!t.projectId||t.projectId===currentProject().id).map(t=>`<option value="${t.id}" ${selected===t.id?'selected':''}>${t.favorite?'★ ':''}${esc(t.name)} / ${esc(t.usage)}</option>`).join('')}
function characterSetting(c){return state.viduCharacterSettings.find(x=>x.characterId===c.id)||normalizeViduCharacterSettings({characterId:c.id,projectId:c.projectId})}
function sceneSeedInput(s){const input=defaultViduPromptInput(s.vidu?.promptInput||{});return{...input,sceneTitle:input.sceneTitle||s.title||s.sceneNumber||'',summary:input.summary||s.summary||'',location:input.location||s.location||'',timeOfDay:input.timeOfDay||s.timeOfDay||'',script:input.script||s.script||'',sceneMemo:input.sceneMemo||s.memo||'',characterIds:input.characterIds.length?input.characterIds:idsFromText(projectCharacters(),s.charactersText),worldIds:input.worldIds.length?input.worldIds:idsFromText(projectWorlds(),s.worldsText),event:input.event||s.summary||''}}
function idsFromText(items,text=''){return items.filter(x=>String(text).includes(x.title||x.name||'__none__')).map(x=>x.id)}
function selectedTexts(ids,items){return ids.map(id=>items.find(x=>x.id===id)).filter(Boolean).map(x=>x.title||x.name||x.id)}
function buildViduPrompts(input,templateId=''){const chars=projectCharacters().filter(c=>input.characterIds.includes(c.id));const worlds=projectWorlds().filter(w=>input.worldIds.includes(w.id));const tpl=state.viduTemplates.find(t=>t.id===templateId);const fixed=chars.map(c=>{const f=characterSetting(c);return [c.title||c.name,f.appearance,f.hair&&`髪:${f.hair}`,f.eyes&&`目:${f.eyes}`,f.costume&&`衣装:${f.costume}`,f.body&&`体格:${f.body}`,f.importantFeatures&&`重要:${f.importantFeatures}`,f.mustKeep&&`固定:${f.mustKeep}`,f.baseStyle&&`画風:${f.baseStyle}`].filter(Boolean).join('、')}).filter(Boolean);
 const jpParts=[`Scene「${input.sceneTitle||''}」`,input.summary&&`概要:${input.summary}`,chars.length&&`登場キャラクター:${fixed.join(' / ')}`,worlds.length&&`関連世界観:${selectedTexts(input.worldIds,projectWorlds()).join('、')}`,input.location&&`場所:${input.location}`,input.timeOfDay&&`時間帯:${input.timeOfDay}`,input.weather&&`天候:${input.weather}`,input.background&&`背景:${input.background}`,input.expression&&`表情:${input.expression}`,input.action&&`動作:${input.action}`,input.event&&`動画内の出来事:${input.event}`,`カメラ:${[input.cameraPosition,input.cameraMove,input.composition,input.angle,tpl?.camera].filter(Boolean).join('、')}`,`光:${[input.light,tpl?.light].filter(Boolean).join('、')}`,`色調:${input.colorTone||''}`,`画風:${[input.style,tpl?.baseStyle].filter(Boolean).join('、')}`,`動き:${tpl?.motion||''}`,input.script&&`台本:${input.script}`,input.sceneMemo&&`制作メモ:${input.sceneMemo}`,input.extra&&`追加指示:${input.extra}`,tpl?.extra&&`テンプレート追加指示:${tpl.extra}`].filter(x=>x&& !String(x).endsWith(':')).join('。');
 const enParts=[`Scene: ${input.sceneTitle||''}`,input.summary&&`summary: ${input.summary}`,chars.length&&`characters with locked details: ${fixed.join(' / ')}`,worlds.length&&`world setting: ${selectedTexts(input.worldIds,projectWorlds()).join(', ')}`,input.location&&`location: ${input.location}`,input.timeOfDay&&`time of day: ${input.timeOfDay}`,input.weather&&`weather: ${input.weather}`,input.background&&`background: ${input.background}`,input.expression&&`expression: ${input.expression}`,input.action&&`action: ${input.action}`,input.event&&`event in the video: ${input.event}`,`camera: ${[input.cameraPosition,input.cameraMove,input.composition,input.angle,tpl?.camera].filter(Boolean).join(', ')}`,`lighting: ${[input.light,tpl?.light].filter(Boolean).join(', ')}`,input.colorTone&&`color tone: ${input.colorTone}`,`visual style: ${[input.style,tpl?.baseStyle].filter(Boolean).join(', ')}`,tpl?.motion&&`motion: ${tpl.motion}`,input.extra&&`additional instructions: ${input.extra}`,tpl?.extra&&`template notes: ${tpl.extra}`].filter(x=>x&& !String(x).endsWith(': ')).join('. ');
 const neg=[input.negative,tpl?.negative,...chars.map(c=>characterSetting(c).avoidChanges)].filter(Boolean).join('、');return{jp:jpParts,en:enParts,negative:neg}}
function openViduPromptComposer(sceneId,templateId=''){ensureV08();const s=state.scenes.find(x=>x.id===sceneId);if(!s)return;const input=sceneSeedInput(s);const gen=buildViduPrompts(input,templateId);modal(`<h2>Viduプロンプト作成：${esc(storyTitle('scenes',s))}</h2><form class="vidu-prompt-form" oninput="updatePromptPreview()"><input type="hidden" id="vp_scene" value="${sceneId}"><label>テンプレート<select id="vp_templateId" onchange="applyPromptTemplate()">${templateOptions(templateId)}</select></label>${group('Scene情報の自動反映',`<label>Sceneタイトル<input id="vp_sceneTitle" value="${esc(input.sceneTitle)}"></label><label>概要<textarea id="vp_summary" rows="3">${esc(input.summary)}</textarea></label><label>台本<textarea id="vp_script" rows="4">${esc(input.script)}</textarea></label><label>制作メモ<textarea id="vp_sceneMemo" rows="3">${esc(input.sceneMemo)}</textarea></label>`)}${group('登録済みデータから選択',`<label>登場キャラクター<select id="vp_characterIds" multiple onchange="applyCharacterLocks();updatePromptPreview()">${optList(projectCharacters(),input.characterIds)}</select></label><label>関連世界観<select id="vp_worldIds" multiple>${optList(projectWorlds(),input.worldIds)}</select></label><label>登録済み場所・世界観<select id="vp_placePick" onchange="if(this.value){document.getElementById('vp_location').value=this.value;updatePromptPreview()}"><option value="">手入力を使う</option>${projectWorlds().map(w=>`<option>${esc(w.title||w.name)}</option>`).join('')}</select></label><div id="vp_locks" class="important"></div>`)}<div class="prompt-grid">${VIDU_PROMPT_FIELDS.map(([k,l])=>`<label>${l}<textarea id="vp_${k}" rows="${['event','negative','extra','appearance'].includes(k)?3:2}">${esc(input[k]||'')}</textarea></label>`).join('')}</div>${group('生成プロンプト（個別に編集できます）',`<label>日本語プロンプト<textarea id="vp_japanesePrompt" rows="7">${esc(gen.jp)}</textarea></label><label>英語プロンプト<textarea id="vp_englishPrompt" rows="7">${esc(gen.en)}</textarea></label><label>ネガティブプロンプト<textarea id="vp_negativePrompt" rows="4">${esc(gen.negative)}</textarea></label><div class="vidu-actions"><button type="button" onclick="copyPrompt('jp')">日本語をコピー</button><button type="button" onclick="copyPrompt('en')">英語をコピー</button><button type="button" onclick="copyPrompt('negative')">ネガティブをコピー</button><button type="button" onclick="copyPrompt('all')">全部まとめてコピー</button></div><label>状態<select id="vp_adoptionStatus">${VIDU_PROMPT_STATUSES.map(x=>`<option>${x}</option>`).join('')}</select></label><label>制作メモ<textarea id="vp_memo" rows="3"></textarea></label>`)}<button type="button" onclick="saveViduPrompt('${sceneId}')">履歴として保存</button></form>`);applyCharacterLocks()}
function collectPromptInput(){const x={};['sceneTitle','summary','script','sceneMemo'].forEach(k=>x[k]=$('#vp_'+k).value);VIDU_PROMPT_FIELDS.forEach(([k])=>x[k]=$('#vp_'+k).value);x.characterIds=selectedIds('vp_characterIds');x.worldIds=selectedIds('vp_worldIds');return defaultViduPromptInput(x)}
function updatePromptPreview(){const oldJ=$('#vp_japanesePrompt'),oldE=$('#vp_englishPrompt'),oldN=$('#vp_negativePrompt');if(!oldJ)return;const g=buildViduPrompts(collectPromptInput(),$('#vp_templateId').value);oldJ.value=g.jp;oldE.value=g.en;oldN.value=g.negative}
function applyPromptTemplate(){const t=state.viduTemplates.find(x=>x.id===$('#vp_templateId').value);if(t){if(t.baseStyle)$('#vp_style').value=t.baseStyle;if(t.camera)$('#vp_cameraMove').value=t.camera;if(t.light)$('#vp_light').value=t.light;if(t.motion)$('#vp_action').value=[$('#vp_action').value,t.motion].filter(Boolean).join('、');if(t.negative)$('#vp_negative').value=[$('#vp_negative').value,t.negative].filter(Boolean).join('、');if(t.extra)$('#vp_extra').value=[$('#vp_extra').value,t.extra].filter(Boolean).join('\n')}updatePromptPreview()}
function applyCharacterLocks(){const ids=selectedIds('vp_characterIds'),chars=projectCharacters().filter(c=>ids.includes(c.id));const locks=chars.map(c=>characterSetting(c));$('#vp_locks').innerHTML=locks.length?locks.map((f,i)=>`<b>${esc(chars[i].title||chars[i].name)}</b>: ${esc([f.appearance,f.hair,f.eyes,f.costume,f.body,f.importantFeatures,f.mustKeep,f.baseStyle].filter(Boolean).join(' / ')||'固定設定なし')}`).join('<br>'):'キャラクター固定設定は未選択です。';const add=(id,text)=>{const el=$('#'+id);if(el&&text&&!el.value.includes(text))el.value=[el.value,text].filter(Boolean).join('、')};locks.forEach(f=>{add('vp_appearance',[f.appearance,f.hair&&`髪:${f.hair}`,f.eyes&&`目:${f.eyes}`,f.body&&`体格:${f.body}`,f.importantFeatures].filter(Boolean).join('、'));add('vp_costume',f.costume);add('vp_style',f.baseStyle);add('vp_negative',f.avoidChanges)});}
async function copyPrompt(kind){const map={jp:'#vp_japanesePrompt',en:'#vp_englishPrompt',negative:'#vp_negativePrompt'};let text=kind==='all'?`【日本語】\n${$(map.jp).value}\n\n【English】\n${$(map.en).value}\n\n【Negative】\n${$(map.negative).value}`:$(map[kind]).value;await navigator.clipboard?.writeText(text);toast('コピーしました')}
function missingImportantWarnings(input,jp,en){return projectCharacters().filter(c=>input.characterIds.includes(c.id)).flatMap(c=>{const f=characterSetting(c),hay=jp+' '+en;return [f.importantFeatures,f.mustKeep].filter(Boolean).filter(t=>!hay.includes(t)).map(t=>`${c.title||c.name}: ${t}`)})}
function saveViduPrompt(sceneId){const s=state.scenes.find(x=>x.id===sceneId);const input=collectPromptInput(),jp=$('#vp_japanesePrompt').value,en=$('#vp_englishPrompt').value,neg=$('#vp_negativePrompt').value;const warn=missingImportantWarnings(input,jp,en);if(warn.length&&!confirm('重要設定がプロンプトに含まれていない可能性があります。\n'+warn.join('\n')+'\n\nこのまま保存しますか？'))return;const h=normalizePromptHistory({version:(s.vidu.promptHistory||[]).length+1,japanesePrompt:jp,englishPrompt:en,negativePrompt:neg,templateId:$('#vp_templateId').value,templateName:state.viduTemplates.find(t=>t.id===$('#vp_templateId').value)?.name||'',adoptionStatus:$('#vp_adoptionStatus').value,memo:$('#vp_memo').value,input});s.vidu.promptInput=input;s.vidu.japanesePrompt=jp;s.vidu.englishPrompt=en;s.vidu.negativePrompt=neg;s.vidu.promptHistory=[...(s.vidu.promptHistory||[]),h];touch(s);saveState();closeModal();openSceneDetail(sceneId);toast('プロンプト履歴を保存しました')}
function viduPromptHistoryHtml(s){const hs=s.vidu.promptHistory||[];return `<section><h3>保存済みプロンプト履歴</h3>${hs.map(h=>`<div class="row"><span><b>v${h.version} ${esc(h.adoptionStatus)}</b> ${esc(h.templateName||'テンプレートなし')}<br><small>${esc(h.updatedAt)} / ${esc(h.memo)}</small></span><span><button onclick="loadViduPromptHistory('${s.id}','${h.id}')">再利用</button><button onclick="setPromptStatus('${s.id}','${h.id}')">状態変更</button></span></div>`).join('')||'<p class="meta">保存済みプロンプトはありません。</p>'}</section>`}
function loadViduPromptHistory(sceneId,hid){const s=state.scenes.find(x=>x.id===sceneId),h=s.vidu.promptHistory.find(x=>x.id===hid);s.vidu.promptInput=h.input;s.vidu.japanesePrompt=h.japanesePrompt;s.vidu.englishPrompt=h.englishPrompt;s.vidu.negativePrompt=h.negativePrompt;openViduPromptComposer(sceneId,h.templateId)}
function setPromptStatus(sceneId,hid){const h=state.scenes.find(x=>x.id===sceneId).vidu.promptHistory.find(x=>x.id===hid),v=prompt('状態を入力: '+VIDU_PROMPT_STATUSES.join(' / '),h.adoptionStatus);if(v&&VIDU_PROMPT_STATUSES.includes(v)){h.adoptionStatus=v;h.updatedAt=now();saveState();openSceneDetail(sceneId)}}
function viduTemplatesView(){ensureV08();const list=state.viduTemplates.filter(t=>!currentProject()||t.projectId===currentProject().id);return `<h1>Viduテンプレート管理</h1><button class="primary-action" onclick="editViduTemplate()">＋テンプレート作成</button>${list.map(t=>`<div class="row"><span>${t.favorite?'★ ':''}<b>${esc(t.name)}</b> / ${esc(t.usage)}<br><small>${esc(t.baseStyle)} / ${esc(t.camera)} / ${esc(t.updatedAt)}</small></span><span><button onclick="editViduTemplate('${t.id}')">編集</button><button class="danger" onclick="deleteViduTemplate('${t.id}')">削除</button></span></div>`).join('')||'<p class="meta">テンプレートは未登録です。</p>'}`}
function editViduTemplate(id=''){const p=currentProject(),t=id?state.viduTemplates.find(x=>x.id===id):normalizeViduTemplate({projectId:p?.id});modal(`<h2>Viduテンプレート</h2><form>${['name:テンプレート名','baseStyle:基本画風','camera:カメラ','light:光','motion:動き','negative:ネガティブ','extra:追加指示','tags:タグ'].map(x=>{let[k,l]=x.split(':');return `<label>${l}<textarea id="tpl_${k}" rows="${['negative','extra'].includes(k)?3:1}">${esc(k==='tags'?(t.tags||[]).join(','):t[k]||'')}</textarea></label>`}).join('')}<label>用途<select id="tpl_usage">${VIDU_TEMPLATE_USES.map(x=>`<option ${t.usage===x?'selected':''}>${x}</option>`).join('')}</select></label><label><input type="checkbox" id="tpl_favorite" ${t.favorite?'checked':''}>お気に入り</label><p class="meta">作成:${esc(t.createdAt)} / 更新:${esc(t.updatedAt)}</p><button type="button" onclick="saveViduTemplate('${id}')">保存</button></form>`)}
function saveViduTemplate(id=''){const t=id?state.viduTemplates.find(x=>x.id===id):normalizeViduTemplate({projectId:currentProject()?.id});['name','baseStyle','camera','light','motion','negative','extra'].forEach(k=>t[k]=$('#tpl_'+k).value);t.usage=$('#tpl_usage').value;t.tags=parseTags($('#tpl_tags').value);t.favorite=$('#tpl_favorite').checked;t.updatedAt=now();if(!id)state.viduTemplates.push(t);saveState();closeModal();render()}
function deleteViduTemplate(id){if(confirm('テンプレートを削除しますか？')){state.viduTemplates=state.viduTemplates.filter(x=>x.id!==id);saveState();render()}}
function editViduCharSettings(characterId=''){const chars=projectCharacters();const c=chars.find(x=>x.id===characterId)||chars[0];if(!c){toast('キャラクターがありません');return}let f=characterSetting(c);modal(`<h2>キャラクター固定設定</h2><label>キャラクター<select id="vc_characterId" onchange="editViduCharSettings(this.value)">${optList(chars,[c.id])}</select></label><form>${['appearance:外見','hair:髪','eyes:目','costume:衣装','body:体格','importantFeatures:重要な特徴','mustKeep:絶対に変えない条件','avoidChanges:避けたい変化','baseStyle:基本画風'].map(x=>{let[k,l]=x.split(':');return `<label>${l}<textarea id="vc_${k}" rows="2">${esc(f[k]||'')}</textarea></label>`}).join('')}<button type="button" onclick="saveViduCharSettings('${c.id}')">保存</button></form>`)}
function saveViduCharSettings(characterId){let f=state.viduCharacterSettings.find(x=>x.characterId===characterId);if(!f){const c=state.characters.find(x=>x.id===characterId);f=normalizeViduCharacterSettings({characterId,projectId:c?.projectId});state.viduCharacterSettings.push(f)}['appearance','hair','eyes','costume','body','importantFeatures','mustKeep','avoidChanges','baseStyle'].forEach(k=>f[k]=$('#vc_'+k).value);f.updatedAt=now();saveState();closeModal();toast('固定設定を保存しました')}
function editViduVideoWithPrompt(id){const s=currentOpenScene();const g=s.vidu.generatedVideos.find(x=>x.id===id)||normalizeGeneratedVideo();modal(`<h2>生成動画とプロンプトの関連付け</h2><form>${genVideoFields(g)}<label>使用したプロンプト<select id="gv_promptId"><option value="">未指定</option>${(s.vidu.promptHistory||[]).map(h=>`<option value="${h.id}" ${g.promptId===h.id?'selected':''}>v${h.version} ${esc(h.adoptionStatus)} ${esc(h.templateName)}</option>`).join('')}</select></label><label>使用した参照画像<select id="gv_ref" multiple>${optList(s.illustrations,g.referenceImages||[],assetLabel)}</select></label><label>使用モデル<input id="gv_model" value="${esc(g.model||s.vidu.model||'')}"></label><label>生成日時<input id="gv_generatedAt" value="${esc(g.generatedAt||'')}"></label><button type="button" onclick="saveLinkedViduVideo('${g.id}')">保存</button></form>`)}
function saveLinkedViduVideo(id){const s=currentOpenScene();let g=s.vidu.generatedVideos.find(x=>x.id===id);if(!g){g=normalizeGeneratedVideo({id});s.vidu.generatedVideos.push(g)}const el=document.querySelector('.gen-video');g.title=el.querySelector('.gv_title').value;g.fileName=el.querySelector('.gv_fileName').value;g.location=el.querySelector('.gv_location').value;g.adoptionStatus=el.querySelector('.gv_adoptionStatus').value;g.memo=el.querySelector('.gv_memo').value;g.promptId=$('#gv_promptId').value;g.referenceImages=selectedIds('gv_ref');g.model=$('#gv_model').value;g.generatedAt=$('#gv_generatedAt').value;g.updatedAt=now();touch(s);saveState();closeModal();openSceneDetail(s.id)}
const v08OldViduCardFull=viduCardFull;viduCardFull=function(s){ensureV08();const base=v08OldViduCardFull(s).replace('<button onclick="editVidu(\''+s.id+'\')">編集</button>',`<div class="vidu-actions"><button onclick="openViduPromptComposer('${s.id}')">プロンプトを作成</button><button onclick="document.getElementById('vidu_history_${s.id}')?.scrollIntoView({behavior:'smooth'})">保存済みプロンプト</button><button onclick="setView('viduTemplates')">テンプレートから作成</button><button onclick="editVidu('${s.id}')">Vidu管理を編集</button><button onclick="editViduCharSettings()">キャラクター固定設定</button></div>`).replace('</details>',`${viduPromptHistoryHtml(s)}<section><h3>生成動画との関連付け</h3>${(s.vidu.generatedVideos||[]).map(g=>{const h=(s.vidu.promptHistory||[]).find(x=>x.id===g.promptId);return `<div class="row"><span><b>${esc(assetLabel(g))}</b><br><small>使用プロンプト:${h?'v'+h.version:'未指定'} / 参照画像:${(g.referenceImages||[]).length}件 / モデル:${esc(g.model||'')} / 生成:${esc(g.generatedAt||'')} / 採用:${esc(g.adoptionStatus||'')}</small></span><button onclick="editViduVideoWithPrompt('${g.id}')">関連付け</button></div>`}).join('')||'<p class="meta">生成動画は未登録です。</p>'}</section></details>`);return base.replace('<section><h3>保存済みプロンプト履歴</h3>',`<section id="vidu_history_${s.id}"><h3>保存済みプロンプト履歴</h3>`)}
