function novaSceneCheck(s){const v=normalizeViduProduction(s.vidu||{}),a=novaSceneAssets(s),rate=sceneCompletionRateFull(s);return [{label:'台本未入力',ok:!!String(s.script||'').trim(),fix:'Sceneの台本欄を入力する'},{label:'画像不足',ok:a.images>0,fix:'イラストまたはVidu参照画像を追加する'},{label:'Vidu未作成',ok:v.status!=='未着手'||v.generatedVideos.length>0||!!v.japanesePrompt,fix:'Viduプロンプトまたは生成動画を作成する'},{label:'BGM未設定',ok:(s.audioItems||[]).some(x=>/bgm|ＢＧＭ|音楽/i.test([x.kind,x.title,x.memo].join(' '))),fix:'音声/BGM素材を追加する'},{label:'完成率',ok:rate>=80,fix:`現在 ${rate}%。未完了工程を進める`},{label:'公開待ち',ok:!!(s.completion?.youtubeReady||s.youtube?.status==='公開待ち'||s.youtube?.status==='公開済み'),fix:'YouTube/公開情報を確認する'}]}
function novaSceneSummary(s){const checks=novaSceneCheck(s),done=checks.filter(x=>x.ok),missing=checks.filter(x=>!x.ok),v=normalizeViduProduction(s.vidu||{});return `<section class="nova-panel"><h3>ノヴァ制作チェック</h3><div class="stats"><div><b>完成率</b><span>${sceneCompletionRateFull(s)}%</span></div><div><b>不足</b><span>${missing.length}件</span></div><div><b>公開待ち</b><span>${checks.find(x=>x.label==='公開待ち')?.ok?'はい':'未確認'}</span></div></div>${checks.map(c=>`<div class="row"><span>${c.ok?'✅':'⚠️'} ${esc(c.label)}<br><small>修正候補：${esc(c.fix)}</small></span></div>`).join('')}</section><section><h3>ノヴァSceneサマリー</h3><p><b>終わっていること：</b>${done.map(x=>x.label).join('、')||'なし'}<br><b>不足：</b>${missing.map(x=>x.label).join('、')||'なし'}<br><b>関連キャラクター：</b>${esc(s.charactersText||selectedTexts(s.relatedCharacters||[],state.characters).join('、')||'未設定')}<br><b>関連世界観：</b>${esc(s.worldsText||selectedTexts(s.relatedWorlds||[],state.worlds).join('、')||'未設定')}<br><b>使用Vidu：</b>${esc(v.status)} / 生成動画${v.generatedVideos.length}件</p></section>`}
