function novaConflicts(){const p=currentProject(),scope=c=>(state[c]||[]).filter(x=>!x.isArchived&&(!p||x.projectId===p.id));const out=[];for(const c of ['characters','terms']){const groups={};scope(c).forEach(x=>{const k=(x.title||x.name||'').trim();if(k)(groups[k]=groups[k]||[]).push(x)});Object.entries(groups).filter(([,v])=>v.length>1).forEach(([k,v])=>{const text=new Set(v.map(x=>x.importantSettings||x.description||x.profile||x.memo||''));if(text.size>1)out.push({type:c==='characters'?'同じ人物の設定違い':'同じ用語の説明違い',title:k,fix:'最新更新の内容を基準に統合候補を作る',items:v,collection:c})})}const ts=scope('timelines').sort((a,b)=>(+a.sortOrder||0)-(+b.sortOrder||0));ts.forEach((x,i)=>{const prev=ts[i-1];if(prev&&String(prev.eraLabel||'')>String(x.eraLabel||''))out.push({type:'年表の前後矛盾',title:storyTitle('timelines',x),fix:'eraLabelまたは並び順を見直す',items:[prev,x],collection:'timelines'})});const byEp={};scope('scenes').forEach(s=>(byEp[s.episodeId]=byEp[s.episodeId]||[]).push(s));Object.values(byEp).forEach(list=>list.sort((a,b)=>(+a.sortOrder||0)-(+b.sortOrder||0)).forEach((s,i)=>{const n=Number(String(s.sceneNumber||'').replace(/\D/g,''));const pn=Number(String(list[i-1]?.sceneNumber||'').replace(/\D/g,''));if(i&&n&&pn&&n<pn)out.push({type:'Sceneの順番矛盾',title:storyTitle('scenes',s),fix:'Scene番号または並び順を修正する',items:[list[i-1],s],collection:'scenes'})}));novaAllSearchItems().filter(r=>!['projects','apps','viduTemplates'].includes(r.collection)&&!r.item.episodeId&&!(r.item.relatedIds||[]).length).slice(0,8).forEach(r=>out.push({type:'未関連データ',title:r.title,fix:'作品・話数・関連項目を設定する',items:[r.item],collection:r.collection}));return out.slice(0,30)}
