// Nova Studio Version 1.1: unified CRUD controls for core story collections
const NOVA11_COLLECTIONS=['projects','episodes','scenes','characters','worlds','terms','timelines','ideas'];
function nova11Label(c){return c==='projects'?'作品':c==='episodes'?'話数':(STORY_LABELS[c]||typeLabel(COLLECTION_TYPE_MAP[c]))}
function nova11Title(c,item){return c==='projects'?item.title:c==='episodes'?`${item.numberLabel||item.title||''} ${item.subtitle||''}`.trim():storyTitle(c,item)}
function nova11Items(c){const p=currentProject();let items=(state[c]||[]).filter(x=>!x.isArchived);if(c!=='projects')items=items.filter(x=>x.projectId===p?.id);return items}
function nova11FilterState(c){state.filters=state.filters||{};state.filters[c]=state.filters[c]||{};return state.filters[c]}
function nova11Toolbar(c){const f=nova11FilterState(c),items=nova11Items(c),tags=[...new Set(items.flatMap(x=>x.tags||[]))],label=nova11Label(c);return `<section class="list-tools"><div class="tool-actions"><button class="primary-action" onclick="${c==='projects'?'editProject()':c==='episodes'?'editEpisode()':`editStoryItem('${c}')`}">＋ ${esc(label)}を追加</button></div><div class="filters"><label>検索<input id="f_query" value="${esc(f.query||'')}" placeholder="${esc(label)}を検索" inputmode="search" oninput="setFilter('${c}')"></label><label>状態<select id="f_status" onchange="setFilter('${c}')"><option value="">すべて</option>${ITEM_STATUSES.map(s=>`<option value="${s}" ${f.status===s?'selected':''}>${s}</option>`).join('')}</select></label><label>タグ<select id="f_tag" onchange="setFilter('${c}')"><option value="">すべて</option>${tags.map(t=>`<option value="${esc(t)}" ${f.tag===t?'selected':''}>${esc(t)}</option>`).join('')}</select></label><label>お気に入り<select id="f_fav" onchange="setFilter('${c}')"><option value="">すべて</option><option value="yes" ${f.fav==='yes'?'selected':''}>お気に入り</option></select></label><label>並び替え<select id="f_sort" onchange="setFilter('${c}')"><option value="sortOrder" ${f.sort==='sortOrder'?'selected':''}>手動順</option><option value="updated" ${!f.sort||f.sort==='updated'?'selected':''}>更新順</option><option value="created" ${f.sort==='created'?'selected':''}>作成順</option><option value="name" ${f.sort==='name'?'selected':''}>名前順</option>${c==='terms'?`<option value="kana" ${f.sort==='kana'?'selected':''}>五十音順</option>`:''}</select></label></div></section>`}
setFilter=function(c){state.filters=state.filters||{};state.filters[c]={query:$('#f_query')?.value||'',status:$('#f_status')?.value||'',tag:$('#f_tag')?.value||'',fav:$('#f_fav')?.value||'',sort:$('#f_sort')?.value||''};render()}
applyFilters=function(c,items){const f=nova11FilterState(c),q=String(f.query||'').toLowerCase().trim(),type=COLLECTION_TYPE_MAP[c];let out=items.filter(x=>(!f.status||x.status===f.status)&&(!f.tag||(x.tags||[]).includes(f.tag))&&(!f.fav||isFav(type,x.id)));if(q)out=out.filter(x=>[nova11Title(c,x),x.summary,x.description,x.content,x.profile,x.memo,x.script,x.reading,x.category,x.role,(x.tags||[]).join(' ')].join(' ').toLowerCase().includes(q));const sort=f.sort||'updated';return out.sort((a,b)=>sort==='sortOrder'?((+a.sortOrder||0)-(+b.sortOrder||0)):sort==='created'?(b.createdAt||'').localeCompare(a.createdAt||''):sort==='name'?nova11Title(c,a).localeCompare(nova11Title(c,b),'ja'):sort==='kana'?((a.reading||nova11Title(c,a)).localeCompare(b.reading||nova11Title(c,b),'ja')):(b.updatedAt||'').localeCompare(a.updatedAt||''))}
function nova11Duplicate(c,id){if(c==='projects')return duplicateProject(id);if(c==='episodes')return duplicateEpisode(id);const src=state[c].find(x=>x.id===id);if(!src)return;const copy=typeof structuredClone==='function'?structuredClone(src):JSON.parse(JSON.stringify(src));copy.id=uid(COLLECTION_TYPE_MAP[c]);copy.title=(nova11Title(c,src)||'無題')+' コピー';if(c==='scenes')copy.sceneNumber=(src.sceneNumber||'Scene')+' コピー';copy.createdAt=now();copy.updatedAt=now();copy.sortOrder=(state[c]||[]).length+1;copy.isArchived=false;state[c].push(copy);saveState();render();toast('複製しました')}
function nova11Delete(c,id){const item=(state[c]||[]).find(x=>x.id===id);if(!item)return;if(!confirm(`${nova11Label(c)}「${nova11Title(c,item)}」を削除しますか？`))return;state[c]=state[c].filter(x=>x.id!==id);state.favorites=(state.favorites||[]).filter(f=>!(f.type===COLLECTION_TYPE_MAP[c]&&f.targetId===id));saveState();render();toast('削除しました')}
function nova11Move(c,id,d){const item=state[c].find(x=>x.id===id);if(!item)return;item.sortOrder=(+item.sortOrder||0)+d*1.5;nova11Items(c).sort((a,b)=>(+a.sortOrder||0)-(+b.sortOrder||0)).forEach((x,i)=>x.sortOrder=i+1);touch(item);saveState();render()}
function nova11RowActions(c,item){const type=COLLECTION_TYPE_MAP[c],pid=item.projectId||item.id||'',eid=c==='episodes'?item.id:(item.episodeId||'');return `<div class="card-actions"><button onclick="${c==='projects'?`openProjectDetail('${item.id}')`:c==='episodes'?`openEpisodeDetail('${item.id}')`:`openStoryDetail('${c}','${item.id}')`}">詳細</button>${c==='projects'?`<button onclick="selectContext('${item.id}','')">選択</button>`:c==='episodes'?`<button onclick="selectContext('${item.projectId}','${item.id}')">選択</button>`:''}<button onclick="${c==='projects'?`editProject('${item.id}')`:c==='episodes'?`editEpisode('${item.id}')`:`editStoryItem('${c}','${item.id}')`}">編集</button><button onclick="nova11Duplicate('${c}','${item.id}')">複製</button><button onclick="nova11Move('${c}','${item.id}',-1)">↑</button><button onclick="nova11Move('${c}','${item.id}',1)">↓</button><button class="danger" onclick="nova11Delete('${c}','${item.id}')">削除</button><button class="favorite ${isFav(type,item.id)?'active':''}" onclick="toggleFavorite('${type}','${item.id}','${pid}','${eid}')">${isFav(type,item.id)?'★':'☆'} お気に入り</button></div>`}
projectsView=function(){const items=applyFilters('projects',nova11Items('projects'));return `<h1>作品管理</h1>${nova11Toolbar('projects')}<div>${items.map(p=>`<article class="card"><h3>${esc(p.title)}</h3><p>ID:${esc(p.id)}<br>${esc(p.summary||'')}<br>制作状態:${esc(p.productionStatus||'')} / ${metaLine(p)}<br>${itemTagsHtml(p)}</p>${nova11RowActions('projects',p)}</article>`).join('')||'<section class="empty-state"><p>作品はまだ登録されていません</p><button class="primary-action" onclick="editProject()">最初の作品を追加</button></section>'}</div>`}
episodesView=function(){const p=currentProject();if(!p)return requireProject('episodes');const items=applyFilters('episodes',nova11Items('episodes'));return `<h1>話数：${esc(p.title)}</h1>${nova11Toolbar('episodes')}<div>${items.map(e=>`<article class="card"><h3>${esc(nova11Title('episodes',e))}</h3><p>${esc(e.summary||'')}<br>制作状態:${esc(e.productionStatus||'')} / 完成率:${esc(e.completionRate||'未設定')} / ${metaLine(e)}<br>${itemTagsHtml(e)}</p>${nova11RowActions('episodes',e)}</article>`).join('')||emptyState('episodes')}</div>`}
storyCollectionView=function(collection){const p=currentProject();if(!p)return requireProject(collection);const items=applyFilters(collection,nova11Items(collection));return `<h1>${esc(nova11Label(collection))}：${esc(p.title)}</h1>${nova11Toolbar(collection)}<div class="${collection==='timelines'?'timeline-list':''}">${items.map(it=>`<article class="card ${collection==='timelines'?'timeline-item':''}"><h3>${esc(nova11Title(collection,it))}</h3>${collection==='characters'&&it.importantSettings?`<div class="important"><b>重要設定</b><br>${esc(it.importantSettings)}</div>`:''}<p>${esc(it.summary||it.description||it.content||it.profile||it.memo||'')}</p><p>${itemTagsHtml(it)}<br>${metaLine(it)}</p>${nova11RowActions(collection,it)}</article>`).join('')||emptyState(collection)}</div>`}

