// Nova Studio Version 1.2.3: keep edit modals open after save and preserve draft state.
let novaEditSaveMessageTimer=null;
function novaEditStatusHtml(){return `<div class="nova-edit-save-status quiet" role="status" aria-live="polite" aria-atomic="true">未保存の変更はありません</div>`}
function novaSetEditStatus(text,quiet=false){
 const el=document.querySelector('#modalBody .nova-edit-save-status');
 if(el){el.textContent=text;el.classList.toggle('quiet',!!quiet)}
 setSaveStatus(text);
 if(novaEditSaveMessageTimer)clearTimeout(novaEditSaveMessageTimer);
 if(text==='保存しました')novaEditSaveMessageTimer=setTimeout(()=>novaSetEditStatus('未保存の変更はありません',true),3200);
}
function novaCurrentModalForm(){return document.querySelector('#modalBody form[data-dirty]')}
function novaPreventSubmit(form){if(form)form.onsubmit=e=>{e.preventDefault();return false}}
function novaRefreshSaveButtonsId(id){
 document.querySelectorAll('#modalBody button[onclick*="saveProject"],#modalBody button[onclick*="saveEpisode"],#modalBody button[onclick*="saveStoryItem"]').forEach(btn=>{
  const old=btn.getAttribute('onclick')||'';
  btn.setAttribute('onclick',old.replace(/,''\)|,''\)/g,`,\'${id}\')`).replace(/saveProject\(''\)/,`saveProject('${id}')`).replace(/saveEpisode\(''\)/,`saveEpisode('${id}')`).replace(/saveStoryItem\('([^']+)'\s*,\s*''\)/,`saveStoryItem('$1','${id}')`));
 });
}
function novaPersistEdit(){
 novaSetEditStatus('保存中…');
 const ok=saveState(true);
 if(ok){novaSetEditStatus('保存しました');return true}
 novaSetEditStatus('保存に失敗しました');toast('保存に失敗しました');return false
}
function novaAfterEditSaved(id){
 const form=novaMarkSavedForm();
 if(form){form.dataset.savedId=id||form.dataset.savedId||'';novaPreventSubmit(form)}
 if(id)novaRefreshSaveButtonsId(id);
 ['p_id','e_id'].forEach(fieldId=>{const el=document.getElementById(fieldId);if(el)el.readOnly=true});
 toast('保存しました');
}
function novaEnhanceEditModalV123(collection){
 novaEnhanceEditModal(collection);
 const form=novaCurrentModalForm();
 if(!form)return;
 novaPreventSubmit(form);
 if(!form.querySelector('.nova-edit-save-status')){
  const firstAction=[...form.querySelectorAll('button')].find(b=>/保存|一覧へ戻る/.test(b.textContent||''));
  if(firstAction)firstAction.insertAdjacentHTML('beforebegin',novaEditStatusHtml());
  else form.insertAdjacentHTML('beforeend',novaEditStatusHtml());
 }
 novaSetEditStatus('未保存の変更はありません',true);
 form.addEventListener('input',()=>novaSetEditStatus('未保存の変更があります'),{passive:true});
 form.addEventListener('change',()=>novaSetEditStatus('未保存の変更があります'),{passive:true});
}
editProject=function(id=''){nova122OldEditProject(id);novaEnhanceEditModalV123('projects')};
editEpisode=function(id=''){nova122OldEditEpisode(id);novaEnhanceEditModalV123('episodes')};
editStoryItem=function(collection,id=''){nova122OldEditStoryItem(collection,id);novaEnhanceEditModalV123(collection)};
saveProject=function(id=''){
 const form=novaCurrentModalForm();
 id=id||form?.dataset.savedId||'';
 return novaRunSingleSave(()=>{
  let p=id?state.projects.find(x=>x.id===id):null;
  if(!p){p={};id=$('#p_id')?.value||uid('project')}
  ['id','title','reading','shortName','englishTitle','genre','summary','themeColor'].forEach(k=>p[k]=$('#p_'+k)?.value||'');
  p.productionStatus=$('#p_productionStatus')?.value||p.productionStatus||'';p.status=$('#p_status')?.value||p.status||'';p.tags=parseTags($('#p_tags')?.value||'');touch(p);
  if(!state.projects.some(x=>x.id===p.id)){p.sortOrder=state.projects.length+1;p.isArchived=false;state.projects.push(p);state.episodes.push(episode(uid('episode'),p.id,'作品全体',1),episode(uid('episode'),p.id,'未分類',2))}
  addRecentItem('project',p);
  if(novaPersistEdit())novaAfterEditSaved(p.id);
 });
};
saveEpisode=function(id=''){
 const form=novaCurrentModalForm();
 id=id||form?.dataset.savedId||'';
 return novaRunSingleSave(()=>{
  let e=id?state.episodes.find(x=>x.id===id):null;
  if(!e)e={id:$('#e_id')?.value||uid('episode'),projectId:currentProject().id,createdAt:now(),sortOrder:state.episodes.length+1,isArchived:false,type:'episode'};
  ['id','numberLabel','subtitle','chapter','summary','memo','completionRate'].forEach(k=>e[k]=$('#e_'+k)?.value||'');
  e.relatedCharacters=selectedIds('s_relatedCharacters');e.relatedTerms=selectedIds('s_relatedTerms');e.relatedWorlds=selectedIds('s_relatedWorlds');e.relatedIds=[...new Set([...e.relatedCharacters,...e.relatedTerms,...e.relatedWorlds])];
  e.productionStatus=$('#e_productionStatus')?.value||'';e.status=$('#e_status')?.value||'';e.tags=parseTags($('#e_tags')?.value||'');touch(e);
  if(!state.episodes.some(x=>x.id===e.id))state.episodes.push(e);
  addRecentItem('episode',e);
  if(novaPersistEdit())novaAfterEditSaved(e.id);
 });
};
saveStoryItem=function(collection,id=''){
 const form=novaCurrentModalForm();
 id=id||form?.dataset.savedId||'';
 return novaRunSingleSave(()=>{
  const type=COLLECTION_TYPE_MAP[collection];let item=id?state[collection].find(x=>x.id===id):null;
  if(!item)item=normalizeCommonItem({id:uid(type),projectId:currentProject()?.id||'',episodeId:collection==='scenes'?currentEpisode()?.id:'',sortOrder:(state[collection]||[]).length+1},type);
  const before=JSON.stringify(item);
  STORY_FIELDS[collection].forEach(f=>{const el=$('#s_'+f);if(el)item[f]=f==='tags'?parseTags(el.value):el.value});
  ['relatedCharacters','relatedEpisodes','relatedTerms','relatedWorlds'].forEach(f=>item[f]=selectedIds('s_'+f));item.relatedIds=[...new Set([...(item.relatedCharacters||[]),...(item.relatedEpisodes||[]),...(item.relatedTerms||[]),...(item.relatedWorlds||[])])];
  item.title=item.title||item.name||item.sceneNumber||item.eraLabel||'無題';touch(item);
  if(!state[collection].some(x=>x.id===item.id))state[collection].push(item);
  recordHistory(item,before);
  if(novaPersistEdit())novaAfterEditSaved(item.id);
 });
};

// Keep save buttons usable after an in-place save because the modal is no longer re-rendered.
novaRunSingleSave=function(fn){
 if(novaSaveInProgress)return false;
 novaSaveInProgress=true;
 const buttons=[...document.querySelectorAll('#modalBody button')];
 const saveButtons=buttons.filter(b=>/保存/.test(b.textContent||''));
 saveButtons.forEach(b=>b.disabled=true);
 novaMarkSavedForm();
 try{return fn()}finally{novaSaveInProgress=false;saveButtons.forEach(b=>b.disabled=false)}
};

// Version 0.2.2 Import Center: selectable files, preview, paste area, and local history.
const IMPORT_CENTER_ACCEPT='.pdf,.txt,.md,.markdown,.json,.docx,application/pdf,text/plain,text/markdown,application/json,application/vnd.openxmlformats-officedocument.wordprocessingml.document';
let importCenterSelection={file:null,preview:null,pasteText:''};
function ensureImportCenterState(){state.importCenter=state.importCenter||{};state.importCenter.history=Array.isArray(state.importCenter.history)?state.importCenter.history:[];return state.importCenter}
function importFileKind(file){const name=(file?.name||'').toLowerCase(),type=(file?.type||'').toLowerCase();if(name.endsWith('.pdf')||type==='application/pdf')return 'PDF';if(name.endsWith('.docx')||type.includes('wordprocessingml'))return 'Word';if(name.endsWith('.md')||name.endsWith('.markdown'))return 'Markdown';if(name.endsWith('.json')||type.includes('json'))return 'JSON';if(name.endsWith('.txt')||type.startsWith('text/'))return 'TXT';return '未対応'}
function importFormatSize(bytes){if(!Number.isFinite(bytes))return '不明';const units=['B','KB','MB','GB'];let n=bytes,i=0;while(n>=1024&&i<units.length-1){n/=1024;i++}return `${n.toFixed(n>=10||i===0?0:1)} ${units[i]}`}
function importFormatDate(value){return value?new Date(value).toLocaleString('ja-JP'):'不明'}
function importHistoryRows(){const h=ensureImportCenterState().history.slice(0,20);return h.length?h.map(x=>`<div class="row"><span><b>${esc(x.fileName)}</b><br><small>${esc(x.importedAt)} / ${esc(x.kind)}</small></span></div>`).join(''):'<p class="empty-note">読み込み履歴はまだありません。</p>'}
function importCenterHomeCard(){return `<article class="home-action-card import-center-card" role="button" tabindex="0" onclick="setView('importCenter')" onkeydown="if(event.key==='Enter'||event.key===' ')setView('importCenter')"><h3>📥 資料取り込み</h3><p>PDF、Word、TXT、Markdown、JSON、長文貼り付けから資料を選択・確認します。</p><button class="primary-action" onclick="event.stopPropagation();setView('importCenter')">Import Centerを開く</button></article>`}
function homePrimaryCards(){return `<div class="big-actions home-action-grid" aria-label="ホーム主要カード"><article class="home-action-card" role="button" tabindex="0" onclick="openFeaturedEpisode()" onkeydown="if(event.key==='Enter'||event.key===' ')openFeaturedEpisode()"><h3>続きから</h3><p>前回開いた画面や制作中の項目へ戻ります。</p><button class="primary-action" onclick="event.stopPropagation();openFeaturedEpisode()">続きから開く</button></article><article class="home-action-card" role="button" tabindex="0" onclick="openProductionDashboard()" onkeydown="if(event.key==='Enter'||event.key===' ')openProductionDashboard()"><h3>作品ダッシュボード</h3><p>選択中の作品の進捗と構成を確認します。</p><button class="primary-action" onclick="event.stopPropagation();openProductionDashboard()">作品ダッシュボードを開く</button></article>${importCenterHomeCard()}<article class="home-action-card" role="button" tabindex="0" onclick="setView('universe')" onkeydown="if(event.key==='Enter'||event.key===' ')setView('universe')"><h3>🌌 Universe</h3><p>作品・話数・設定カードのつながりを確認します。</p><button class="primary-action" onclick="event.stopPropagation();setView('universe')">Universeを開く</button></article></div>`}
function importMethodCards(){const methods=[['PDF','PDF資料を選択し、基本情報を確認します。'],['Word','Word（.docx）資料を選択し、基本情報を確認します。'],['TXT','TXT本文を読み込み、プレビュー表示します。'],['Markdown','Markdown本文を読み込み、プレビュー表示します。'],['JSON','JSONを読み込み、整形プレビューします。'],['長文貼り付け','長文をテキストエリアへ貼り付けて履歴に保存します。']];return `<section><div class="section-head"><div><p class="eyebrow">Methods</p><h2>取り込み方法</h2></div><button onclick="setView('home')">ホームへ戻る</button></div><div class="import-method-grid">${methods.map(([name,desc])=>`<article class="import-method-card"><h3>${esc(name)}</h3><p>${esc(desc)}</p></article>`).join('')}</div></section>`}
function importCenterView(){ensureImportCenterState();const f=importCenterSelection.file,p=importCenterSelection.preview;return `<section class="hero import-hero"><h1>📥 Import Center</h1><p>資料を選択し、内容または基本情報を確認する画面です。</p><p class="meta">解析・AI分類・既存カードへの取り込みは次バージョン以降で実装します。</p><button onclick="setView('home')">ホームへ戻る</button></section>${importMethodCards()}<section class="import-workspace"><div class="section-head"><div><p class="eyebrow">File</p><h2>ファイル選択</h2></div><label class="file import-file-button">ファイルを選択<input id="importFileInput" type="file" accept="${IMPORT_CENTER_ACCEPT}" onchange="handleImportFile(this.files[0])"></label></div><p class="meta">対応：PDF / TXT / Markdown(.md) / JSON / Word(.docx)。iPad Safariで押しやすいボタンにしています。</p>${f?`<div class="import-file-meta"><div><b>ファイル名</b><span>${esc(f.name)}</span></div><div><b>サイズ</b><span>${esc(importFormatSize(f.size))}</span></div><div><b>種類</b><span>${esc(importFileKind(f))}</span></div><div><b>更新日時</b><span>${esc(importFormatDate(f.lastModified))}</span></div></div>`:'<p class="empty-note">まだファイルが選択されていません。</p>'}</section><section><h2>長文貼り付け</h2><label>貼り付け用テキストエリア<textarea id="importPasteText" rows="10" placeholder="ここに長文を貼り付けます。解析や保存先への反映はまだ行いません。" oninput="importCenterSelection.pasteText=this.value">${esc(importCenterSelection.pasteText||'')}</textarea></label><button class="primary-action" onclick="savePasteImportHistory()">貼り付けを履歴に保存</button></section><section><h2>プレビュー</h2><div id="importPreview">${importPreviewHtml(f,p)}</div></section><section><h2>読み込み履歴</h2><div id="importHistory">${importHistoryRows()}</div></section><section><h2>ノヴァ整理</h2><p class="empty-note">ノヴァ整理、解析、AI分類はまだ実装していません。</p></section><section><button onclick="setView('home')">ホームへ戻る</button></section>`}
function importPreviewHtml(file,preview){if(!file)return '<p class="empty-note">ファイルを選択するとプレビューが表示されます。</p>';const kind=importFileKind(file);if(kind==='TXT'||kind==='Markdown'||kind==='JSON')return `<pre class="import-preview-text">${esc(preview?.text||'読み込み中…')}</pre>`;if(kind==='PDF')return `<div class="import-preview-summary"><p><b>PDF</b></p><p>ページ数：${esc(preview?.pages||'確認中')}</p><p>ファイル名：${esc(file.name)}</p><p>サイズ：${esc(importFormatSize(file.size))}</p><p class="meta">PDF本文解析は次バージョンで対応します。</p></div>`;if(kind==='Word')return `<div class="import-preview-summary"><p><b>Word</b></p><p>ファイル名：${esc(file.name)}</p><p class="meta">Word本文解析は次バージョン以降で対応します。</p></div>`;return '<p class="empty-note">未対応ファイルです。</p>'}
function addImportHistory(fileName,kind){const c=ensureImportCenterState();c.history.unshift({id:uid('import'),importedAt:now(),fileName,kind});c.history=c.history.slice(0,50);saveState(true)}
function handleImportFile(file){if(!file)return;const kind=importFileKind(file);importCenterSelection={file,preview:{},pasteText:importCenterSelection.pasteText||''};addImportHistory(file.name,kind);render();if(['TXT','Markdown','JSON'].includes(kind)){const reader=new FileReader();reader.onload=()=>{let text=String(reader.result||'');if(kind==='JSON'){try{text=JSON.stringify(JSON.parse(text),null,2)}catch(e){text='JSONとして整形できませんでした。元の内容を表示します。\n\n'+text}}importCenterSelection.preview={text};render()};reader.onerror=()=>{importCenterSelection.preview={text:'ファイルの読み込みに失敗しました。'};render()};reader.readAsText(file)}else if(kind==='PDF'){const reader=new FileReader();reader.onload=()=>{const text=String(reader.result||'');const pages=(text.match(/\/Type\s*\/Page\b/g)||[]).length||'不明';importCenterSelection.preview={pages};render()};reader.readAsText(file)}else render()}
function savePasteImportHistory(){const text=$('#importPasteText')?.value||'';importCenterSelection.pasteText=text;if(!text.trim())return toast('貼り付け内容が空です');addImportHistory('長文貼り付け','Paste');render();toast('貼り付けを履歴に保存しました')}
const nova021OldHomeView=homeView;
homeView=function(){const base=nova021OldHomeView();return base.includes('aria-label="ホーム主要カード"')?base:`${homePrimaryCards()}${base}`}
const nova021OldRender=render;
render=function(){const v=(location.hash||'#home').slice(1);if(v==='importCenter')return shell(importCenterView());nova021OldRender()}

function saveProductionDashboardUrl(value){const d=dashboardApp();if(!d)return;d.url=String(value||'').trim();touch(d);saveState(true);render()}

// Version 0.2.3 Nova Studio basic bridge: receive URL params and return safely.
const novaBridgeParams=new URLSearchParams(location.search);
const novaBridge={
 project:novaBridgeParams.get('project')||'',
 episode:novaBridgeParams.get('episode')||'',
 source:novaBridgeParams.get('source')||'',
 returnUrl:novaBridgeParams.get('returnUrl')||''
};
function novaFindProject(value){if(!value)return null;return state.projects.find(p=>p.id===value)||state.projects.find(p=>p.title===value||p.shortName===value||p.englishTitle===value)||null}
function novaFindEpisode(projectId,value){if(!value)return null;return state.episodes.find(e=>e.projectId===projectId&&e.id===value)||state.episodes.find(e=>e.projectId===projectId&&(e.numberLabel===value||e.title===value||e.subtitle===value))||null}
function applyNovaBridgeParams(){const p=novaFindProject(novaBridge.project);if(!p)return false;const e=novaFindEpisode(p.id,novaBridge.episode)||state.episodes.find(x=>x.projectId===p.id&&x.numberLabel==='作品全体')||state.episodes.find(x=>x.projectId===p.id);state.activeContext={projectId:p.id,episodeId:e?.id||'',updatedAt:now()};state.lastLocation={...(state.lastLocation||{}),projectId:p.id,episodeId:e?.id||'',openedAt:now()};saveState(true);return true}
function novaStudioReturnTarget(){if(novaBridge.returnUrl)return novaBridge.returnUrl;return `${location.origin}${location.pathname}`}
function returnToNovaStudio(){window.location.href=novaStudioReturnTarget()}
function novaBridgeButtonHtml(){return `<button class="nova-return" onclick="returnToNovaStudio()">Nova Studioへ戻る</button>`}
const nova023Shell=shell;
shell=function(main){nova023Shell(main);const header=document.querySelector('header');if(header&&!header.querySelector('.nova-return'))header.insertAdjacentHTML('afterbegin',novaBridgeButtonHtml())}
