render();

// Version 0.2.4 Import Center: preview-to-candidates Nova organization flow.
const NOVA_IMPORT_CATEGORIES=['概要','世界観','キャラクター','時系列','用語','場所','アイテム','組織・種族','エピソード','台本','アイデア','伏線','変更履歴','作品設定','ゴミ箱'];
const NOVA_IMPORT_CATEGORY_COLLECTION={概要:'ideas',世界観:'worlds',キャラクター:'characters',時系列:'timelines',用語:'terms',場所:'worlds',アイテム:'terms','組織・種族':'worlds',エピソード:'episodes',台本:'scenes',アイデア:'ideas',伏線:'ideas',変更履歴:'changeHistory',作品設定:'worlds'};
function novaImportText(){const fileText=importCenterSelection.preview?.text||'';return String(fileText||importCenterSelection.pasteText||'').trim()}
function novaImportCategoryFor(text){const s=String(text||'');const tests=[['台本',/(セリフ|台詞|ナレーション|INT\.|EXT\.|「|」|脚本|台本)/],['キャラクター',/(キャラクター|人物|主人公|ヒロイン|性格|口調|年齢|能力|外見)/],['時系列',/(年表|時系列|年代|第\d+話|\d{4}年|翌日|過去|未来)/],['用語',/(用語|意味|定義|とは|キーワード|専門語)/],['場所',/(場所|都市|村|国|地域|拠点|店|学校|城|駅)/],['アイテム',/(アイテム|道具|武器|装備|鍵|本|端末|薬|宝石)/],['組織・種族',/(組織|会社|政府|軍|ギルド|種族|一族|チーム)/],['エピソード',/(エピソード|話|第\d|章|プロローグ|あらすじ)/],['伏線',/(伏線|謎|秘密|違和感|回収|暗示)/],['変更履歴',/(変更|修正|履歴|更新|改稿|差分)/],['作品設定',/(作品設定|ルール|設定|テーマ|ジャンル|コンセプト)/],['世界観',/(世界観|世界|魔法|科学|文化|歴史|社会|制度)/],['概要',/(概要|要約|サマリー|summary|about)/]];return (tests.find(([,re])=>re.test(s))||['アイデア'])[0]}
function novaImportSplitText(text){return String(text||'').split(/\n\s*\n|(?=^#{1,3}\s+)/m).map(x=>x.trim()).filter(Boolean).flatMap(block=>block.length>1200?block.match(/[\s\S]{1,1200}/g):[block]).slice(0,80)}
function novaImportTitle(text,category,index){const first=String(text||'').split('\n').map(x=>x.trim()).find(Boolean)||`${category} ${index+1}`;return first.replace(/^#{1,6}\s*/,'').slice(0,60)}
function novaOrganizeImport(){const text=novaImportText();if(!text)return toast('整理できる本文がありません。ファイルまたは長文貼り付けを読み込んでください');const c=ensureImportCenterState();c.candidates=novaImportSplitText(text).map((body,i)=>{const category=novaImportCategoryFor(body);return{id:uid('candidate'),createdAt:now(),sourceName:importCenterSelection.file?.name||'長文貼り付け',category,title:novaImportTitle(body,category,i),body,checked:category!=='ゴミ箱'}});saveState(true);render();toast('登録候補を作成しました')}
function novaImportCandidateRows(){const candidates=ensureImportCenterState().candidates||[];if(!candidates.length)return '<p class="empty-note">「Nova整理」を押すと、候補カテゴリへ分類した登録候補を表示します。まだ自動登録はしません。</p>';return candidates.map((x,i)=>`<article class="import-candidate ${x.checked?'selected':''}"><label><input type="checkbox" ${x.checked?'checked':''} onchange="toggleImportCandidate('${x.id}',this.checked)"> 登録候補 ${i+1}</label><div class="import-candidate-head"><select onchange="updateImportCandidate('${x.id}','category',this.value)">${NOVA_IMPORT_CATEGORIES.map(c=>`<option ${x.category===c?'selected':''}>${esc(c)}</option>`).join('')}</select><input value="${esc(x.title)}" onchange="updateImportCandidate('${x.id}','title',this.value)"></div><textarea rows="5" onchange="updateImportCandidate('${x.id}','body',this.value)">${esc(x.body)}</textarea></article>`).join('')+`<button class="primary-action" onclick="registerImportCandidates()">チェックした項目だけ登録</button>`}
function toggleImportCandidate(id,checked){const x=(ensureImportCenterState().candidates||[]).find(c=>c.id===id);if(x){x.checked=checked;saveState(true);render()}}
function updateImportCandidate(id,key,value){const x=(ensureImportCenterState().candidates||[]).find(c=>c.id===id);if(x){x[key]=value;saveState(true)}}
function registerImportCandidates(){const c=ensureImportCenterState(),items=(c.candidates||[]).filter(x=>x.checked);if(!items.length)return toast('チェックされた登録候補がありません');const p=currentProject(),e=currentEpisode();items.forEach(x=>{const collection=NOVA_IMPORT_CATEGORY_COLLECTION[x.category]||'ideas';state[collection]=state[collection]||[];const base={id:uid(COLLECTION_TYPE_MAP[collection]||'item'),projectId:p?.id||'',episodeId:collection==='scenes'?e?.id:'',title:x.title,status:'仮設定',tags:['Import Center',x.category],memo:x.body,summary:x.body,description:x.body,content:x.body,sortOrder:(state[collection]||[]).length+1};let item=normalizeCommonItem(base,COLLECTION_TYPE_MAP[collection]||'idea');if(collection==='episodes')item={...episode(item.id,p?.id||'',x.title,(state.episodes||[]).length+1),summary:x.body,memo:x.body,tags:base.tags};state[collection].push(touch(item))});c.history.unshift({id:uid('import'),importedAt:now(),fileName:'登録候補',kind:`${items.length}件登録`});c.candidates=(c.candidates||[]).filter(x=>!x.checked);state.backupStatus.lastImportedAt=now();saveState(true);render();toast(`${items.length}件を登録しました`)}
function importPdfTextPreview(raw){return String(raw||'').replace(/\\[()]/g,'').match(/[\u3040-\u30ff\u3400-\u9fff\w .,;:!?()\-]{8,}/g)?.join('\n').slice(0,12000)||''}
const nova024OldImportCenterView=importCenterView;
importCenterView=function(){ensureImportCenterState();const f=importCenterSelection.file,p=importCenterSelection.preview;return `<section class="hero import-hero"><h1>📥 Import Center</h1><p>資料を選択し、内容をプレビューしてからNova Studioの登録候補へ整理します。</p><p class="meta">Version 0.2.4：PDF / TXT / Markdown / JSON / 長文貼り付けを対象に、候補表示後、チェックした項目だけ登録します。</p><button onclick="setView('home')">ホームへ戻る</button></section>${importMethodCards()}<section class="import-workspace"><div class="section-head"><div><p class="eyebrow">File</p><h2>ファイル選択</h2></div><label class="file import-file-button">ファイルを選択<input id="importFileInput" type="file" accept="${IMPORT_CENTER_ACCEPT}" onchange="handleImportFile(this.files[0])"></label></div><p class="meta">既存データは自動変更しません。登録は「チェックした項目だけ登録」を押した時だけ行います。</p>${f?`<div class="import-file-meta"><div><b>ファイル名</b><span>${esc(f.name)}</span></div><div><b>サイズ</b><span>${esc(importFormatSize(f.size))}</span></div><div><b>種類</b><span>${esc(importFileKind(f))}</span></div><div><b>更新日時</b><span>${esc(importFormatDate(f.lastModified))}</span></div></div>`:'<p class="empty-note">まだファイルが選択されていません。</p>'}</section><section><h2>長文貼り付け</h2><label>貼り付け用テキストエリア<textarea id="importPasteText" rows="10" placeholder="ここに長文を貼り付けます。" oninput="importCenterSelection.pasteText=this.value">${esc(importCenterSelection.pasteText||'')}</textarea></label><button class="secondary" onclick="savePasteImportHistory()">貼り付けを履歴に保存</button></section><section><div class="section-head"><div><h2>プレビュー</h2><p class="meta">読み込み後の内容を確認できます。</p></div><button class="primary-action" onclick="novaOrganizeImport()">Nova整理</button></div><div id="importPreview">${importPreviewHtml(f,p)||'<pre class="import-preview-text">'+esc(importCenterSelection.pasteText||'')+'</pre>'}</div></section><section><h2>登録候補</h2>${novaImportCandidateRows()}</section><section><h2>読み込み履歴</h2><div id="importHistory">${importHistoryRows()}</div></section><section><button onclick="setView('home')">ホームへ戻る</button></section>`}
const nova024OldHandleImportFile=handleImportFile;
handleImportFile=function(file){if(!file)return;const kind=importFileKind(file);if(kind==='Word')return nova024OldHandleImportFile(file);importCenterSelection={file,preview:{},pasteText:importCenterSelection.pasteText||''};addImportHistory(file.name,kind);render();const reader=new FileReader();reader.onload=()=>{let text=String(reader.result||'');if(kind==='JSON'){try{text=JSON.stringify(JSON.parse(text),null,2)}catch(e){text='JSONとして整形できませんでした。元の内容を表示します。\n\n'+text}}else if(kind==='PDF'){const pages=(text.match(/\/Type\s*\/Page\b/g)||[]).length||'不明';const extracted=importPdfTextPreview(text);importCenterSelection.preview={pages,text:extracted||`PDF本文を直接抽出できませんでした。\nページ数：${pages}\nファイル名：${file.name}\nサイズ：${importFormatSize(file.size)}`};render();return}importCenterSelection.preview={text};render()};reader.onerror=()=>{importCenterSelection.preview={text:'ファイルの読み込みに失敗しました。'};render()};reader.readAsText(file)};
const nova024OldImportPreviewHtml=importPreviewHtml;
importPreviewHtml=function(file,preview){if(!file){const pasted=String(importCenterSelection.pasteText||'').trim();return pasted?`<pre class="import-preview-text">${esc(pasted)}</pre>`:'<p class="empty-note">ファイル選択または長文貼り付けを行うとプレビューが表示されます。</p>'}const kind=importFileKind(file);if(['TXT','Markdown','JSON','PDF'].includes(kind))return `<pre class="import-preview-text">${esc(preview?.text||'読み込み中…')}</pre>`;return nova024OldImportPreviewHtml(file,preview)};
render();

// Version 0.2.5 Import Center: confirm selected candidates before saving to Story Archive.
const NOVA_IMPORT_REGISTER_CATEGORIES=NOVA_IMPORT_CATEGORIES.filter(x=>x!=='ゴミ箱');
function novaImportTargetOptions(selected){return NOVA_IMPORT_REGISTER_CATEGORIES.map(c=>`<option value="${esc(c)}" ${selected===c?'selected':''}>${esc(c)}</option>`).join('')}
function novaImportCollectionFor(category){return NOVA_IMPORT_CATEGORY_COLLECTION[category]||'ideas'}
function novaImportDuplicateFor(candidate){const collection=novaImportCollectionFor(candidate.category),title=String(candidate.title||'').trim();if(!title)return null;return (state[collection]||[]).find(item=>String(storyTitle(collection,item)||continueTitle(collection,item)||item.title||'').trim()===title&&(!candidate.projectId||!item.projectId||item.projectId===candidate.projectId))||null}
function novaImportDuplicateBadge(candidate){const dup=novaImportDuplicateFor(candidate);return dup?`<div class="import-duplicate"><b>重複候補</b>：同じタイトル「${esc(candidate.title)}」が ${esc(STORY_LABELS[novaImportCollectionFor(candidate.category)]||candidate.category)} にあります。<br><label>重複時の動作<select onchange="updateImportCandidate('${candidate.id}','duplicateAction',this.value)">${novaImportDuplicateActionOptions(candidate.duplicateAction||'new')}</select></label></div>`:''}
function novaImportDuplicateActionOptions(selected){return [['new','新規登録'],['keep','既存を維持'],['manual','手動で確認']].map(([value,label])=>`<option value="${value}" ${selected===value?'selected':''}>${label}</option>`).join('')}
function novaImportCandidateRows(){const candidates=ensureImportCenterState().candidates||[];if(!candidates.length)return '<p class="empty-note">「Nova整理」を押すと、候補カテゴリへ分類した登録候補を表示します。まだ自動登録はしません。</p>';return `<div class="section-head"><div><p class="meta">候補ごとにチェック、タイトル、本文、登録先を確認できます。</p></div><button class="primary-action" onclick="showImportRegisterConfirm()">Story Archiveへ登録</button></div>`+candidates.map((x,i)=>`<article class="import-candidate ${x.checked?'selected':''}"><label><input type="checkbox" ${x.checked?'checked':''} onchange="toggleImportCandidate('${x.id}',this.checked)"> 登録候補 ${i+1}</label><div class="import-candidate-head"><select aria-label="登録先" onchange="updateImportCandidate('${x.id}','category',this.value)">${novaImportTargetOptions(x.category)}</select><input aria-label="タイトル" value="${esc(x.title)}" onchange="updateImportCandidate('${x.id}','title',this.value)"></div>${novaImportDuplicateBadge(x)}<textarea rows="5" aria-label="本文" onchange="updateImportCandidate('${x.id}','body',this.value)">${esc(x.body)}</textarea></article>`).join('')+`<button class="primary-action" onclick="showImportRegisterConfirm()">Story Archiveへ登録</button>`}
function novaImportSelectedCandidates(){return (ensureImportCenterState().candidates||[]).filter(x=>x.checked&&NOVA_IMPORT_REGISTER_CATEGORIES.includes(x.category))}
function showImportRegisterConfirm(){const items=novaImportSelectedCandidates();if(!items.length)return toast('チェックされた登録候補がありません');const byTarget=items.reduce((a,x)=>{a[x.category]=(a[x.category]||0)+1;return a},{});const duplicates=items.map(x=>({candidate:x,dup:novaImportDuplicateFor(x)})).filter(x=>x.dup);modal(`<h2>Story Archiveへ登録確認</h2><p>対象件数：<b>${items.length}件</b></p><h3>登録先</h3><ul>${Object.entries(byTarget).map(([k,v])=>`<li>${esc(k)}：${v}件</li>`).join('')}</ul><h3>重複候補</h3>${duplicates.length?duplicates.map(({candidate,dup})=>`<div class="import-duplicate"><b>${esc(candidate.title)}</b><br><small>${esc(candidate.category)} / 既存ID：${esc(dup.id||'')}</small><label>重複時の動作<select onchange="updateImportCandidate('${candidate.id}','duplicateAction',this.value)">${novaImportDuplicateActionOptions(candidate.duplicateAction||'new')}</select></label></div>`).join(''):'<p class="empty-note">同じタイトルの既存項目は見つかりませんでした。</p>'}<p class="meta">新規登録は既存項目を上書きせず追加します。既存を維持は候補を登録せず処理済みにします。手動で確認は候補を残して該当カテゴリを開きます。</p><button class="primary-action" onclick="registerImportCandidates()">この内容で登録</button><button class="secondary" onclick="closeModal()">戻って修正</button>`)}
function registerImportCandidates(){const c=ensureImportCenterState(),items=novaImportSelectedCandidates();if(!items.length)return toast('チェックされた登録候補がありません');const p=currentProject(),e=currentEpisode();let registered=0,kept=0,manual=0,openedCategory=items[items.length-1]?.category;items.forEach(x=>{const dup=novaImportDuplicateFor(x),action=dup?(x.duplicateAction||'new'):'new';if(action==='manual'){manual++;openedCategory=x.category;return}if(action==='keep'){kept++;return}const collection=novaImportCollectionFor(x.category);openedCategory=x.category;state[collection]=state[collection]||[];const base={id:uid(COLLECTION_TYPE_MAP[collection]||'item'),projectId:p?.id||'',episodeId:collection==='scenes'?e?.id:'',title:x.title,status:'仮設定',tags:['Import Center',x.category],memo:x.body,summary:x.body,description:x.body,content:x.body,sortOrder:(state[collection]||[]).length+1,importSource:{sourceName:x.sourceName||'',candidateId:x.id,importedAt:now(),category:x.category,duplicateAction:action,duplicateOf:dup?.id||''}};let item=normalizeCommonItem(base,COLLECTION_TYPE_MAP[collection]||'idea');if(collection==='episodes')item={...episode(item.id,p?.id||'',x.title,(state.episodes||[]).filter(ep=>ep.projectId===p?.id).length+1),summary:x.body,memo:x.body,tags:base.tags,importSource:base.importSource};state[collection].push(touch(item));registered++});c.history.unshift({id:uid('import'),importedAt:now(),fileName:'Story Archive登録候補',kind:`${registered}件登録 / ${kept}件維持 / ${manual}件手動確認`});const processedIds=new Set(items.filter(x=>{const dup=novaImportDuplicateFor(x),action=dup?(x.duplicateAction||'new'):'new';return action!=='manual'}).map(x=>x.id));c.candidates=(c.candidates||[]).filter(x=>!processedIds.has(x.id));state.backupStatus.lastImportedAt=now();saveState(true);closeModal();openImportArchiveList(openedCategory);toast(`${registered}件を登録、${kept}件は既存維持、${manual}件は候補に残しました`)}
function openImportArchiveList(category){const collection=novaImportCollectionFor(category);if(collection==='episodes')return setView('episodes');if(collection==='changeHistory')return setView('history');const views={worlds:'worlds',characters:'characters',timelines:'timelines',terms:'terms',scenes:'scenes',ideas:'ideas'};setView(views[collection]||'ideas')}
const nova025OldImportCenterView=importCenterView;
importCenterView=function(){ensureImportCenterState();const f=importCenterSelection.file,p=importCenterSelection.preview;return `<section class="hero import-hero"><h1>📥 Import Center</h1><p>資料を選択し、内容をプレビューしてからStory Archiveの登録候補へ整理します。</p><p class="meta">Version 0.2.5：候補をチェックし、登録先と重複候補を確認してからStory Archiveへ登録します。</p><button onclick="setView('home')">ホームへ戻る</button></section>${importMethodCards()}<section class="import-workspace"><div class="section-head"><div><p class="eyebrow">File</p><h2>ファイル選択</h2></div><label class="file import-file-button">ファイルを選択<input id="importFileInput" type="file" accept="${IMPORT_CENTER_ACCEPT}" onchange="handleImportFile(this.files[0])"></label></div><p class="meta">既存データは自動変更しません。登録は確認画面で「この内容で登録」を押した時だけ追記します。</p>${f?`<div class="import-file-meta"><div><b>ファイル名</b><span>${esc(f.name)}</span></div><div><b>サイズ</b><span>${esc(importFormatSize(f.size))}</span></div><div><b>種類</b><span>${esc(importFileKind(f))}</span></div><div><b>更新日時</b><span>${esc(importFormatDate(f.lastModified))}</span></div></div>`:'<p class="empty-note">まだファイルが選択されていません。</p>'}</section><section><h2>長文貼り付け</h2><label>貼り付け用テキストエリア<textarea id="importPasteText" rows="10" placeholder="ここに長文を貼り付けます。" oninput="importCenterSelection.pasteText=this.value">${esc(importCenterSelection.pasteText||'')}</textarea></label><button class="secondary" onclick="savePasteImportHistory()">貼り付けを履歴に保存</button></section><section><div class="section-head"><div><h2>プレビュー</h2><p class="meta">読み込み後の内容を確認できます。</p></div><button class="primary-action" onclick="novaOrganizeImport()">Nova整理</button></div><div id="importPreview">${importPreviewHtml(f,p)||'<pre class="import-preview-text">'+esc(importCenterSelection.pasteText||'')+'</pre>'}</div></section><section><h2>登録候補</h2>${novaImportCandidateRows()}</section><section><h2>読み込み履歴</h2><div id="importHistory">${importHistoryRows()}</div></section><section><button onclick="setView('home')">ホームへ戻る</button></section>`}
render();

// Version 0.2.6 Story Archive foundation: real card registration, local CRUD, and search.
function ensureStoryArchiveState(){state.storyArchiveCards=Array.isArray(state.storyArchiveCards)?state.storyArchiveCards:[];return state.storyArchiveCards}
function normalizeStoryArchiveCard(card={}){const t=card.createdAt||card.updatedAt||now(),p=currentProject(),e=currentEpisode();return{...commonItemFields(COMMON_ITEM_TYPES.STORY_ARCHIVE_CARD,card.title||'',t),id:card.id||uid('archive'),type:COMMON_ITEM_TYPES.STORY_ARCHIVE_CARD,title:card.title||'無題',body:card.body||card.content||card.memo||'',category:STORY_ARCHIVE_CATEGORIES.includes(card.category)?card.category:'概要',tags:Array.isArray(card.tags)?card.tags:parseTags(card.tags),projectId:card.projectId||card.project||p?.id||'',episodeId:card.episodeId||card.episode||e?.id||'',relatedIds:Array.isArray(card.relatedIds)?card.relatedIds:parseTags(card.relatedIds),relatedWorks:Array.isArray(card.relatedWorks)?card.relatedWorks:parseTags(card.relatedWorks),relatedEpisodes:Array.isArray(card.relatedEpisodes)?card.relatedEpisodes:parseTags(card.relatedEpisodes),createdAt:t,updatedAt:card.updatedAt||t,status:STORY_ARCHIVE_STATUSES.includes(card.status)?card.status:'仮設定'}}
function storyArchiveProjectName(id){return state.projects.find(p=>p.id===id)?.title||id||'未設定'}
function storyArchiveEpisodeName(id){return state.episodes.find(e=>e.id===id)?.numberLabel||id||'未設定'}
function storyArchiveCards(){return ensureStoryArchiveState().map(normalizeStoryArchiveCard)}
function storyArchiveScopedCards(){const p=currentProject(),e=currentEpisode();return storyArchiveCards().filter(c=>(!p||c.projectId===p.id)&&(!e||c.episodeId===e.id||e.numberLabel==='作品全体')).sort((a,b)=>(b.updatedAt||'').localeCompare(a.updatedAt||''))}
function storyArchiveSearchText(card){return [card.title,card.category,card.body,(card.tags||[]).join(' '),(card.relatedWorks||[]).join(' '),(card.relatedEpisodes||[]).join(' '),(card.relatedIds||[]).join(' '),storyArchiveProjectName(card.projectId),storyArchiveEpisodeName(card.episodeId),card.status].join(' ').toLowerCase()}
function storyArchiveFilterCards(cards){const q=($('#storyArchiveSearch')?.value||'').trim().toLowerCase();return q?cards.filter(c=>storyArchiveSearchText(c).includes(q)):cards}
function storyArchiveCardsByCategory(){const scoped=storyArchiveFilterCards(storyArchiveScopedCards());return STORY_ARCHIVE_CATEGORIES.map(category=>({category,cards:scoped.filter(c=>c.category===category)}))}
function getStoryArchiveCard(id){return ensureStoryArchiveState().find(c=>c.id===id)}
function newStoryArchiveCard(){const p=currentProject(),e=currentEpisode();return normalizeStoryArchiveCard({title:'',body:'',category:'概要',tags:[],projectId:p?.id||'',episodeId:e?.id||'',relatedIds:[],status:'仮設定'})}
function editStoryArchiveCard(id=''){const existing=id?getStoryArchiveCard(id):newStoryArchiveCard();const card=normalizeStoryArchiveCard(existing);modal(`<h2>${id?'Story Archiveカード編集':'Story Archiveカード作成'}</h2><label>ID<input id="archiveId" value="${esc(card.id)}" ${id?'readonly':''}></label><label>タイトル<input id="archiveTitle" value="${esc(card.title)}"></label><label>本文<textarea id="archiveBody" rows="8">${esc(card.body)}</textarea></label><label>カテゴリ<select id="archiveCategory">${STORY_ARCHIVE_CATEGORIES.map(c=>`<option value="${esc(c)}" ${card.category===c?'selected':''}>${esc(c)}</option>`).join('')}</select></label><label>タグ（カンマ区切り）<input id="archiveTags" value="${esc(tagInputValue(card))}"></label><label>作品<select id="archiveProject">${state.projects.map(p=>`<option value="${esc(p.id)}" ${card.projectId===p.id?'selected':''}>${esc(p.title)}</option>`).join('')}</select></label><label>話数<select id="archiveEpisode">${state.episodes.map(e=>`<option value="${esc(e.id)}" ${card.episodeId===e.id?'selected':''}>${esc(storyArchiveProjectName(e.projectId))} / ${esc(e.numberLabel)}</option>`).join('')}</select></label><label>関連作品<input id="archiveRelatedWorks" value="${esc((card.relatedWorks||[]).join(','))}" placeholder="作品名・作品IDをカンマ区切り"></label><label>関連話数<input id="archiveRelatedEpisodes" value="${esc((card.relatedEpisodes||[]).join(','))}" placeholder="話数名・話数IDをカンマ区切り"></label><label>関連カードID（カンマ区切り）<input id="archiveRelated" value="${esc((card.relatedIds||[]).join(','))}"></label><label>状態<select id="archiveStatus">${STORY_ARCHIVE_STATUSES.map(s=>`<option value="${esc(s)}" ${card.status===s?'selected':''}>${esc(s)}</option>`).join('')}</select></label><p class="meta">作成日時：${esc(card.createdAt)} / 更新日時：${esc(card.updatedAt)}</p><button class="primary-action" onclick="saveStoryArchiveCard('${esc(id)}')">保存</button><button class="secondary" onclick="closeModal()">キャンセル</button>`)}
function saveStoryArchiveCard(id=''){const cards=ensureStoryArchiveState(),current=id?getStoryArchiveCard(id):null;const next=normalizeStoryArchiveCard({...(current||{}),id:($('#archiveId')?.value||uid('archive')).trim(),title:$('#archiveTitle')?.value||'',body:$('#archiveBody')?.value||'',category:$('#archiveCategory')?.value||'概要',tags:parseTags($('#archiveTags')?.value||''),projectId:$('#archiveProject')?.value||'',episodeId:$('#archiveEpisode')?.value||'',relatedIds:parseTags($('#archiveRelated')?.value||''),relatedWorks:parseTags($('#archiveRelatedWorks')?.value||''),relatedEpisodes:parseTags($('#archiveRelatedEpisodes')?.value||''),status:$('#archiveStatus')?.value||'仮設定',createdAt:current?.createdAt||now(),updatedAt:now()});const i=cards.findIndex(c=>c.id===(id||next.id));if(i>=0)cards[i]=next;else cards.push(next);saveState(true);closeModal();render();toast('Story Archiveカードを保存しました')}
function deleteStoryArchiveCard(id){if(state.settings.confirmOnDelete&&!confirm('Story Archiveカードを削除します。よろしいですか？'))return;state.storyArchiveCards=ensureStoryArchiveState().filter(c=>c.id!==id);saveState(true);render();toast('Story Archiveカードを削除しました')}
function storyArchiveView(){const p=currentProject(),e=currentEpisode(),groups=storyArchiveCardsByCategory(),total=groups.reduce((n,g)=>n+g.cards.length,0);return `<section class="hero"><p class="eyebrow">Story Archive</p><h1>Story Archive</h1><p>作品設定を蓄積するためのカード登録画面です。入力したカードは既存のlocalStorageキー内へ追記保存します。</p><p class="meta">現在：${esc(p?.title||'未選択')} / ${esc(e?.numberLabel||'未選択')} / ${total}件</p><button class="primary-action" onclick="editStoryArchiveCard()">＋カード作成</button></section><section><h2>検索</h2><input id="storyArchiveSearch" placeholder="タイトル・カテゴリ・本文・タグ・関連作品・関連話数を検索" oninput="render()" value="${esc($('#storyArchiveSearch')?.value||'')}"></section><section><h2>カテゴリ</h2><div class="archive-category-grid">${groups.map(g=>`<article class="archive-category"><h3>${esc(g.category)} <span class="meta">${g.cards.length}件</span></h3>${g.cards.map(c=>`<div class="archive-card"><h4>${esc(c.title)}</h4><p>${esc(c.body).slice(0,160)}</p><p class="meta">ID：${esc(c.id)} / 作品：${esc(storyArchiveProjectName(c.projectId))} / 話数：${esc(storyArchiveEpisodeName(c.episodeId))}<br>タグ：${esc((c.tags||[]).join(', ')||'なし')} / 関連作品：${esc((c.relatedWorks||[]).join(', ')||'なし')} / 関連話数：${esc((c.relatedEpisodes||[]).join(', ')||'なし')}<br>関連カード：${esc((c.relatedIds||[]).join(', ')||'なし')}<br>作成：${esc(c.createdAt)} / 更新：${esc(c.updatedAt)} / 状態：${esc(c.status)}</p><button onclick="editStoryArchiveCard('${c.id}')">編集</button><button class="danger" onclick="deleteStoryArchiveCard('${c.id}')">削除</button></div>`).join('')||'<p class="empty-note">カードなし</p>'}</article>`).join('')}</div></section>`}
const nova025ArchiveOldRender=render;
render=function(){ensureStoryArchiveState();const v=(location.hash||'#home').slice(1);if(v==='storyArchive')return shell(storyArchiveView());nova025ArchiveOldRender()}
const nova025ArchiveOldOpenApp=openApp;
openApp=function(appId,urlOverride){if(appId==='storyArchive'&&!urlOverride&&!storyArchiveApp()?.url)return setView('storyArchive');return nova025ArchiveOldOpenApp(appId,urlOverride)}
render();

// Version 0.2.7 Story Archive links and image reference management.
