const ARCHIVE_CHARACTER_IMAGE_TYPES=['正式立ち絵','三面図 正面','三面図 左側面','三面図 右側面','三面図 背面','斜め前','斜め後ろ','表情集','衣装','ちびキャラ','髪型','小物','部分資料','Vidu用基準画像','ロゴ・配色資料','旧デザイン','没案','制作途中','その他'];
const ARCHIVE_PLACE_IMAGE_TYPES=['正面','左側','右側','背面','斜め前','斜め後ろ','俯瞰','真上','煽り','広角','寄り','外観','室内','入口側','窓側','間取り','配置図','背景美術','昼','夜','朝','夕方','季節違い','天候違い','Vidu用基準画像','旧案','没案','制作途中','その他'];
const ARCHIVE_ITEM_IMAGE_TYPES=['正面','左側面','右側面','背面','上面','底面','斜め前','斜め後ろ','分解図','開いた状態','閉じた状態','使用中','収納時','持った状態','装着状態','サイズ比較','細部アップ','材質資料','配色資料','Vidu用基準画像','旧案','没案','制作途中','その他'];
const ARCHIVE_ANGLES=['正面','左側面','右側面','背面','斜め前左','斜め前右','斜め後ろ左','斜め後ろ右','真上','俯瞰','水平','煽り','真下','自由入力'];
const ARCHIVE_STATES=['通常','開いている','閉じている','壊れている','使用中','収納中','装着中','変形前','変形後','点灯','消灯','昼','夜','雨','雪','その他'];
function archiveImageTypeOptions(category){return (category==='キャラクター'?ARCHIVE_CHARACTER_IMAGE_TYPES:['背景','場所','世界観'].includes(category)?ARCHIVE_PLACE_IMAGE_TYPES:['アイテム','小物'].includes(category)?ARCHIVE_ITEM_IMAGE_TYPES:[...new Set([...ARCHIVE_CHARACTER_IMAGE_TYPES,...ARCHIVE_PLACE_IMAGE_TYPES,...ARCHIVE_ITEM_TYPES])]).map(x=>`<option value="${esc(x)}">${esc(x)}</option>`).join('')}
function normalizeArchiveImage(img={},card={}){const t=img.createdAt||img.updatedAt||now();return{id:img.id||uid('archiveImage'),name:img.name||img.imageName||img.fileName||'画像資料',cardId:img.cardId||card.id||'',targetCategory:img.targetCategory||card.category||'',materialType:img.materialType||img.kind||'その他',angle:img.angle||'',viewpoint:img.viewpoint||img.angle||'',direction:img.direction||'',state:img.state||'通常',timeOfDay:img.timeOfDay||'',weather:img.weather||'',season:img.season||'',description:img.description||'',isOfficial:Boolean(img.isOfficial),version:img.version||'',createdAt:t,updatedAt:img.updatedAt||t,storageLocation:img.storageLocation||'',fileName:img.fileName||'',tags:Array.isArray(img.tags)?img.tags:parseTags(img.tags),notes:img.notes||'',sourceKind:img.sourceKind||'元画像',displayRange:img.displayRange||'',sortOrder:Number(img.sortOrder||0),relatedImageIds:Array.isArray(img.relatedImageIds)?img.relatedImageIds:parseTags(img.relatedImageIds),previewDataUrl:img.previewDataUrl||''}}
function normalizeArchiveImageSet(set={},card={}){const t=set.createdAt||set.updatedAt||now();return{id:set.id||uid('archiveImageSet'),name:set.name||'画像セット',cardId:set.cardId||card.id||'',description:set.description||'',imageIds:Array.isArray(set.imageIds)?set.imageIds:parseTags(set.imageIds),baseImageId:set.baseImageId||'',createdAt:t,updatedAt:set.updatedAt||t,sortOrder:Number(set.sortOrder||0)}}
const v027OldNormalizeStoryArchiveCard=normalizeStoryArchiveCard;
normalizeStoryArchiveCard=function(card={}){const c=v027OldNormalizeStoryArchiveCard(card);c.relatedIds=[...new Set((Array.isArray(c.relatedIds)?c.relatedIds:parseTags(c.relatedIds)).filter(Boolean))];c.images=(Array.isArray(card.images)?card.images:[]).map(x=>normalizeArchiveImage(x,c));c.imageSets=(Array.isArray(card.imageSets)?card.imageSets:[]).map(x=>normalizeArchiveImageSet(x,c));return c}
function saveNormalizedArchiveCard(card){const cards=ensureStoryArchiveState(),i=cards.findIndex(c=>c.id===card.id);if(i>=0)cards[i]=card;else cards.push(card)}
function archiveRelatedIds(card){return [...new Set([...(card.relatedIds||[]),...storyArchiveCards().filter(c=>(c.relatedIds||[]).includes(card.id)).map(c=>c.id)].filter(id=>id&&id!==card.id&&getStoryArchiveCard(id)))]}
function archiveRelatedLinks(card){const ids=archiveRelatedIds(card);return ids.length?ids.map(id=>{const c=getStoryArchiveCard(id);return `<button class="secondary mini" onclick="openStoryArchiveDetail('${id}')">${esc(c?.title||id)}</button>`}).join(' '):'<span class="meta">関連カードなし</span>'}
function archiveRelatedPicker(card){const ids=new Set(archiveRelatedIds(card));return `<label>関連カードを検索・複数選択<select id="archiveRelated" multiple>${storyArchiveCards().filter(c=>c.id!==card.id).map(c=>`<option value="${esc(c.id)}" ${ids.has(c.id)?'selected':''}>${esc(c.title)} / ${esc(c.category)} / ${esc((c.tags||[]).join(' '))}</option>`).join('')}</select></label><p class="meta">タイトル・本文・タグ・関連カード名は検索対象です。保存時に相互表示され、解除は選択を外して保存します。</p>`}
function archiveSyncBacklinks(cardId,nextIds){storyArchiveCards().forEach(c=>{let changed=false;const has=(c.relatedIds||[]).includes(cardId),want=nextIds.includes(c.id);if(want&&!has){c.relatedIds=[...(c.relatedIds||[]),cardId];changed=true}if(!want&&has){c.relatedIds=(c.relatedIds||[]).filter(id=>id!==cardId);changed=true}if(changed){c.updatedAt=now();saveNormalizedArchiveCard(c)}})}
function archiveFormImages(card){return `<section><h3>画像資料</h3><p class="meta">元画像本体は保存せず、小さなプレビュー・ファイル名・保存場所・登録情報だけ保存します。</p>${archiveImageGallery(card,'all')}<label class="file">複数画像を追加<input type="file" accept="image/*" multiple onchange="addArchiveImages('${card.id}',this.files)"></label><button class="secondary" onclick="editArchiveImage('${card.id}')">画像情報を手入力</button><button class="secondary" onclick="editArchiveImageSet('${card.id}')">画像セット作成</button></section>`}
editStoryArchiveCard=function(id=''){const card=normalizeStoryArchiveCard(id?getStoryArchiveCard(id):newStoryArchiveCard());modal(`<h2>${id?'Story Archiveカード編集':'Story Archiveカード作成'}</h2><label>ID<input id="archiveId" value="${esc(card.id)}" ${id?'readonly':''}></label><label>タイトル<input id="archiveTitle" value="${esc(card.title)}"></label><label>本文<textarea id="archiveBody" rows="8">${esc(card.body)}</textarea></label><label>カテゴリ<select id="archiveCategory">${STORY_ARCHIVE_CATEGORIES.map(c=>`<option value="${esc(c)}" ${card.category===c?'selected':''}>${esc(c)}</option>`).join('')}</select></label><label>タグ（カンマ区切り）<input id="archiveTags" value="${esc(tagInputValue(card))}"></label><label>作品<select id="archiveProject">${state.projects.map(p=>`<option value="${esc(p.id)}" ${card.projectId===p.id?'selected':''}>${esc(p.title)}</option>`).join('')}</select></label><label>話数<select id="archiveEpisode">${state.episodes.map(e=>`<option value="${esc(e.id)}" ${card.episodeId===e.id?'selected':''}>${esc(storyArchiveProjectName(e.projectId))} / ${esc(e.numberLabel)}</option>`).join('')}</select></label><label>関連作品<input id="archiveRelatedWorks" value="${esc((card.relatedWorks||[]).join(','))}"></label><label>関連話数<input id="archiveRelatedEpisodes" value="${esc((card.relatedEpisodes||[]).join(','))}"></label>${archiveRelatedPicker(card)}<label>状態<select id="archiveStatus">${STORY_ARCHIVE_STATUSES.map(s=>`<option value="${esc(s)}" ${card.status===s?'selected':''}>${esc(s)}</option>`).join('')}</select></label>${ARCHIVE_IMAGE_CATEGORIES.includes(card.category)?archiveFormImages(card):'<p class="meta">画像資料は保存後、対象カテゴリで表示されます。</p>'}<p class="meta">作成日時：${esc(card.createdAt)} / 更新日時：${esc(card.updatedAt)}</p><button class="primary-action" onclick="saveStoryArchiveCard('${esc(id)}')">保存</button><button class="secondary" onclick="closeModal()">キャンセル</button>`)};
saveStoryArchiveCard=function(id=''){const current=id?normalizeStoryArchiveCard(getStoryArchiveCard(id)):null;const next=normalizeStoryArchiveCard({...(current||{}),id:($('#archiveId')?.value||uid('archive')).trim(),title:$('#archiveTitle')?.value||'',body:$('#archiveBody')?.value||'',category:$('#archiveCategory')?.value||'概要',tags:parseTags($('#archiveTags')?.value||''),projectId:$('#archiveProject')?.value||'',episodeId:$('#archiveEpisode')?.value||'',relatedIds:selectedIds('archiveRelated'),relatedWorks:parseTags($('#archiveRelatedWorks')?.value||''),relatedEpisodes:parseTags($('#archiveRelatedEpisodes')?.value||''),status:$('#archiveStatus')?.value||'仮設定',images:current?.images||[],imageSets:current?.imageSets||[],createdAt:current?.createdAt||now(),updatedAt:now()});saveNormalizedArchiveCard(next);archiveSyncBacklinks(next.id,next.relatedIds||[]);saveState(true);closeModal();render();toast('Story Archiveカードを保存しました')};
deleteStoryArchiveCard=function(id){if(state.settings.confirmOnDelete&&!confirm('Story Archiveカードを削除します。よろしいですか？'))return;state.storyArchiveCards=ensureStoryArchiveState().filter(c=>c.id!==id).map(c=>({...c,relatedIds:(c.relatedIds||[]).filter(r=>r!==id),imageSets:(c.imageSets||[]).map(s=>({...s,imageIds:(s.imageIds||[]).filter(Boolean)}))}));saveState(true);render();toast('Story Archiveカードを削除しました')};
function archiveThumb(img){return img.previewDataUrl?`<img src="${img.previewDataUrl}" alt="">`:'<div class="archive-thumb-empty">No preview</div>'}
function archiveImageGallery(card,mode='all'){card=normalizeStoryArchiveCard(card);let imgs=[...(card.images||[])].sort((a,b)=>(+a.sortOrder||0)-(+b.sortOrder||0));if(mode==='official')imgs=imgs.filter(i=>i.isOfficial);if(mode==='old')imgs=imgs.filter(i=>['旧案','旧デザイン'].includes(i.materialType));if(mode==='rejected')imgs=imgs.filter(i=>i.materialType==='没案');if(mode==='set')return (card.imageSets||[]).map(s=>`<article class="archive-image-set"><h4>${esc(s.name)}</h4><p>${esc(s.description||'')}</p><div class="archive-gallery">${imgs.filter(i=>(s.imageIds||[]).includes(i.id)).map(i=>archiveImageCard(card,i)).join('')||'<p class="meta">画像なし</p>'}</div><button class="secondary" onclick="editArchiveImageSet('${card.id}','${s.id}')">セット編集</button><button class="danger" onclick="deleteArchiveImageSet('${card.id}','${s.id}')">セット削除</button></article>`).join('')||'<p class="meta">画像セットなし</p>';return `<div class="archive-gallery">${imgs.map(i=>archiveImageCard(card,i)).join('')||'<p class="meta">画像資料なし</p>'}</div>`}
function archiveImageCard(card,img){return `<article class="archive-image-card" onclick="openArchiveImageDetail('${card.id}','${img.id}')">${archiveThumb(img)}<b>${esc(img.name)}</b><small>${esc(img.materialType)} / ${esc(img.angle||'角度未設定')} / ${esc(img.state||'状態未設定')}</small><small>${img.isOfficial?'正式採用':''} ${esc(img.fileName||'')}</small></article>`}
function openStoryArchiveDetail(id,mode='all'){const card=normalizeStoryArchiveCard(getStoryArchiveCard(id));if(!card)return;modal(`<h2>${esc(card.title)}</h2><p>${metaLine(card)}<br>カテゴリ：${esc(card.category)} / タグ：${itemTagsHtml(card)}</p><section><h3>本文</h3><p>${esc(card.body)}</p></section><section><h3>関連カード</h3>${archiveRelatedLinks(card)}</section><section><h3>画像ギャラリー</h3><div class="gallery-tabs">${[['all','すべて'],['official','正式採用'],['type','種類別'],['angle','角度別'],['state','状態別'],['set','画像セット別'],['old','旧案'],['rejected','没案']].map(([m,l])=>`<button class="secondary" onclick="openStoryArchiveDetail('${id}','${m}')">${l}</button>`).join('')}</div>${['type','angle','state'].includes(mode)?archiveGroupedGallery(card,mode):archiveImageGallery(card,mode)}</section><button onclick="editStoryArchiveCard('${id}')">編集</button><button class="secondary" onclick="closeModal()">閉じる</button>`)}
function archiveGroupedGallery(card,mode){const key=mode==='type'?'materialType':mode;const labels={type:'種類',angle:'角度',state:'状態'};const map={};(card.images||[]).forEach(i=>{const k=i[key]||'未設定';(map[k]=map[k]||[]).push(i)});return Object.entries(map).map(([k,imgs])=>`<h4>${esc(labels[mode])}：${esc(k)}</h4><div class="archive-gallery">${imgs.map(i=>archiveImageCard(card,i)).join('')}</div>`).join('')||'<p class="meta">画像資料なし</p>'}
async function addArchiveImages(cardId,files){let card=normalizeStoryArchiveCard(getStoryArchiveCard(cardId)||{id:cardId});for(const file of Array.from(files||[])){const preview=await makeArchivePreview(file);card.images.push(normalizeArchiveImage({name:file.name.replace(/\.[^.]+$/,''),cardId,targetCategory:card.category,materialType:'その他',fileName:file.name,storageLocation:'iCloud / 外付けSSD',previewDataUrl:preview,sortOrder:card.images.length+1},card))}saveNormalizedArchiveCard(card);saveState(true);editStoryArchiveCard(cardId);toast('画像資料を追加しました')}
function makeArchivePreview(file){return new Promise(resolve=>{const reader=new FileReader();reader.onload=()=>{const img=new Image();img.onload=()=>{const c=document.createElement('canvas'),max=180,scale=Math.min(1,max/Math.max(img.width,img.height));c.width=Math.max(1,Math.round(img.width*scale));c.height=Math.max(1,Math.round(img.height*scale));c.getContext('2d').drawImage(img,0,0,c.width,c.height);resolve(c.toDataURL('image/jpeg',.62))};img.onerror=()=>resolve('');img.src=reader.result};reader.onerror=()=>resolve('');reader.readAsDataURL(file)})}
function editArchiveImage(cardId,imgId=''){const card=normalizeStoryArchiveCard(getStoryArchiveCard(cardId));const img=normalizeArchiveImage(imgId?card.images.find(i=>i.id===imgId):{cardId,targetCategory:card.category,sortOrder:(card.images||[]).length+1},card);modal(`<h2>画像資料${imgId?'編集':'追加'}</h2><label>画像名<input id="imgName" value="${esc(img.name)}"></label><label>種類<select id="imgType">${archiveImageTypeOptions(card.category)}</select></label><label>角度・視点<select id="imgAngle">${ARCHIVE_ANGLES.map(x=>`<option ${img.angle===x?'selected':''}>${esc(x)}</option>`).join('')}</select></label><label>自由入力角度<input id="imgDirection" value="${esc(img.direction)}"></label><label>状態<select id="imgState">${ARCHIVE_STATES.map(x=>`<option ${img.state===x?'selected':''}>${esc(x)}</option>`).join('')}</select></label><label><input type="checkbox" id="imgOfficial" ${img.isOfficial?'checked':''}>正式採用</label><label>保存場所<input id="imgStorage" value="${esc(img.storageLocation)}"></label><label>ファイル名<input id="imgFile" value="${esc(img.fileName)}"></label><label>説明<textarea id="imgDesc">${esc(img.description)}</textarea></label><label>タグ<input id="imgTags" value="${esc((img.tags||[]).join(','))}"></label><label>注意事項<textarea id="imgNotes">${esc(img.notes)}</textarea></label><button class="primary-action" onclick="saveArchiveImage('${cardId}','${imgId}')">保存</button>`);setTimeout(()=>{const t=$('#imgType');if(t)t.value=img.materialType},0)}
function saveArchiveImage(cardId,imgId=''){const card=normalizeStoryArchiveCard(getStoryArchiveCard(cardId));const img=normalizeArchiveImage({...(imgId?card.images.find(i=>i.id===imgId):{}),id:imgId||uid('archiveImage'),cardId,name:$('#imgName').value,materialType:$('#imgType').value,angle:$('#imgAngle').value,viewpoint:$('#imgAngle').value,direction:$('#imgDirection').value,state:$('#imgState').value,isOfficial:$('#imgOfficial').checked,storageLocation:$('#imgStorage').value,fileName:$('#imgFile').value,description:$('#imgDesc').value,tags:parseTags($('#imgTags').value),notes:$('#imgNotes').value,updatedAt:now()},card);const i=card.images.findIndex(x=>x.id===img.id);if(i>=0)card.images[i]=img;else card.images.push(img);saveNormalizedArchiveCard(card);saveState(true);openStoryArchiveDetail(cardId);toast('画像資料を保存しました')}
function openArchiveImageDetail(cardId,imgId){const card=normalizeStoryArchiveCard(getStoryArchiveCard(cardId)),img=card.images.find(i=>i.id===imgId);if(!img)return;modal(`<h2>${esc(img.name)}</h2><div class="archive-preview-large">${archiveThumb(img)}</div><p><b>種類：</b>${esc(img.materialType)} / <b>角度：</b>${esc(img.angle)} / <b>状態：</b>${esc(img.state)}<br><b>保存場所：</b>${esc(img.storageLocation)}<br><b>ファイル名：</b>${esc(img.fileName)}<br><b>タグ：</b>${esc((img.tags||[]).join(', ')||'なし')}<br><b>注意事項：</b>${esc(img.notes||'なし')}</p><p>${esc(img.description)}</p><h3>関連画像</h3>${(img.relatedImageIds||[]).map(id=>archiveImageCard(card,card.images.find(i=>i.id===id)||{id,name:id})).join('')||'<p class="meta">関連画像なし</p>'}<button onclick="editArchiveImage('${cardId}','${imgId}')">編集</button><button class="danger" onclick="deleteArchiveImage('${cardId}','${imgId}')">登録情報を削除</button>`)}
function deleteArchiveImage(cardId,imgId){const card=normalizeStoryArchiveCard(getStoryArchiveCard(cardId));card.images=card.images.filter(i=>i.id!==imgId);card.imageSets=card.imageSets.map(s=>({...s,imageIds:(s.imageIds||[]).filter(id=>id!==imgId),baseImageId:s.baseImageId===imgId?'':s.baseImageId}));saveNormalizedArchiveCard(card);saveState(true);openStoryArchiveDetail(cardId);toast('画像本体ではなく登録情報だけ削除しました')}
function editArchiveImageSet(cardId,setId=''){const card=normalizeStoryArchiveCard(getStoryArchiveCard(cardId));const set=normalizeArchiveImageSet(setId?card.imageSets.find(s=>s.id===setId):{cardId},card);modal(`<h2>画像セット${setId?'編集':'作成'}</h2><label>セット名<input id="setName" value="${esc(set.name)}"></label><label>説明<textarea id="setDesc">${esc(set.description)}</textarea></label><label>含める画像<select id="setImages" multiple>${(card.images||[]).map(i=>`<option value="${i.id}" ${(set.imageIds||[]).includes(i.id)?'selected':''}>${esc(i.name)} / ${esc(i.angle)}</option>`).join('')}</select></label><label>基準画像<select id="setBase"><option value="">未設定</option>${(card.images||[]).map(i=>`<option value="${i.id}" ${set.baseImageId===i.id?'selected':''}>${esc(i.name)}</option>`).join('')}</select></label><label>並び順<input id="setOrder" type="number" value="${esc(set.sortOrder)}"></label><button class="primary-action" onclick="saveArchiveImageSet('${cardId}','${setId}')">保存</button>`)}
function saveArchiveImageSet(cardId,setId=''){const card=normalizeStoryArchiveCard(getStoryArchiveCard(cardId));const set=normalizeArchiveImageSet({...(setId?card.imageSets.find(s=>s.id===setId):{}),id:setId||uid('archiveImageSet'),cardId,name:$('#setName').value,description:$('#setDesc').value,imageIds:selectedIds('setImages'),baseImageId:$('#setBase').value,sortOrder:+$('#setOrder').value||0,updatedAt:now()},card);const i=card.imageSets.findIndex(s=>s.id===set.id);if(i>=0)card.imageSets[i]=set;else card.imageSets.push(set);saveNormalizedArchiveCard(card);saveState(true);openStoryArchiveDetail(cardId,'set');toast('画像セットを保存しました')}
function deleteArchiveImageSet(cardId,setId){const card=normalizeStoryArchiveCard(getStoryArchiveCard(cardId));card.imageSets=card.imageSets.filter(s=>s.id!==setId);saveNormalizedArchiveCard(card);saveState(true);openStoryArchiveDetail(cardId,'set')}
storyArchiveSearchText=function(card){const relatedNames=archiveRelatedIds(card).map(id=>getStoryArchiveCard(id)?.title||id).join(' ');return [card.title,card.category,card.body,(card.tags||[]).join(' '),relatedNames,(card.relatedWorks||[]).join(' '),(card.relatedEpisodes||[]).join(' '),storyArchiveProjectName(card.projectId),storyArchiveEpisodeName(card.episodeId),card.status].join(' ').toLowerCase()};
storyArchiveView=function(){const p=currentProject(),e=currentEpisode(),groups=storyArchiveCardsByCategory(),total=groups.reduce((n,g)=>n+g.cards.length,0);return `<section class="hero"><p class="eyebrow">Story Archive</p><h1>Story Archive</h1><p>設定カード同士の関連付けと、複数画像資料・画像セットを管理します。画像本体の大量保存やVidu連携は行いません。</p><p class="meta">現在：${esc(p?.title||'未選択')} / ${esc(e?.numberLabel||'未選択')} / ${total}件</p><button class="primary-action" onclick="editStoryArchiveCard()">＋カード作成</button></section><section><h2>検索</h2><input id="storyArchiveSearch" placeholder="タイトル・本文・タグ・関連カード名を検索" oninput="render()" value="${esc($('#storyArchiveSearch')?.value||'')}"></section><section><h2>カテゴリ</h2><div class="archive-category-grid">${groups.map(g=>`<article class="archive-category"><h3>${esc(g.category)} <span class="meta">${g.cards.length}件</span></h3>${g.cards.map(c=>`<div class="archive-card"><h4><button class="link-button" onclick="openStoryArchiveDetail('${c.id}')">${esc(c.title)}</button></h4><p>${esc(c.body).slice(0,160)}</p><p class="meta">ID：${esc(c.id)} / 作品：${esc(storyArchiveProjectName(c.projectId))} / 話数：${esc(storyArchiveEpisodeName(c.episodeId))}<br>タグ：${esc((c.tags||[]).join(', ')||'なし')}<br>関連カード：${archiveRelatedLinks(c)}<br>画像資料：${(c.images||[]).length}件 / 画像セット：${(c.imageSets||[]).length}件<br>作成：${esc(c.createdAt)} / 更新：${esc(c.updatedAt)} / 状態：${esc(c.status)}</p><button onclick="openStoryArchiveDetail('${c.id}')">詳細</button><button onclick="editStoryArchiveCard('${c.id}')">編集</button><button class="danger" onclick="deleteStoryArchiveCard('${c.id}')">削除</button></div>`).join('')||'<p class="empty-note">カードなし</p>'}</article>`).join('')}</div></section>`};
const v027OldSearchAll=searchAll;searchAll=function(q,show=false){const box=show?$('#searchResults'):null;if(!q){if(box)box.innerHTML='';return}const query=String(q).toLowerCase().trim();const archiveHits=storyArchiveCards().filter(c=>storyArchiveSearchText(c).includes(query)).map(c=>({collection:'storyArchiveCards',item:c,type:'storyArchiveCard',title:c.title}));if(show&&archiveHits.length){const html=archiveHits.map(({item,title,type})=>`<div class="row search-hit"><span><b>${esc(title)}</b><br><small>${esc(typeLabel(type))} / ${esc(item.category)} / 更新:${esc(item.updatedAt)}</small></span><button onclick="openStoryArchiveDetail('${item.id}')">直接開く</button></div>`).join('');box.innerHTML=html;return}return v027OldSearchAll(q,show)};

