const ARCHIVE_IMAGE_TYPES_V028=['正式資料','正式立ち絵','三面図','表情','衣装','ポーズ','髪型','部分資料','背景','場所','小物','アイテム','ロゴ','配色資料','材質資料','間取り','配置図','分解図','サイズ比較','細部アップ','Vidu用基準画像','旧案','旧デザイン','没案','制作途中','その他'];
