const ARCHIVE_STATES_V028=['通常','開いている','閉じている','壊れている','使用中','収納中','装着中','変形前','変形後','点灯','消灯','昼','夜','朝','夕方','雨','雪','その他'];
archiveImageTypeOptions=function(category){return ARCHIVE_IMAGE_TYPES_V028.map(x=>`<option value="${esc(x)}">${esc(x)}</option>`).join('')};
const v028OldNormalizeArchiveImage=normalizeArchiveImage;
normalizeArchiveImage=function(img={},card={}){const x=v028OldNormalizeArchiveImage(img,card);return{...x,imageFile:img.imageFile||'',targetCardId:img.targetCardId||x.cardId,targetCategory:img.targetCategory||card.category||x.targetCategory,kind:img.kind||x.materialType,perspective:img.perspective||x.viewpoint,caution:img.caution||x.notes,isOfficial:Boolean(img.isOfficial),isViduReference:Boolean(img.isViduReference),sourceKind:img.sourceKind||'元画像',displayRange:img.displayRange||'',version:img.version||'1',imageSetId:img.imageSetId||'',viduOrder:Number(img.viduOrder||0),promptMemo:img.promptMemo||'',referenceRole:img.referenceRole||'',sourceApp:img.sourceApp||'Story Archive',sourceCardId:img.sourceCardId||card.id||'',memo:img.memo||img.notes||'',updatedAt:img.updatedAt||x.updatedAt}};
const v028OldNormalizeArchiveImageSet=normalizeArchiveImageSet;
normalizeArchiveImageSet=function(set={},card={}){const s=v028OldNormalizeArchiveImageSet(set,card);return{...s,isOfficial:Boolean(set.isOfficial),updatedAt:set.updatedAt||s.updatedAt}};
function archiveCardThumb(card){card=normalizeStoryArchiveCard(card);const imgs=[...(card.images||[])].sort((a,b)=>(+a.sortOrder||0)-(+b.sortOrder||0));const bases=(card.imageSets||[]).map(s=>imgs.find(i=>i.id===s.baseImageId)).filter(Boolean);return imgs.find(i=>i.isOfficial)||imgs.find(i=>i.isViduReference)||bases[0]||imgs[0]||null}
const v028OldCardHtml=cardHtml;
cardHtml=function(collection,item){const img=archiveCardThumb({id:item.id,category:typeLabel(item.type||COLLECTION_TYPE_MAP[collection]),images:item.images||[],imageSets:item.imageSets||[]});if(!img)return v028OldCardHtml(collection,item);const type=item.type||COLLECTION_TYPE_MAP[collection],title=continueTitle(collection,item)||'無題';return `<article class="unified-card ${item.isArchived?'archived':''}" role="button" tabindex="0" onclick="openCardDetail('${collection}','${item.id}')" onkeydown="if(event.key==='Enter'||event.key===' ')openCardDetail('${collection}','${item.id}')"><div class="card-list-thumb">${archiveThumb(img)}</div><div class="card-top"><span class="type-pill">${esc(typeLabel(type))}</span><button class="favorite mini ${isFav(type,item.id)?'active':''}" onclick="event.stopPropagation();toggleFavorite('${type}','${item.id}','${item.projectId||item.id||''}','${collection==='episodes'?item.id:(item.episodeId||'')}')" aria-label="お気に入り切替">${isFav(type,item.id)?'★':'☆'}</button></div><h3>${esc(title)}</h3><p class="card-status">状態：${esc(cardStatus(item))}</p><div class="tags">${itemTagsHtml(item)}</div><p class="meta">更新：${esc(item.updatedAt||'未記録')}</p></article>`};
function archiveImageBadges(img){return `${img.isOfficial?'<span class="tag">正式採用</span>':''}${img.isViduReference?'<span class="tag">Vidu参照</span>':''}`||'<span class="meta">未指定</span>'}
archiveImageCard=function(card,img){return `<article class="archive-image-card" onclick="openArchiveImageDetail('${card.id}','${img.id}')">${archiveThumb(img)}<b>${esc(img.name)}</b><small>${esc(img.materialType)} / ${esc(img.angle||'角度未設定')}</small><small>${archiveImageBadges(img)}</small><small>${esc(img.fileName||'')}</small></article>`};
archiveFormImages=function(card){return `<section class="archive-image-editor"><h3>画像資料</h3><p class="meta">画像本体は保存しません。最大長辺180px程度の低容量JPEGサムネイル、管理情報、ファイル名、保存場所だけlocalStorageへ保存します。</p><div class="archive-image-actions"><label class="file">画像追加・複数追加<input type="file" accept="image/*" multiple onchange="addArchiveImages('${card.id}',this.files)"></label><button class="secondary" onclick="editArchiveImage('${card.id}')">画像資料を手入力</button><button class="secondary" onclick="editArchiveImageSet('${card.id}')">画像セット作成</button></div>${archiveImageGallery(card,'all')}<h4>画像セット</h4>${archiveImageGallery(card,'set')}</section>`};
editStoryArchiveCard=function(id=''){const card=normalizeStoryArchiveCard(id?getStoryArchiveCard(id):newStoryArchiveCard());modal(`<h2>${id?'Story Archiveカード編集':'Story Archiveカード作成'}</h2><label>ID<input id="archiveId" value="${esc(card.id)}" ${id?'readonly':''}></label><label>タイトル<input id="archiveTitle" value="${esc(card.title)}"></label><label>本文<textarea id="archiveBody" rows="8">${esc(card.body)}</textarea></label><label>カテゴリ<select id="archiveCategory">${STORY_ARCHIVE_CATEGORIES.map(c=>`<option value="${esc(c)}" ${card.category===c?'selected':''}>${esc(c)}</option>`).join('')}</select></label><label>タグ（カンマ区切り）<input id="archiveTags" value="${esc(tagInputValue(card))}"></label><label>作品<select id="archiveProject">${state.projects.map(p=>`<option value="${esc(p.id)}" ${card.projectId===p.id?'selected':''}>${esc(p.title)}</option>`).join('')}</select></label><label>話数<select id="archiveEpisode">${state.episodes.map(e=>`<option value="${esc(e.id)}" ${card.episodeId===e.id?'selected':''}>${esc(storyArchiveProjectName(e.projectId))} / ${esc(e.numberLabel)}</option>`).join('')}</select></label><label>関連作品<input id="archiveRelatedWorks" value="${esc((card.relatedWorks||[]).join(','))}"></label><label>関連話数<input id="archiveRelatedEpisodes" value="${esc((card.relatedEpisodes||[]).join(','))}"></label>${archiveRelatedPicker(card)}<label>状態<select id="archiveStatus">${STORY_ARCHIVE_STATUSES.map(s=>`<option value="${esc(s)}" ${card.status===s?'selected':''}>${esc(s)}</option>`).join('')}</select></label>${archiveFormImages(card)}<p class="meta">作成日時：${esc(card.createdAt)} / 更新日時：${esc(card.updatedAt)}</p><button class="primary-action" onclick="saveStoryArchiveCard('${esc(id)}')">保存</button><button class="secondary" onclick="closeModal()">キャンセル</button>`)};
function archiveOptionList(items,val){return items.map(x=>`<option value="${esc(x)}" ${val===x?'selected':''}>${esc(x)}</option>`).join('')}
editArchiveImage=function(cardId,imgId=''){const card=normalizeStoryArchiveCard(getStoryArchiveCard(cardId));const img=normalizeArchiveImage(imgId?card.images.find(i=>i.id===imgId):{cardId,targetCategory:card.category,sortOrder:(card.images||[]).length+1},card);modal(`<h2>画像資料${imgId?'編集':'追加'}</h2><label>画像資料ID<input id="imgId" value="${esc(img.id)}" readonly></label><label>画像名<input id="imgName" value="${esc(img.name)}"></label><label>種類<select id="imgType">${archiveOptionList(ARCHIVE_IMAGE_TYPES_V028,img.materialType)}</select></label><label>角度<select id="imgAngle">${archiveOptionList(ARCHIVE_ANGLES_V028,img.angle)}</select></label><label>視点<input id="imgViewpoint" value="${esc(img.viewpoint)}"></label><label>方向<input id="imgDirection" value="${esc(img.direction)}"></label><label>状態<select id="imgState">${archiveOptionList(ARCHIVE_STATES_V028,img.state)}</select></label><label>時間帯<input id="imgTime" value="${esc(img.timeOfDay)}"></label><label>天候<input id="imgWeather" value="${esc(img.weather)}"></label><label>季節<input id="imgSeason" value="${esc(img.season)}"></label><label>タグ<input id="imgTags" value="${esc((img.tags||[]).join(','))}"></label><label>メモ<textarea id="imgMemo">${esc(img.memo||'')}</textarea></label><label>説明<textarea id="imgDesc">${esc(img.description)}</textarea></label><label>注意事項<textarea id="imgNotes">${esc(img.notes)}</textarea></label><label><input type="checkbox" id="imgOfficial" ${img.isOfficial?'checked':''}>正式採用</label><label><input type="checkbox" id="imgVidu" ${img.isViduReference?'checked':''}>Vidu参照</label><label>元画像か加工後か<select id="imgSourceKind"><option ${img.sourceKind==='元画像'?'selected':''}>元画像</option><option ${img.sourceKind==='加工後'?'selected':''}>加工後</option></select></label><label>表示範囲<input id="imgDisplayRange" value="${esc(img.displayRange)}"></label><label>保存場所<input id="imgStorage" value="${esc(img.storageLocation)}"></label><label>ファイル名<input id="imgFile" value="${esc(img.fileName)}"></label><label>バージョン<input id="imgVersion" value="${esc(img.version)}"></label><label>関連画像資料ID<input id="imgRelated" value="${esc((img.relatedImageIds||[]).join(','))}"></label><label>所属画像セット<select id="imgSet"><option value="">未所属</option>${(card.imageSets||[]).map(s=>`<option value="${s.id}" ${img.imageSetId===s.id?'selected':''}>${esc(s.name)}</option>`).join('')}</select></label><fieldset><legend>将来連携用</legend><label>Vidu順<input id="imgViduOrder" type="number" value="${esc(img.viduOrder)}"></label><label>Promptメモ<textarea id="imgPromptMemo">${esc(img.promptMemo)}</textarea></label><label>参照ロール<input id="imgReferenceRole" value="${esc(img.referenceRole)}"></label><label>Source App<input id="imgSourceApp" value="${esc(img.sourceApp)}"></label><label>Source Card ID<input id="imgSourceCard" value="${esc(img.sourceCardId)}"></label></fieldset><p class="meta">対象カードID：${esc(card.id)} / 対象カテゴリ：${esc(card.category)} / 作成：${esc(img.createdAt)} / 更新：${esc(img.updatedAt)}</p><button class="primary-action" onclick="saveArchiveImage('${cardId}','${imgId}')">保存</button><button class="secondary" onclick="openStoryArchiveDetail('${cardId}')">戻る</button>`)};
saveArchiveImage=function(cardId,imgId=''){const card=normalizeStoryArchiveCard(getStoryArchiveCard(cardId));const old=imgId?card.images.find(i=>i.id===imgId):{};const img=normalizeArchiveImage({...old,id:imgId||uid('archiveImage'),cardId,targetCardId:cardId,targetCategory:card.category,name:$('#imgName').value,materialType:$('#imgType').value,angle:$('#imgAngle').value,viewpoint:$('#imgViewpoint').value,direction:$('#imgDirection').value,state:$('#imgState').value,timeOfDay:$('#imgTime').value,weather:$('#imgWeather').value,season:$('#imgSeason').value,isOfficial:$('#imgOfficial').checked,isViduReference:$('#imgVidu').checked,sourceKind:$('#imgSourceKind').value,displayRange:$('#imgDisplayRange').value,storageLocation:$('#imgStorage').value,fileName:$('#imgFile').value,version:$('#imgVersion').value,description:$('#imgDesc').value,memo:$('#imgMemo').value,tags:parseTags($('#imgTags').value),notes:$('#imgNotes').value,caution:$('#imgNotes').value,relatedImageIds:parseTags($('#imgRelated').value),imageSetId:$('#imgSet').value,viduOrder:+$('#imgViduOrder').value||0,promptMemo:$('#imgPromptMemo').value,referenceRole:$('#imgReferenceRole').value,sourceApp:$('#imgSourceApp').value,sourceCardId:$('#imgSourceCard').value,updatedAt:now()},card);const i=card.images.findIndex(x=>x.id===img.id);if(i>=0)card.images[i]=img;else card.images.push(img);card.imageSets=(card.imageSets||[]).map(s=>({...s,imageIds:img.imageSetId===s.id?[...new Set([...(s.imageIds||[]),img.id])]:(s.imageIds||[]).filter(id=>id!==img.id)}));saveNormalizedArchiveCard(card);saveState(true);openStoryArchiveDetail(cardId);toast('画像資料を保存しました')};
function moveArchiveImage(cardId,imgId,dir){const card=normalizeStoryArchiveCard(getStoryArchiveCard(cardId));const imgs=card.images.sort((a,b)=>(+a.sortOrder||0)-(+b.sortOrder||0));const i=imgs.findIndex(x=>x.id===imgId),j=i+dir;if(i<0||j<0||j>=imgs.length)return;[imgs[i],imgs[j]]=[imgs[j],imgs[i]];imgs.forEach((x,n)=>x.sortOrder=n+1);card.images=imgs;saveNormalizedArchiveCard(card);saveState(true);openStoryArchiveDetail(cardId)}
function moveImageInSet(cardId,setId,imgId,dir){const card=normalizeStoryArchiveCard(getStoryArchiveCard(cardId));const set=card.imageSets.find(s=>s.id===setId);if(!set)return;const a=[...(set.imageIds||[])],i=a.indexOf(imgId),j=i+dir;if(i<0||j<0||j>=a.length)return;[a[i],a[j]]=[a[j],a[i]];set.imageIds=a;set.updatedAt=now();saveNormalizedArchiveCard(card);saveState(true);openStoryArchiveDetail(cardId,'set')}
archiveImageGallery=function(card,mode='all'){card=normalizeStoryArchiveCard(card);let imgs=[...(card.images||[])].sort((a,b)=>(+a.sortOrder||0)-(+b.sortOrder||0));if(mode==='official')imgs=imgs.filter(i=>i.isOfficial);if(mode==='vidu')imgs=imgs.filter(i=>i.isViduReference);if(mode==='old')imgs=imgs.filter(i=>['旧案','旧デザイン'].includes(i.materialType));if(mode==='rejected')imgs=imgs.filter(i=>i.materialType==='没案');if(mode==='set')return (card.imageSets||[]).sort((a,b)=>(+a.sortOrder||0)-(+b.sortOrder||0)).map(s=>`<article class="archive-image-set"><h4>${esc(s.name)} ${s.isOfficial?'<span class="tag">正式採用</span>':''}</h4><p>${esc(s.description||'')}</p><p class="meta">基準画像：${esc(card.images.find(i=>i.id===s.baseImageId)?.name||'未設定')}</p><div class="archive-gallery">${(s.imageIds||[]).map(id=>card.images.find(i=>i.id===id)).filter(Boolean).map(i=>archiveImageCard(card,i)+`<div class="inline-move"><button onclick="moveImageInSet('${card.id}','${s.id}','${i.id}',-1)">上へ</button><button onclick="moveImageInSet('${card.id}','${s.id}','${i.id}',1)">下へ</button></div>`).join('')||'<p class="meta">画像なし</p>'}</div><button class="secondary" onclick="editArchiveImageSet('${card.id}','${s.id}')">セット編集</button><button class="danger" onclick="deleteArchiveImageSet('${card.id}','${s.id}')">セット削除</button></article>`).join('')||'<p class="meta">画像セットなし</p>';return `<div class="archive-gallery">${imgs.map(i=>archiveImageCard(card,i)+`<div class="inline-move"><button onclick="event.stopPropagation();moveArchiveImage('${card.id}','${i.id}',-1)">上へ</button><button onclick="event.stopPropagation();moveArchiveImage('${card.id}','${i.id}',1)">下へ</button></div>`).join('')||'<p class="meta">画像資料なし</p>'}</div>`};
openStoryArchiveDetail=function(id,mode='all'){const card=normalizeStoryArchiveCard(getStoryArchiveCard(id));if(!card)return;modal(`<h2>${esc(card.title)}</h2><p>${metaLine(card)}<br>カテゴリ：${esc(card.category)} / タグ：${itemTagsHtml(card)}</p><section><h3>本文</h3><p>${esc(card.body)}</p></section><section><h3>関連カード</h3>${archiveRelatedLinks(card)}</section><section><h3>画像資料</h3><div class="gallery-tabs">${[['all','すべて'],['official','正式採用'],['vidu','Vidu参照'],['type','種類別'],['angle','角度別'],['state','状態別'],['set','画像セット別'],['old','旧案'],['rejected','没案']].map(([m,l])=>`<button class="secondary" onclick="openStoryArchiveDetail('${id}','${m}')">${l}</button>`).join('')}</div>${['type','angle','state'].includes(mode)?archiveGroupedGallery(card,mode):archiveImageGallery(card,mode)}</section><button onclick="editStoryArchiveCard('${id}')">編集</button><button class="secondary" onclick="closeModal()">閉じる</button>`)};
openArchiveImageDetail=function(cardId,imgId){const card=normalizeStoryArchiveCard(getStoryArchiveCard(cardId)),img=card.images.find(i=>i.id===imgId);if(!img)return;modal(`<h2>${esc(img.name)}</h2><div class="archive-preview-large">${archiveThumb(img)}</div><p><b>種類：</b>${esc(img.materialType)} / <b>角度：</b>${esc(img.angle)} / <b>視点：</b>${esc(img.viewpoint)} / <b>状態：</b>${esc(img.state)}<br><b>タグ：</b>${esc((img.tags||[]).join(', ')||'なし')}<br><b>メモ：</b>${esc(img.memo||'なし')}<br><b>説明：</b>${esc(img.description||'なし')}<br><b>注意事項：</b>${esc(img.notes||'なし')}<br><b>正式採用：</b>${img.isOfficial?'ON':'OFF'} / <b>Vidu参照：</b>${img.isViduReference?'ON':'OFF'}<br><b>保存場所：</b>${esc(img.storageLocation)}<br><b>ファイル名：</b>${esc(img.fileName)}<br><b>所属画像セット：</b>${esc((card.imageSets||[]).filter(s=>(s.imageIds||[]).includes(img.id)||s.id===img.imageSetId).map(s=>s.name).join(', ')||'なし')}</p><h3>関連画像</h3><div class="archive-gallery">${(img.relatedImageIds||[]).map(id=>card.images.find(i=>i.id===id)).filter(Boolean).map(i=>archiveImageCard(card,i)).join('')||'<p class="meta">関連画像なし</p>'}</div><button onclick="editArchiveImage('${cardId}','${imgId}')">編集</button><button class="danger" onclick="deleteArchiveImage('${cardId}','${imgId}')">削除</button>`)};
editArchiveImageSet=function(cardId,setId=''){const card=normalizeStoryArchiveCard(getStoryArchiveCard(cardId));const set=normalizeArchiveImageSet(setId?card.imageSets.find(s=>s.id===setId):{cardId,sortOrder:(card.imageSets||[]).length+1},card);modal(`<h2>画像セット${setId?'編集':'作成'}</h2><label>セットID<input value="${esc(set.id)}" readonly></label><label>セット名<input id="setName" value="${esc(set.name)}"></label><label>説明<textarea id="setDesc">${esc(set.description)}</textarea></label><label>含まれる画像資料ID<select id="setImages" multiple>${(card.images||[]).map(i=>`<option value="${i.id}" ${(set.imageIds||[]).includes(i.id)?'selected':''}>${esc(i.name)} / ${esc(i.angle)}</option>`).join('')}</select></label><label>基準画像<select id="setBase"><option value="">未設定</option>${(card.images||[]).map(i=>`<option value="${i.id}" ${set.baseImageId===i.id?'selected':''}>${esc(i.name)}</option>`).join('')}</select></label><label><input type="checkbox" id="setOfficial" ${set.isOfficial?'checked':''}>正式採用</label><label>並び順<input id="setOrder" type="number" value="${esc(set.sortOrder)}"></label><p class="meta">対象カードID：${esc(card.id)} / 作成：${esc(set.createdAt)} / 更新：${esc(set.updatedAt)}</p><button class="primary-action" onclick="saveArchiveImageSet('${cardId}','${setId}')">保存</button>`)};
saveArchiveImageSet=function(cardId,setId=''){const card=normalizeStoryArchiveCard(getStoryArchiveCard(cardId));const set=normalizeArchiveImageSet({...(setId?card.imageSets.find(s=>s.id===setId):{}),id:setId||uid('archiveImageSet'),cardId,name:$('#setName').value,description:$('#setDesc').value,imageIds:selectedIds('setImages'),baseImageId:$('#setBase').value,isOfficial:$('#setOfficial').checked,sortOrder:+$('#setOrder').value||0,updatedAt:now()},card);const i=card.imageSets.findIndex(s=>s.id===set.id);if(i>=0)card.imageSets[i]=set;else card.imageSets.push(set);card.images=(card.images||[]).map(img=>({...img,imageSetId:set.imageIds.includes(img.id)?set.id:(img.imageSetId===set.id?'':img.imageSetId)}));saveNormalizedArchiveCard(card);saveState(true);openStoryArchiveDetail(cardId,'set');toast('画像セットを保存しました')};
storyArchiveView=function(){const p=currentProject(),e=currentEpisode(),groups=storyArchiveCardsByCategory(),total=groups.reduce((n,g)=>n+g.cards.length,0);return `<section class="hero"><p class="eyebrow">Story Archive</p><h1>Story Archive</h1><p>すべてのカードカテゴリで複数画像資料・画像セット・正式採用・Vidu参照を管理します。Vidu API連携や画像生成は未実装です。</p><p class="meta">現在：${esc(p?.title||'未選択')} / ${esc(e?.numberLabel||'未選択')} / ${total}件</p><button class="primary-action" onclick="editStoryArchiveCard()">＋カード作成</button></section><section><h2>検索</h2><input id="storyArchiveSearch" placeholder="タイトル・本文・タグ・関連カード名を検索" oninput="render()" value="${esc($('#storyArchiveSearch')?.value||'')}"></section><section><h2>カテゴリ</h2><div class="archive-category-grid">${groups.map(g=>`<article class="archive-category"><h3>${esc(g.category)} <span class="meta">${g.cards.length}件</span></h3>${g.cards.map(c=>{const th=archiveCardThumb(c);return `<div class="archive-card">${th?`<div class="card-list-thumb">${archiveThumb(th)}</div>`:''}<h4><button class="link-button" onclick="openStoryArchiveDetail('${c.id}')">${esc(c.title)}</button></h4><p>${esc(c.body).slice(0,160)}</p><p class="meta">ID：${esc(c.id)} / 作品：${esc(storyArchiveProjectName(c.projectId))} / 話数：${esc(storyArchiveEpisodeName(c.episodeId))}<br>タグ：${esc((c.tags||[]).join(', ')||'なし')}<br>関連カード：${archiveRelatedLinks(c)}<br>画像資料：${(c.images||[]).length}件 / 画像セット：${(c.imageSets||[]).length}件<br>作成：${esc(c.createdAt)} / 更新：${esc(c.updatedAt)} / 状態：${esc(c.status)}</p><button onclick="openStoryArchiveDetail('${c.id}')">詳細</button><button onclick="editStoryArchiveCard('${c.id}')">編集</button><button class="danger" onclick="deleteStoryArchiveCard('${c.id}')">削除</button></div>`}).join('')||'<p class="empty-note">カードなし</p>'}</article>`).join('')}</div></section>`};

// Version 0.2.8 completion: Story Archive image add/edit/delete UI, DnD, search/filter, and set workflows.
const ARCHIVE_IMAGE_TYPES_FINAL=['キャラクター','三面図','立ち絵','表情','背景','場所','小物','アイテム','ロゴ','UI','その他'];
const ARCHIVE_ANGLES_FINAL=['正面','左45°','右45°','真横','後ろ','真上','自由'];
const ARCHIVE_IMAGE_STATES_FINAL=['正式採用','仮','旧案','没案'];
function archiveImageMatches(img,q,type,angle,state,setId){const hay=[img.name,img.materialType,img.angle,img.state,img.description,img.memo,img.storageLocation,img.fileName,(img.tags||[]).join(' ')].join(' ').toLowerCase();return (!q||hay.includes(q.toLowerCase()))&&(!type||img.materialType===type)&&(!angle||img.angle===angle)&&(!state||img.state===state)&&(!setId||img.imageSetId===setId)}
function archiveImageToolbar(card,mode='all'){const types=[...new Set((card.images||[]).map(i=>i.materialType).filter(Boolean))],angles=[...new Set((card.images||[]).map(i=>i.angle).filter(Boolean))],states=[...new Set((card.images||[]).map(i=>i.state).filter(Boolean))];return `<div class="archive-image-toolbar"><input id="archiveImageSearch_${card.id}" placeholder="画像名・説明・タグ・保存場所を検索" oninput="filterArchiveImages('${card.id}','${mode}')"><select id="archiveImageType_${card.id}" onchange="filterArchiveImages('${card.id}','${mode}')"><option value="">種類すべて</option>${types.map(x=>`<option value="${esc(x)}">${esc(x)}</option>`).join('')}</select><select id="archiveImageAngle_${card.id}" onchange="filterArchiveImages('${card.id}','${mode}')"><option value="">角度すべて</option>${angles.map(x=>`<option value="${esc(x)}">${esc(x)}</option>`).join('')}</select><select id="archiveImageState_${card.id}" onchange="filterArchiveImages('${card.id}','${mode}')"><option value="">状態すべて</option>${states.map(x=>`<option value="${esc(x)}">${esc(x)}</option>`).join('')}</select><select id="archiveImageSetFilter_${card.id}" onchange="filterArchiveImages('${card.id}','${mode}')"><option value="">画像セットすべて</option>${(card.imageSets||[]).map(s=>`<option value="${esc(s.id)}">${esc(s.name)}</option>`).join('')}</select></div>`}
function archiveVisibleImages(card,mode='all'){let imgs=[...(card.images||[])].sort((a,b)=>(+a.sortOrder||0)-(+b.sortOrder||0));if(mode==='official')imgs=imgs.filter(i=>i.state==='正式採用'||i.isOfficial);if(mode==='vidu')imgs=imgs.filter(i=>i.isViduReference);if(mode==='old')imgs=imgs.filter(i=>i.state==='旧案'||i.materialType==='旧案');if(mode==='rejected')imgs=imgs.filter(i=>i.state==='没案'||i.materialType==='没案');const q=$(`#archiveImageSearch_${card.id}`)?.value||'',type=$(`#archiveImageType_${card.id}`)?.value||'',angle=$(`#archiveImageAngle_${card.id}`)?.value||'',stateVal=$(`#archiveImageState_${card.id}`)?.value||'',setId=$(`#archiveImageSetFilter_${card.id}`)?.value||'';return imgs.filter(i=>archiveImageMatches(i,q,type,angle,stateVal,setId))}
function filterArchiveImages(cardId,mode='all'){const card=normalizeStoryArchiveCard(getStoryArchiveCard(cardId));const el=$(`#archiveImageResults_${cardId}`);if(el)el.innerHTML=archiveImageGallery(card,mode,true)}
function archiveImageDropZone(cardId){return `<div class="archive-drop-zone" ondragover="event.preventDefault();this.classList.add('dragging')" ondragleave="this.classList.remove('dragging')" ondrop="event.preventDefault();this.classList.remove('dragging');addArchiveImages('${cardId}',event.dataTransfer.files)"><b>画像を追加</b><span>PCはここへドラッグ＆ドロップできます。iPad・iPhoneは下の「写真から追加」「ファイルから追加」を使えます。</span><div class="archive-image-actions"><label class="file primary-action">写真から追加<input type="file" accept="image/*" multiple onchange="addArchiveImages('${cardId}',this.files)"></label><label class="file secondary">ファイルから追加<input type="file" multiple onchange="addArchiveImages('${cardId}',this.files)"></label><button class="secondary" onclick="editArchiveImage('${cardId}')">画像を追加</button><button class="secondary" onclick="editArchiveImageSet('${cardId}')">画像セット管理</button></div></div>`}
archiveImageCard=function(card,img){return `<article class="archive-image-card" onclick="openArchiveImageDetail('${card.id}','${img.id}')">${archiveThumb(img)}<b>${esc(img.name)}</b><small>${esc(img.materialType)} / ${esc(img.angle||'角度未設定')} / ${esc(img.state||'状態未設定')}</small><small>${archiveImageBadges(img)}</small><small>${esc(img.fileName||'')}</small><div class="archive-card-actions"><button onclick="event.stopPropagation();editArchiveImage('${card.id}','${img.id}')">編集</button><button class="danger" onclick="event.stopPropagation();deleteArchiveImage('${card.id}','${img.id}')">削除</button></div></article>`};
archiveImageGallery=function(card,mode='all',filtered=false){card=normalizeStoryArchiveCard(card);if(mode==='set')return (card.imageSets||[]).sort((a,b)=>(+a.sortOrder||0)-(+b.sortOrder||0)).map(s=>`<article class="archive-image-set"><h4>${esc(s.name)} ${s.isOfficial?'<span class="tag">正式採用</span>':''}</h4><p>${esc(s.description||'')}</p><p class="meta">基準画像：${esc(card.images.find(i=>i.id===s.baseImageId)?.name||'未設定')}</p><div class="archive-gallery">${(s.imageIds||[]).map(id=>card.images.find(i=>i.id===id)).filter(Boolean).map(i=>archiveImageCard(card,i)+`<div class="inline-move"><button onclick="moveImageInSet('${card.id}','${s.id}','${i.id}',-1)">上へ</button><button onclick="moveImageInSet('${card.id}','${s.id}','${i.id}',1)">下へ</button></div>`).join('')||'<p class="meta">画像なし</p>'}</div><button class="secondary" onclick="editArchiveImageSet('${card.id}','${s.id}')">セット編集</button><button class="danger" onclick="deleteArchiveImageSet('${card.id}','${s.id}')">セット削除</button></article>`).join('')||'<p class="meta">画像セットなし</p>';const imgs=filtered?archiveVisibleImages(card,mode):archiveVisibleImages(card,mode);return `<div class="archive-gallery">${imgs.map(i=>archiveImageCard(card,i)+`<div class="inline-move"><button onclick="event.stopPropagation();moveArchiveImage('${card.id}','${i.id}',-1)">上へ</button><button onclick="event.stopPropagation();moveArchiveImage('${card.id}','${i.id}',1)">下へ</button></div>`).join('')||'<p class="meta">画像資料なし</p>'}</div>`};
openStoryArchiveDetail=function(id,mode='all'){const card=normalizeStoryArchiveCard(getStoryArchiveCard(id));if(!card)return;modal(`<h2>${esc(card.title)}</h2><p>${metaLine(card)}<br>カテゴリ：${esc(card.category)} / タグ：${itemTagsHtml(card)}</p><section><h3>本文</h3><p>${esc(card.body)}</p></section><section><h3>関連カード</h3>${archiveRelatedLinks(card)}</section><section><h3>画像ギャラリー</h3><div class="gallery-tabs">${[['all','すべて'],['official','正式採用'],['vidu','Vidu参照'],['type','種類別'],['angle','角度別'],['state','状態別'],['set','画像セット別'],['old','旧案'],['rejected','没案']].map(([m,l])=>`<button class="secondary" onclick="openStoryArchiveDetail('${id}','${m}')">${l}</button>`).join('')}</div>${mode==='set'?'':archiveImageToolbar(card,mode)}<div id="archiveImageResults_${card.id}">${['type','angle','state'].includes(mode)?archiveGroupedGallery(card,mode):archiveImageGallery(card,mode)}</div>${archiveImageDropZone(card.id)}</section><button onclick="editStoryArchiveCard('${id}')">編集</button><button class="secondary" onclick="closeModal()">閉じる</button>`)};
editArchiveImage=function(cardId,imgId=''){const card=normalizeStoryArchiveCard(getStoryArchiveCard(cardId));const img=normalizeArchiveImage(imgId?card.images.find(i=>i.id===imgId):{cardId,targetCategory:card.category,sortOrder:(card.images||[]).length+1,state:'仮'},card);modal(`<h2>画像資料${imgId?'編集':'追加'}</h2><div class="archive-preview-large" id="imgPreviewBox">${archiveThumb(img)}</div><label>プレビュー画像を選択<input id="imgPreviewFile" type="file" accept="image/*" onchange="previewArchiveImageFile(this.files[0])"></label><label>画像名<input id="imgName" value="${esc(img.name)}"></label><label>種類<select id="imgType">${archiveOptionList(ARCHIVE_IMAGE_TYPES_FINAL,img.materialType)}</select></label><label>角度<select id="imgAngle">${archiveOptionList(ARCHIVE_ANGLES_FINAL,img.angle)}</select></label><label>状態<select id="imgState">${archiveOptionList(ARCHIVE_IMAGE_STATES_FINAL,img.state)}</select></label><label>画像セット<select id="imgSet"><option value="">未所属</option>${(card.imageSets||[]).map(s=>`<option value="${s.id}" ${img.imageSetId===s.id?'selected':''}>${esc(s.name)}</option>`).join('')}</select></label><label>画像セットを新規作成・自由入力<input id="imgSetNew" placeholder="例：ティア / OP衣装 / Vidu基準画像"></label><label>説明<textarea id="imgDesc">${esc(img.description)}</textarea></label><label>タグ<input id="imgTags" value="${esc((img.tags||[]).join(','))}" placeholder="カンマ区切り"></label><label>保存場所<input id="imgStorage" value="${esc(img.storageLocation)}" placeholder="iCloud / 外付けSSD / NAS / URLなど"></label><label>ファイル名<input id="imgFile" value="${esc(img.fileName)}"></label><fieldset><legend>将来連携用</legend><label><input type="checkbox" id="imgVidu" ${img.isViduReference?'checked':''}>Vidu参照</label><label>Promptメモ<textarea id="imgPromptMemo">${esc(img.promptMemo||'')}</textarea></label><label>参照ロール<input id="imgReferenceRole" value="${esc(img.referenceRole||'')}"></label><label>Source App<input id="imgSourceApp" value="${esc(img.sourceApp||'Story Archive')}"></label><label>Source Card ID<input id="imgSourceCard" value="${esc(img.sourceCardId||card.id)}"></label></fieldset><p class="meta">画像本体は保存せず、低容量プレビュー・ファイル名・保存場所・各種情報のみ保存します。</p><button class="primary-action" onclick="saveArchiveImage('${cardId}','${imgId}')">保存</button><button class="secondary" onclick="openStoryArchiveDetail('${cardId}')">戻る</button>`);window.pendingArchivePreviewDataUrl=img.previewDataUrl||''};
async function previewArchiveImageFile(file){if(!file)return;window.pendingArchivePreviewDataUrl=await makeArchivePreview(file);const box=$('#imgPreviewBox');if(box)box.innerHTML=window.pendingArchivePreviewDataUrl?`<img src="${window.pendingArchivePreviewDataUrl}" alt="">`:'<div class="archive-thumb-empty">No preview</div>';if($('#imgFile')&&!$('#imgFile').value)$('#imgFile').value=file.name;if($('#imgName')&&(!$('#imgName').value||$('#imgName').value==='画像資料'))$('#imgName').value=file.name.replace(/\.[^.]+$/,'')}
saveArchiveImage=function(cardId,imgId=''){const card=normalizeStoryArchiveCard(getStoryArchiveCard(cardId));let imageSetId=$('#imgSet').value;const newSetName=($('#imgSetNew')?.value||'').trim();if(newSetName){const set=normalizeArchiveImageSet({id:uid('archiveImageSet'),cardId,name:newSetName,sortOrder:(card.imageSets||[]).length+1},card);card.imageSets.push(set);imageSetId=set.id}const old=imgId?card.images.find(i=>i.id===imgId):{};const stateVal=$('#imgState').value;const img=normalizeArchiveImage({...old,id:imgId||uid('archiveImage'),cardId,targetCardId:cardId,targetCategory:card.category,name:$('#imgName').value,materialType:$('#imgType').value,angle:$('#imgAngle').value,state:stateVal,isOfficial:stateVal==='正式採用',isViduReference:$('#imgVidu').checked,storageLocation:$('#imgStorage').value,fileName:$('#imgFile').value,description:$('#imgDesc').value,tags:parseTags($('#imgTags').value),imageSetId,previewDataUrl:window.pendingArchivePreviewDataUrl||old?.previewDataUrl||'',promptMemo:$('#imgPromptMemo').value,referenceRole:$('#imgReferenceRole').value,sourceApp:$('#imgSourceApp').value,sourceCardId:$('#imgSourceCard').value,updatedAt:now()},card);const i=card.images.findIndex(x=>x.id===img.id);if(i>=0)card.images[i]=img;else card.images.push(img);card.imageSets=(card.imageSets||[]).map(s=>({...s,imageIds:img.imageSetId===s.id?[...new Set([...(s.imageIds||[]),img.id])]:(s.imageIds||[]).filter(id=>id!==img.id)}));saveNormalizedArchiveCard(card);saveState(true);openStoryArchiveDetail(cardId);toast('画像資料を保存しました')};

// Version 0.2.9 production-ready Story Archive image material manager.
const ARCHIVE_IMAGE_TYPES_PRODUCTION=['キャラクター','背景','小物','アイテム','エフェクト','ロゴ','UI','その他'];
const ARCHIVE_ANGLES_PRODUCTION=['正面','左斜め','右斜め','左側面','右側面','背面','上','下','自由入力'];
const ARCHIVE_STATES_PRODUCTION=['通常','笑顔','泣き','怒り','戦闘','私服','制服','変身','自由入力'];
const v029NormalizeArchiveImage=normalizeArchiveImage;
normalizeArchiveImage=function(img={},card={}){const out=v029NormalizeArchiveImage(img,card);out.isOfficial=Boolean(img.isOfficial);out.isViduReference=Boolean(img.isViduReference);out.promptMemo=img.promptMemo||'';out.referenceRole=img.referenceRole||'';out.sourceApp=img.sourceApp||'Story Archive';out.sourceCardId=img.sourceCardId||card.id||img.cardId||'';out.imageSetId=img.imageSetId||'';return out}
function archiveImageFieldValue(selectId,freeId){const sel=$(`#${selectId}`)?.value||'',free=($(`#${freeId}`)?.value||'').trim();return sel==='自由入力'&&free?free:sel}
function archiveProductionOptionList(list,value){const known=list.includes(value),selected=known?value:(value?'自由入力':'');return list.map(x=>`<option value="${esc(x)}" ${selected===x?'selected':''}>${esc(x)}</option>`).join('')}
function archiveViduReferenceImages(){return storyArchiveCards().map(c=>normalizeStoryArchiveCard(c)).flatMap(card=>(card.images||[]).filter(img=>img.isViduReference).map(img=>({card,img})))}
function openArchiveViduReferences(){const refs=archiveViduReferenceImages();modal(`<h2>Vidu参照画像</h2><p class="meta">将来Viduへ送る画像選択画面として使える、Vidu参照ONの画像だけの一覧です。カード詳細へ戻らずワンタップで確認できます。</p><div class="archive-gallery vidu-selection-gallery">${refs.map(({card,img})=>archiveImageCard(card,img)).join('')||'<p class="meta">Vidu参照画像はまだありません。</p>'}</div><button class="secondary" onclick="closeModal()">閉じる</button>`)}
archiveImageCard=function(card,img){return `<article class="archive-image-card" onclick="openArchiveImageDetail('${card.id}','${img.id}')">${archiveThumb(img)}<b>${esc(img.name)}</b><small>${esc(img.materialType||'種類未設定')} / ${esc(img.angle||'角度未設定')} / ${esc(img.state||'状態未設定')}</small><small>${archiveImageBadges(img)}</small><div class="archive-card-actions"><button onclick="event.stopPropagation();editArchiveImage('${card.id}','${img.id}')">編集</button><button class="danger" onclick="event.stopPropagation();deleteArchiveImage('${card.id}','${img.id}')">削除</button></div></article>`};
const v029StoryArchiveView=storyArchiveView;
storyArchiveView=function(){const html=v029StoryArchiveView();const count=archiveViduReferenceImages().length;return html.replace('<button class="primary-action" onclick="editStoryArchiveCard()">＋カード作成</button>',`<div class="archive-hero-actions"><button class="primary-action" onclick="editStoryArchiveCard()">＋カード作成</button><button class="secondary vidu-one-tap" onclick="openArchiveViduReferences()">Vidu参照画像だけ表示（${count}）</button></div>`)};
openStoryArchiveDetail=function(id,mode='all'){const card=normalizeStoryArchiveCard(getStoryArchiveCard(id));if(!card)return;modal(`<h2>${esc(card.title)}</h2><p>${metaLine(card)}<br>カテゴリ：${esc(card.category)} / タグ：${itemTagsHtml(card)}</p><section><h3>本文</h3><p>${esc(card.body)}</p></section><section><h3>関連カード</h3>${archiveRelatedLinks(card)}</section><section><h3>画像資料</h3><div class="gallery-tabs">${[['all','すべて'],['vidu','Vidu参照'],['official','正式採用'],['type','種類別'],['angle','角度別'],['state','状態別'],['set','画像セット別']].map(([m,l])=>`<button class="secondary" onclick="openStoryArchiveDetail('${id}','${m}')">${l}</button>`).join('')}<button class="vidu-one-tap" onclick="openArchiveViduReferences()">全カードのVidu参照</button></div>${mode==='set'?'':archiveImageToolbar(card,mode)}<div id="archiveImageResults_${card.id}">${['type','angle','state'].includes(mode)?archiveGroupedGallery(card,mode):archiveImageGallery(card,mode)}</div>${archiveImageDropZone(card.id)}</section><button onclick="editStoryArchiveCard('${id}')">カード編集</button><button class="secondary" onclick="closeModal()">閉じる</button>`)};
editArchiveImage=function(cardId,imgId=''){const card=normalizeStoryArchiveCard(getStoryArchiveCard(cardId));const img=normalizeArchiveImage(imgId?card.images.find(i=>i.id===imgId):{cardId,targetCategory:card.category,sortOrder:(card.images||[]).length+1,state:'通常'},card);const angleKnown=ARCHIVE_ANGLES_PRODUCTION.includes(img.angle),stateKnown=ARCHIVE_STATES_PRODUCTION.includes(img.state);modal(`<h2>画像資料${imgId?'編集':'追加'}</h2><div class="archive-image-editor-grid"><div><div class="archive-preview-large" id="imgPreviewBox">${archiveThumb(img)}</div><label class="file primary-action">サムネイル画像を選択<input id="imgPreviewFile" type="file" accept="image/*" onchange="previewArchiveImageFile(this.files[0])"></label></div><div><label>名前<input id="imgName" value="${esc(img.name)}"></label><label>ファイル名<input id="imgFile" value="${esc(img.fileName)}" placeholder="例：tia_front_smile.png"></label><label>保存場所<input id="imgStorage" value="${esc(img.storageLocation)}" placeholder="iCloud / SSD / NAS / URLなど"></label><div class="archive-switches"><label><input type="checkbox" id="imgOfficial" ${img.isOfficial?'checked':''}>正式採用</label><label><input type="checkbox" id="imgVidu" ${img.isViduReference?'checked':''}>Vidu参照画像</label></div></div></div><div class="archive-form-grid"><label>種類<select id="imgType">${archiveProductionOptionList(ARCHIVE_IMAGE_TYPES_PRODUCTION,img.materialType)}</select></label><label>角度<select id="imgAngle">${archiveProductionOptionList(ARCHIVE_ANGLES_PRODUCTION,img.angle)}</select></label><label>角度：自由入力<input id="imgAngleFree" value="${esc(angleKnown?'':img.angle)}" placeholder="例：左斜め上"></label><label>状態<select id="imgState">${archiveProductionOptionList(ARCHIVE_STATES_PRODUCTION,img.state)}</select></label><label>状態：自由入力<input id="imgStateFree" value="${esc(stateKnown?'':img.state)}" placeholder="例：魔法発動中"></label><label>タグ<input id="imgTags" value="${esc((img.tags||[]).join(','))}" placeholder="カンマ区切り"></label></div><label>説明<textarea id="imgDesc">${esc(img.description)}</textarea></label><fieldset><legend>将来Vidu連携用</legend><p class="meta">Viduへ送る画像選択画面でそのまま使えるよう、参照ロールやプロンプトメモを保持します。</p><label>Promptメモ<textarea id="imgPromptMemo">${esc(img.promptMemo||'')}</textarea></label><label>参照ロール<input id="imgReferenceRole" value="${esc(img.referenceRole||'')}" placeholder="character_reference / background_reference など"></label><label>Source App<input id="imgSourceApp" value="${esc(img.sourceApp||'Story Archive')}"></label><label>Source Card ID<input id="imgSourceCard" value="${esc(img.sourceCardId||card.id)}"></label></fieldset><p class="meta">画像本体は保存せず、低容量サムネイル・ファイル名・保存場所・管理情報のみ保存します。</p><button class="primary-action" onclick="saveArchiveImage('${cardId}','${imgId}')">保存</button><button class="secondary" onclick="openStoryArchiveDetail('${cardId}')">戻る</button>`);window.pendingArchivePreviewDataUrl=img.previewDataUrl||''};
saveArchiveImage=function(cardId,imgId=''){const card=normalizeStoryArchiveCard(getStoryArchiveCard(cardId));const old=imgId?card.images.find(i=>i.id===imgId):{};const img=normalizeArchiveImage({...old,id:imgId||uid('archiveImage'),cardId,targetCardId:cardId,targetCategory:card.category,name:$('#imgName').value,fileName:$('#imgFile').value,storageLocation:$('#imgStorage').value,isOfficial:$('#imgOfficial').checked,isViduReference:$('#imgVidu').checked,materialType:$('#imgType').value,angle:archiveImageFieldValue('imgAngle','imgAngleFree'),viewpoint:archiveImageFieldValue('imgAngle','imgAngleFree'),state:archiveImageFieldValue('imgState','imgStateFree'),description:$('#imgDesc').value,tags:parseTags($('#imgTags').value),previewDataUrl:window.pendingArchivePreviewDataUrl||old?.previewDataUrl||'',promptMemo:$('#imgPromptMemo').value,referenceRole:$('#imgReferenceRole').value,sourceApp:$('#imgSourceApp').value,sourceCardId:$('#imgSourceCard').value,updatedAt:now()},card);const i=card.images.findIndex(x=>x.id===img.id);if(i>=0)card.images[i]=img;else card.images.push(img);saveNormalizedArchiveCard(card);saveState(true);openStoryArchiveDetail(cardId);toast('画像資料を保存しました')};

// Version 0.3.0 enhanced image material manager: multi-add, bulk edit, sort/search, and Vidu-ready selection.
const ARCHIVE_IMAGE_SORTS=[['manual','手動順'],['name','名前順'],['createdAt','登録日順'],['updatedAt','更新日順'],['materialType','種類順'],['angle','角度順'],['state','状態順']];
function archiveImageControls(card,mode='all'){return `<div class="archive-image-toolbar enhanced"><input id="archiveImageSearch_${card.id}" placeholder="画像名・タグ・説明で検索" oninput="filterArchiveImages('${card.id}','${mode}')"><select id="archiveImageSort_${card.id}" onchange="filterArchiveImages('${card.id}','${mode}')">${ARCHIVE_IMAGE_SORTS.map(([v,l])=>`<option value="${v}">${l}</option>`).join('')}</select><select id="archiveImageType_${card.id}" onchange="filterArchiveImages('${card.id}','${mode}')"><option value="">種類すべて</option>${[...new Set((card.images||[]).map(i=>i.materialType).filter(Boolean))].sort().map(x=>`<option value="${esc(x)}">${esc(x)}</option>`).join('')}</select><select id="archiveImageAngle_${card.id}" onchange="filterArchiveImages('${card.id}','${mode}')"><option value="">角度すべて</option>${[...new Set((card.images||[]).map(i=>i.angle).filter(Boolean))].sort().map(x=>`<option value="${esc(x)}">${esc(x)}</option>`).join('')}</select><select id="archiveImageState_${card.id}" onchange="filterArchiveImages('${card.id}','${mode}')"><option value="">状態すべて</option>${[...new Set((card.images||[]).map(i=>i.state).filter(Boolean))].sort().map(x=>`<option value="${esc(x)}">${esc(x)}</option>`).join('')}</select></div>`}
function archiveImageMatchesEnhanced(i,q,type,angle,stateVal){const hay=[i.name,i.fileName,i.description,(i.tags||[]).join(' '),i.storageLocation].join(' ').toLowerCase();return (!q||hay.includes(q.toLowerCase()))&&(!type||i.materialType===type)&&(!angle||i.angle===angle)&&(!stateVal||i.state===stateVal)}
function archiveVisibleImagesEnhanced(card,mode='all'){let imgs=[...(card.images||[])];if(mode==='official')imgs=imgs.filter(i=>i.isOfficial||i.state==='正式採用');if(mode==='vidu')imgs=imgs.filter(i=>i.isViduReference);const q=$(`#archiveImageSearch_${card.id}`)?.value||'',type=$(`#archiveImageType_${card.id}`)?.value||'',angle=$(`#archiveImageAngle_${card.id}`)?.value||'',stateVal=$(`#archiveImageState_${card.id}`)?.value||'',sort=$(`#archiveImageSort_${card.id}`)?.value||'manual';imgs=imgs.filter(i=>archiveImageMatchesEnhanced(i,q,type,angle,stateVal));const key=sort==='name'?'name':sort;imgs.sort((a,b)=>sort==='manual'?(+a.sortOrder||0)-(+b.sortOrder||0):String(a[key]||'').localeCompare(String(b[key]||''),'ja'));return imgs}
function archiveSelectedImageIds(cardId){return Array.from(document.querySelectorAll(`[data-archive-image-select="${cardId}"]:checked`)).map(x=>x.value)}
function archiveImageCardSelectable(card,img){return `<article class="archive-image-card archive-image-row" onclick="openArchiveImageDetail('${card.id}','${img.id}')"><label class="archive-select" onclick="event.stopPropagation()"><input type="checkbox" value="${esc(img.id)}" data-archive-image-select="${esc(card.id)}">選択</label>${archiveThumb(img)}<div><b>${esc(img.name)}</b><small>${esc(img.materialType||'種類未設定')} / ${esc(img.angle||'角度未設定')} / ${esc(img.state||'状態未設定')}</small><small>${archiveImageBadges(img)}</small><small>${esc(img.fileName||'')} ${img.storageLocation?` / ${esc(img.storageLocation)}`:''}</small></div><div class="archive-card-actions"><button onclick="event.stopPropagation();editArchiveImage('${card.id}','${img.id}')">編集</button><button class="danger" onclick="event.stopPropagation();deleteArchiveImage('${card.id}','${img.id}')">削除</button></div></article>`}
archiveImageCard=archiveImageCardSelectable;
archiveImageGallery=function(card,mode='all'){card=normalizeStoryArchiveCard(card);if(mode==='set')return (card.imageSets||[]).map(s=>`<article class="archive-image-set"><h4>${esc(s.name)}</h4><div class="archive-gallery">${(s.imageIds||[]).map(id=>card.images.find(i=>i.id===id)).filter(Boolean).map(i=>archiveImageCard(card,i)).join('')||'<p class="meta">画像なし</p>'}</div></article>`).join('')||'<p class="meta">画像セットなし</p>';const imgs=archiveVisibleImagesEnhanced(card,mode);const shown=imgs.slice(0,240);return `<div class="archive-list-summary"><b>${imgs.length}件</b><span>大量登録に備えて現在は先頭${shown.length}件を描画します。検索・並び替えで絞り込めます。</span></div><div class="archive-gallery archive-gallery-large">${shown.map(i=>archiveImageCard(card,i)).join('')||'<p class="meta">画像資料なし</p>'}</div>`};
filterArchiveImages=function(cardId,mode='all'){const card=normalizeStoryArchiveCard(getStoryArchiveCard(cardId));const el=$(`#archiveImageResults_${cardId}`);if(el)el.innerHTML=archiveImageGallery(card,mode)};
function openArchiveBulkEdit(cardId){const ids=archiveSelectedImageIds(cardId);if(!ids.length)return toast('一括編集する画像を選択してください');modal(`<h2>画像資料の一括編集（${ids.length}件）</h2><p class="meta">空欄・変更なしの項目は既存値を保持します。</p><div class="archive-form-grid"><label>種類<select id="bulkType"><option value="">変更なし</option>${archiveProductionOptionList(ARCHIVE_IMAGE_TYPES_PRODUCTION,'')}</select></label><label>角度<select id="bulkAngle"><option value="">変更なし</option>${archiveProductionOptionList(ARCHIVE_ANGLES_PRODUCTION,'')}</select></label><label>状態<select id="bulkState"><option value="">変更なし</option>${archiveProductionOptionList(ARCHIVE_STATES_PRODUCTION,'')}</select></label><label>Vidu参照<select id="bulkVidu"><option value="">変更なし</option><option value="true">ON</option><option value="false">OFF</option></select></label><label>正式採用<select id="bulkOfficial"><option value="">変更なし</option><option value="true">ON</option><option value="false">OFF</option></select></label><label>タグ追加<input id="bulkTags" placeholder="カンマ区切りで追加"></label></div><button class="primary-action" onclick="saveArchiveBulkEdit('${cardId}','${ids.join(',')}')">一括反映</button><button class="secondary" onclick="openStoryArchiveDetail('${cardId}')">戻る</button>`)}
function saveArchiveBulkEdit(cardId,idCsv){const ids=idCsv.split(',').filter(Boolean),card=normalizeStoryArchiveCard(getStoryArchiveCard(cardId)),addTags=parseTags($('#bulkTags').value);card.images=card.images.map(img=>{if(!ids.includes(img.id))return img;const next={...img,updatedAt:now()};if($('#bulkType').value)next.materialType=$('#bulkType').value;if($('#bulkAngle').value)next.angle=$('#bulkAngle').value;if($('#bulkState').value)next.state=$('#bulkState').value;if($('#bulkVidu').value)next.isViduReference=$('#bulkVidu').value==='true';if($('#bulkOfficial').value)next.isOfficial=$('#bulkOfficial').value==='true';next.tags=[...new Set([...(next.tags||[]),...addTags])];return normalizeArchiveImage(next,card)});saveNormalizedArchiveCard(card);saveState(true);openStoryArchiveDetail(cardId);toast('一括編集を反映しました')}
archiveImageDropZone=function(cardId){return `<div class="archive-drop-zone" ondragover="event.preventDefault();this.classList.add('dragging')" ondragleave="this.classList.remove('dragging')" ondrop="event.preventDefault();this.classList.remove('dragging');addArchiveImages('${cardId}',event.dataTransfer.files)"><b>複数画像を追加</b><span>PCはドラッグ＆ドロップ、iPadは「写真から追加」「ファイルから追加」で複数選択できます。</span><div class="archive-image-actions"><label class="file primary-action">写真から追加<input type="file" accept="image/*" multiple onchange="addArchiveImages('${cardId}',this.files)"></label><label class="file secondary">ファイルから追加<input type="file" accept="image/*,.png,.jpg,.jpeg,.webp,.gif" multiple onchange="addArchiveImages('${cardId}',this.files)"></label><button class="secondary" onclick="editArchiveImage('${cardId}')">手入力で追加</button><button class="secondary" onclick="openArchiveBulkEdit('${cardId}')">選択画像を一括編集</button></div></div>`};
openStoryArchiveDetail=function(id,mode='all'){const card=normalizeStoryArchiveCard(getStoryArchiveCard(id));if(!card)return;modal(`<h2>${esc(card.title)}</h2><p>${metaLine(card)}<br>カテゴリ：${esc(card.category)} / タグ：${itemTagsHtml(card)}</p><section><h3>画像資料</h3><p class="meta">一覧から複数選択して一括編集できます。Vidu参照ONの画像は将来のVidu送信候補として保持します。</p><div class="gallery-tabs">${[['all','すべて'],['vidu','Vidu参照'],['official','正式採用'],['type','種類別'],['angle','角度別'],['state','状態別'],['set','画像セット別']].map(([m,l])=>`<button class="secondary" onclick="openStoryArchiveDetail('${id}','${m}')">${l}</button>`).join('')}<button class="vidu-one-tap" onclick="openArchiveViduReferences()">全カードのVidu参照</button></div>${mode==='set'?'':archiveImageControls(card,mode)}<div class="archive-bulk-bar"><button class="secondary" onclick="document.querySelectorAll('[data-archive-image-select=&quot;${card.id}&quot;]').forEach(x=>x.checked=true)">全選択</button><button class="secondary" onclick="document.querySelectorAll('[data-archive-image-select=&quot;${card.id}&quot;]').forEach(x=>x.checked=false)">選択解除</button><button class="primary-action" onclick="openArchiveBulkEdit('${card.id}')">選択画像を一括編集</button></div><div id="archiveImageResults_${card.id}">${['type','angle','state'].includes(mode)?archiveGroupedGallery(card,mode):archiveImageGallery(card,mode)}</div>${archiveImageDropZone(card.id)}</section><section><h3>本文</h3><p>${esc(card.body)}</p></section><section><h3>関連カード</h3>${archiveRelatedLinks(card)}</section><button onclick="editStoryArchiveCard('${id}')">カード編集</button><button class="secondary" onclick="closeModal()">閉じる</button>`)};

// Version 0.2.9 image-first Story Archive UI refinement.
function archiveRepresentativeImage(card){
  card=normalizeStoryArchiveCard(card);
  const imgs=card.images||[],sets=card.imageSets||[];
  return imgs.find(i=>i.isOfficial||i.state==='正式採用')
    ||imgs.find(i=>i.isViduReference)
    ||imgs.find(i=>sets.some(s=>s.baseImageId===i.id))
    ||imgs[0]
    ||null
}
function archiveImageLabels(img){return [img.angle,img.state,img.isOfficial?'正式採用':'',img.isViduReference?'Vidu参照':''].filter(Boolean).slice(0,4)}
function archiveThumbWithLabels(img){return `<div class="archive-thumb-wrap">${archiveThumb(img)}<div class="archive-thumb-labels">${archiveImageLabels(img).map(x=>`<span>${esc(x)}</span>`).join('')}</div></div>`}
function archiveImageMetaGrid(img){return `<dl class="archive-image-meta"><dt>画像名</dt><dd>${esc(img.name||'画像資料')}</dd><dt>種類</dt><dd>${esc(img.materialType||'未設定')}</dd><dt>角度</dt><dd>${esc(img.angle||'未設定')}</dd><dt>状態</dt><dd>${esc(img.state||'未設定')}</dd><dt>正式採用</dt><dd>${img.isOfficial?'はい':'いいえ'}</dd><dt>Vidu参照</dt><dd>${img.isViduReference?'はい':'いいえ'}</dd></dl>`}
archiveImageCard=function(card,img){return `<article class="archive-image-card archive-image-row" onclick="openArchiveImageDetail('${card.id}','${img.id}')"><label class="archive-select" onclick="event.stopPropagation()"><input type="checkbox" value="${esc(img.id)}" data-archive-image-select="${esc(card.id)}">選択</label>${archiveThumbWithLabels(img)}<div><b>${esc(img.name||'画像資料')}</b>${archiveImageMetaGrid(img)}<small>${archiveImageBadges(img)}</small><small>${esc(img.fileName||'')} ${img.storageLocation?` / ${esc(img.storageLocation)}`:''}</small></div><div class="archive-card-actions"><button onclick="event.stopPropagation();editArchiveImage('${card.id}','${img.id}')">編集</button><button class="danger" onclick="event.stopPropagation();deleteArchiveImage('${card.id}','${img.id}')">削除</button></div></article>`}
function archiveRepresentativeHero(card){const img=archiveRepresentativeImage(card);return `<section class="archive-detail-hero"><div class="archive-hero-copy"><p class="eyebrow">代表画像</p><p class="meta">採用・Vidu参照・基準画像を優先表示。</p></div><div class="archive-representative" ${img?`onclick="openArchiveImageDetail('${card.id}','${img.id}')"`:''}>${img?archiveThumbWithLabels(img):'<div class="archive-thumb-empty">画像なし</div>'}</div></section>`}
function archiveManagementDetails(card){return `<details class="archive-management"><summary>管理情報を表示</summary><dl class="archive-image-meta"><dt>ID</dt><dd>${esc(card.id)}</dd><dt>作成日時</dt><dd>${esc(card.createdAt||'未記録')}</dd><dt>更新日時</dt><dd>${esc(card.updatedAt||'未記録')}</dd><dt>作品</dt><dd>${esc(storyArchiveProjectName(card.projectId)||card.projectId||'未設定')}</dd><dt>話数</dt><dd>${esc(storyArchiveEpisodeName(card.episodeId)||card.episodeId||'未設定')}</dd><dt>状態</dt><dd>${esc(card.status||'仮設定')}</dd><dt>タグ</dt><dd>${esc((card.tags||[]).join(', ')||'なし')}</dd></dl></details>`}
function archiveGalleryTabs(id){return [['all','すべて'],['official','正式採用'],['vidu','Vidu参照'],['type','種類'],['angle','角度'],['state','状態'],['set','画像セット'],['old','旧案'],['rejected','没案']].map(([m,l])=>`<button class="secondary" onclick="openStoryArchiveDetail('${id}','${m}')">${l}</button>`).join('')}
openStoryArchiveDetail=function(id,mode='all'){const card=normalizeStoryArchiveCard(getStoryArchiveCard(id));if(!card)return;modal(`<article class="archive-detail"><h2>${esc(card.title)}</h2>${archiveRepresentativeHero(card)}<section class="archive-gallery-panel"><div class="section-head"><div><h3>画像ギャラリー</h3><p class="meta">画像を押すと拡大表示します。</p></div><div class="archive-image-actions"><button class="primary-action" onclick="editArchiveImage('${card.id}')">画像追加</button><button class="secondary" onclick="editArchiveImageSet('${card.id}')">画像セット管理</button></div></div><div class="gallery-tabs">${archiveGalleryTabs(id)}<button class="vidu-one-tap" onclick="openArchiveViduReferences()">全カードのVidu参照</button></div>${mode==='set'?'':archiveImageControls(card,mode)}<div class="archive-bulk-bar"><button class="secondary" onclick="document.querySelectorAll('[data-archive-image-select=&quot;${card.id}&quot;]').forEach(x=>x.checked=true)">全選択</button><button class="secondary" onclick="document.querySelectorAll('[data-archive-image-select=&quot;${card.id}&quot;]').forEach(x=>x.checked=false)">選択解除</button><button class="primary-action" onclick="openArchiveBulkEdit('${card.id}')">選択画像を一括編集</button></div><div id="archiveImageResults_${card.id}">${['type','angle','state'].includes(mode)?archiveGroupedGallery(card,mode):archiveImageGallery(card,mode)}</div>${archiveImageDropZone(card.id)}</section><section><h3>基本設定</h3><p><span class="type-pill">${esc(card.category)}</span> <b>状態：</b>${esc(card.status||'仮設定')}</p><p>${esc(card.body||'本文は未入力です。')}</p></section><section><h3>関連カード</h3>${archiveRelatedLinks(card)}</section>${archiveManagementDetails(card)}<button onclick="editStoryArchiveCard('${id}')">カード編集</button><button class="secondary" onclick="closeModal()">閉じる</button></article>`)};
openArchiveImageDetail=function(cardId,imgId){const card=normalizeStoryArchiveCard(getStoryArchiveCard(cardId)),imgs=card.images||[];let idx=imgs.findIndex(i=>i.id===imgId);if(idx<0)return;const img=imgs[idx],prev=imgs[(idx-1+imgs.length)%imgs.length],next=imgs[(idx+1)%imgs.length];modal(`<div class="archive-lightbox" ontouchstart="archiveLightboxTouchStart(event)" ontouchend="archiveLightboxTouchEnd(event,'${cardId}','${prev?.id||''}','${next?.id||''}')"><div class="section-head"><div><h2>${esc(img.name)}</h2><p class="meta">${idx+1} / ${imgs.length}</p></div><button class="secondary" onclick="openStoryArchiveDetail('${cardId}')">閉じる</button></div><div class="archive-lightbox-stage"><button ${imgs.length<2?'disabled':''} onclick="openArchiveImageDetail('${cardId}','${prev.id}')">←</button><div class="archive-zoom-target" id="archiveZoomTarget" style="--zoom:1">${archiveThumbWithLabels(img)}</div><button ${imgs.length<2?'disabled':''} onclick="openArchiveImageDetail('${cardId}','${next.id}')">→</button></div><div class="archive-image-actions"><button onclick="archiveZoom(-.25)">縮小</button><button onclick="archiveZoom(.25)">拡大</button><button onclick="archiveZoom(0,true)">等倍</button><button onclick="editArchiveImage('${cardId}','${imgId}')">編集</button><button class="danger" onclick="deleteArchiveImage('${cardId}','${imgId}')">削除</button></div><section><h3>画像情報</h3>${archiveImageMetaGrid(img)}<p><b>保存場所：</b>${esc(img.storageLocation||'未設定')}<br><b>ファイル名：</b>${esc(img.fileName||'未設定')}<br><b>タグ：</b>${esc((img.tags||[]).join(', ')||'なし')}</p><p>${esc(img.description||'説明は未入力です。')}</p></section></div>`)};
function archiveZoom(delta,reset=false){const el=$('#archiveZoomTarget');if(!el)return;const cur=parseFloat(el.dataset.zoom||'1'),next=reset?1:Math.min(4,Math.max(.5,cur+delta));el.dataset.zoom=next;el.style.setProperty('--zoom',next)}
function archiveCardListImage(card){const img=archiveRepresentativeImage(card);return `<div class="archive-list-image">${img?archiveThumbWithLabels(img):'<div class="archive-thumb-empty">画像なし</div>'}</div>`}
function archiveCardListMeta(card){return `<div class="archive-list-fields"><h4>${esc(card.title||'無題')}</h4><dl><dt>カテゴリ</dt><dd>${esc(card.category||'未分類')}</dd><dt>状態</dt><dd>${esc(card.status||'仮設定')}</dd><dt>画像件数</dt><dd>${(card.images||[]).length}件</dd><dt>関連カード件数</dt><dd>${archiveRelatedIds(card).length}件</dd><dt>更新日</dt><dd>${esc(card.updatedAt||'未記録')}</dd></dl></div>`}
function archiveListCategories(cards){const names=[...STORY_ARCHIVE_CATEGORIES];cards.forEach(c=>{if(c.category&&!names.includes(c.category))names.push(c.category)});return names}
let archiveTouchX=0;function archiveLightboxTouchStart(e){archiveTouchX=e.changedTouches?.[0]?.clientX||0}function archiveLightboxTouchEnd(e,cardId,prevId,nextId){const x=e.changedTouches?.[0]?.clientX||0,dx=x-archiveTouchX;if(Math.abs(dx)>55)openArchiveImageDetail(cardId,dx>0?prevId:nextId)}

const nova029ImageFirstStoryArchiveView=storyArchiveView;
storyArchiveView=function(){const cards=storyArchiveCards().map(normalizeStoryArchiveCard),q=($('#archiveSearch')?.value||'').toLowerCase();const filtered=q?cards.filter(c=>[c.title,c.category,c.status,c.updatedAt,archiveRelatedIds(c).map(id=>getStoryArchiveCard(id)?.title||'').join(' ')].join(' ').toLowerCase().includes(q)):cards;const byCat=Object.groupBy?Object.groupBy(filtered,c=>c.category):filtered.reduce((a,c)=>((a[c.category]=a[c.category]||[]).push(c),a),{});return `<section class="hero archive-hero"><h1>Story Archive</h1><p>画像資料を主役に、制作カードを代表画像から探せる一覧です。 <span class="ver">Version ${NOVA_VERSION}</span></p><div class="archive-hero-actions"><button class="primary-action" onclick="editStoryArchiveCard()">＋カード作成</button><button class="secondary vidu-one-tap" onclick="openArchiveViduReferences()">Vidu参照画像だけ表示（${archiveViduReferenceImages().length}）</button></div><input id="archiveSearch" placeholder="タイトル・カテゴリ・状態・関連カードを検索" value="${esc($('#archiveSearch')?.value||'')}" oninput="render()"></section><section><div class="archive-category-grid image-first-archive-grid">${archiveListCategories(filtered).map(cat=>`<article class="archive-category image-first-category"><h3>${esc(cat)}</h3>${(byCat[cat]||[]).map(c=>`<article class="archive-card image-first-card" role="button" tabindex="0" onclick="openStoryArchiveDetail('${c.id}')" onkeydown="if(event.key==='Enter'||event.key===' ')openStoryArchiveDetail('${c.id}')">${archiveCardListImage(c)}${archiveCardListMeta(c)}</article>`).join('')||'<p class="empty-note">カードなし</p>'}</article>`).join('')}</div></section>`};

// Version 0.2.9 gallery filter completion for old/rejected proposals and image sets.
archiveImageControls=function(card,mode='all'){return `<div class="archive-image-toolbar enhanced"><input id="archiveImageSearch_${card.id}" placeholder="画像名・タグ・説明で検索" oninput="filterArchiveImages('${card.id}','${mode}')"><select id="archiveImageSort_${card.id}" onchange="filterArchiveImages('${card.id}','${mode}')">${ARCHIVE_IMAGE_SORTS.map(([v,l])=>`<option value="${v}">${l}</option>`).join('')}</select><select id="archiveImageType_${card.id}" onchange="filterArchiveImages('${card.id}','${mode}')"><option value="">種類すべて</option>${[...new Set((card.images||[]).map(i=>i.materialType).filter(Boolean))].sort().map(x=>`<option value="${esc(x)}">${esc(x)}</option>`).join('')}</select><select id="archiveImageAngle_${card.id}" onchange="filterArchiveImages('${card.id}','${mode}')"><option value="">角度すべて</option>${[...new Set((card.images||[]).map(i=>i.angle).filter(Boolean))].sort().map(x=>`<option value="${esc(x)}">${esc(x)}</option>`).join('')}</select><select id="archiveImageState_${card.id}" onchange="filterArchiveImages('${card.id}','${mode}')"><option value="">状態すべて</option>${[...new Set((card.images||[]).map(i=>i.state).filter(Boolean))].sort().map(x=>`<option value="${esc(x)}">${esc(x)}</option>`).join('')}</select><select id="archiveImageSetFilter_${card.id}" onchange="filterArchiveImages('${card.id}','${mode}')"><option value="">画像セットすべて</option>${(card.imageSets||[]).map(s=>`<option value="${esc(s.id)}">${esc(s.name)}</option>`).join('')}</select></div>`}
archiveVisibleImagesEnhanced=function(card,mode='all'){let imgs=[...(card.images||[])];if(mode==='official')imgs=imgs.filter(i=>i.isOfficial||i.state==='正式採用');if(mode==='vidu')imgs=imgs.filter(i=>i.isViduReference);if(mode==='old')imgs=imgs.filter(i=>['旧案','旧デザイン'].includes(i.state)||['旧案','旧デザイン'].includes(i.materialType));if(mode==='rejected')imgs=imgs.filter(i=>i.state==='没案'||i.materialType==='没案');const q=$(`#archiveImageSearch_${card.id}`)?.value||'',type=$(`#archiveImageType_${card.id}`)?.value||'',angle=$(`#archiveImageAngle_${card.id}`)?.value||'',stateVal=$(`#archiveImageState_${card.id}`)?.value||'',setId=$(`#archiveImageSetFilter_${card.id}`)?.value||'',sort=$(`#archiveImageSort_${card.id}`)?.value||'manual';imgs=imgs.filter(i=>archiveImageMatchesEnhanced(i,q,type,angle,stateVal)&&(setId?!setId||i.imageSetId===setId||card.imageSets?.find(s=>s.id===setId)?.imageIds?.includes(i.id):true));const key=sort==='name'?'name':sort;imgs.sort((a,b)=>sort==='manual'?(+a.sortOrder||0)-(+b.sortOrder||0):String(a[key]||'').localeCompare(String(b[key]||''),'ja'));return imgs}

// Version 1.0 Story Archive: templates, certainty, audit trail, backlinks, timeline, folders.
const STORY_ARCHIVE_V1_CATEGORIES=['キャラクター','世界観','場所','アイテム','用語','ストーリー'];
const STORY_ARCHIVE_TEMPLATE_FIELDS={
 キャラクター:[['role','役割'],['profile','プロフィール'],['goal','目的'],['personality','性格'],['appearance','外見'],['voice','声・話し方'],['importantSettings','重要設定']],
 世界観:[['overview','概要'],['rules','世界のルール'],['history','歴史'],['culture','文化'],['conflict','対立・問題']],
 場所:[['locationType','種別'],['description','説明'],['atmosphere','雰囲気'],['residents','関係者'],['events','起きる出来事']],
 アイテム:[['itemType','種別'],['owner','所有者'],['description','説明'],['ability','効果・能力'],['origin','由来'],['limits','制約']],
 用語:[['reading','読み'],['meaning','意味'],['usage','使い方'],['relatedConcepts','関連概念']],
 ストーリー:[['synopsis','あらすじ'],['theme','テーマ'],['plot','プロット'],['conflict','葛藤'],['resolution','結末'],['foreshadowing','伏線']]
};
function archiveV1Ensure(){ensureStoryArchiveState();state.storyArchiveFolders=Array.isArray(state.storyArchiveFolders)?state.storyArchiveFolders:[];state.storyArchiveCards=state.storyArchiveCards.map(c=>normalizeStoryArchiveCardV1(c));return state.storyArchiveCards}
function normalizeStoryArchiveCardV1(card={}){const c=normalizeStoryArchiveCard(card||{});const cat=STORY_ARCHIVE_V1_CATEGORIES.includes(card.templateCategory||card.category)?(card.templateCategory||card.category):c.category;return{...c,category:cat,templateCategory:cat,isConfirmed:typeof card.isConfirmed==='boolean'?card.isConfirmed:c.status==='確定',folderId:card.folderId||'',parentId:card.parentId||'',timelineAt:card.timelineAt||card.date||'',timelineOrder:Number(card.timelineOrder||card.sortOrder||0),templateData:{...(card.templateData||{})},changeLog:Array.isArray(card.changeLog)?card.changeLog:[],images:Array.isArray(card.images)?card.images:[],imageSets:Array.isArray(card.imageSets)?card.imageSets:[]}}
function archiveV1FolderOptions(selected=''){const folders=state.storyArchiveFolders||[];return `<option value="" ${!selected?'selected':''}>未分類</option>`+folders.map(f=>`<option value="${esc(f.id)}" ${selected===f.id?'selected':''}>${'— '.repeat(Math.max(0,archiveFolderDepth(f.id)))}${esc(f.name)}</option>`).join('')}
function archiveFolderDepth(id,seen=new Set()){const f=(state.storyArchiveFolders||[]).find(x=>x.id===id);if(!f||!f.parentId||seen.has(id))return 0;seen.add(id);return 1+archiveFolderDepth(f.parentId,seen)}
function archiveV1CategoryOptions(selected){return STORY_ARCHIVE_V1_CATEGORIES.map(c=>`<option value="${esc(c)}" ${selected===c?'selected':''}>${esc(c)}</option>`).join('')}
