function archiveV1RelatedPicker(card){const ids=new Set(archiveRelatedIds(card));return `<label>関連カード（双方向リンク）<select id="archiveRelated" multiple>${storyArchiveCards().filter(c=>c.id!==card.id).map(c=>`<option value="${esc(c.id)}" ${ids.has(c.id)?'selected':''}>${esc(c.title)} / ${esc(c.category)}</option>`).join('')}</select></label><p class="meta">保存すると選択した相手側にも自動でリンクを追加し、外したリンクは相手側からも解除します。</p>`}
function archiveV1SelectedRelated(){const el=$('#archiveRelated');return el?Array.from(el.selectedOptions).map(o=>o.value).filter(Boolean):[]}
function archiveV1Diff(before,after){const b=before?normalizeStoryArchiveCardV1(before):{};['title','body','category','status','isConfirmed','folderId','parentId','timelineAt','timelineOrder','tags','relatedIds','templateData'].forEach(field=>{if(JSON.stringify(b[field]??'')!==JSON.stringify(after[field]??'')){after.changeLog.unshift({id:uid('log'),field,before:b[field]??'',after:after[field]??'',changedAt:now()})}});after.changeLog=after.changeLog.slice(0,80)}
function archiveV1FoldersTree(){const folders=state.storyArchiveFolders||[],cards=archiveV1Ensure();const roots=folders.filter(f=>!f.parentId);const renderFolder=(f)=>{const children=folders.filter(x=>x.parentId===f.id),items=cards.filter(c=>c.folderId===f.id);return `<details open class="archive-folder"><summary>📁 ${esc(f.name)} <span class="meta">${items.length}件</span></summary>${items.map(archiveV1CardRow).join('')||''}${children.map(renderFolder).join('')}</details>`};return `<section><div class="section-head"><h2>フォルダ・階層</h2><button class="secondary" onclick="editArchiveFolder()">＋フォルダ</button></div>${roots.map(renderFolder).join('')||'<p class="empty-note">フォルダはまだありません。</p>'}<h3>未分類</h3>${cards.filter(c=>!c.folderId).map(archiveV1CardRow).join('')||'<p class="empty-note">未分類カードはありません。</p>'}</section>`}
function editArchiveFolder(id=''){const f=id?(state.storyArchiveFolders||[]).find(x=>x.id===id):{id:uid('folder'),name:'新しいフォルダ',parentId:''};modal(`<h2>フォルダ編集</h2><label>名前<input id="folderName" value="${esc(f.name)}"></label><label>親フォルダ<select id="folderParent">${archiveV1FolderOptions(f.parentId).replace(`value="${f.id}"`,'value="'+f.id+'" disabled')}</select></label><button onclick="saveArchiveFolder('${id}','${f.id}')">保存</button>`)}
function saveArchiveFolder(id,newId){const f=id?state.storyArchiveFolders.find(x=>x.id===id):{id:newId};f.name=$('#folderName').value||'無題フォルダ';f.parentId=$('#folderParent').value||'';f.updatedAt=now();if(!id)state.storyArchiveFolders.push(f);saveState(true);closeModal();render()}
function archiveV1CardRow(c){return `<article class="archive-card image-first-card"><h4><button class="link-button" onclick="openStoryArchiveDetail('${c.id}')">${esc(c.title)}</button></h4><p>${esc(c.body).slice(0,120)}</p><p class="meta">${esc(c.category)} / ${c.isConfirmed?'確定':'未確定'} / 時系列：${esc(c.timelineAt||'未設定')} / 関連：${archiveRelatedIds(c).length}件</p><button onclick="openStoryArchiveDetail('${c.id}')">詳細</button><button onclick="editStoryArchiveCard('${c.id}')">編集</button></article>`}
