function archiveV1ChangeLog(card){return `<section><h3>変更履歴</h3>${(card.changeLog||[]).map(l=>`<div class="row"><span>${esc(l.changedAt)} / ${esc(l.field)}<br><small>${esc(JSON.stringify(l.before)).slice(0,120)} → ${esc(JSON.stringify(l.after)).slice(0,120)}</small></span></div>`).join('')||'<p class="empty-note">このカードの変更履歴はまだありません。</p>'}</section>`}
const storyArchiveViewPreV1=storyArchiveView;
storyArchiveView=function(){const cards=archiveV1Ensure(),q=($('#archiveSearch')?.value||'').toLowerCase(),filtered=q?cards.filter(c=>storyArchiveSearchText(c).includes(q)):cards;const cats=STORY_ARCHIVE_V1_CATEGORIES;return `<section class="hero archive-hero"><p class="eyebrow">Story Archive 1.0</p><h1>Story Archive</h1><p>カテゴリ別テンプレート、確定／未確定、変更履歴、双方向リンク、時系列、フォルダ階層に対応しました。既存カードは自動変換して保持します。</p><div class="archive-hero-actions"><button class="primary-action" onclick="editStoryArchiveCard()">＋カード作成</button><button class="secondary" onclick="editArchiveFolder()">＋フォルダ作成</button></div><input id="archiveSearch" placeholder="タイトル・本文・タグ・関連カード名を検索" value="${esc($('#archiveSearch')?.value||'')}" oninput="render()"></section><section><h2>カテゴリ別カード</h2><div class="archive-category-grid image-first-archive-grid">${cats.map(cat=>`<article class="archive-category image-first-category"><h3>${esc(cat)}</h3>${filtered.filter(c=>c.category===cat).map(archiveV1CardRow).join('')||'<p class="empty-note">カードなし</p>'}</article>`).join('')}</div></section>${archiveV1Timeline()}${archiveV1FoldersTree()}`}
editStoryArchiveCard=function(id=''){const card=normalizeStoryArchiveCardV1(id?getStoryArchiveCard(id):newStoryArchiveCard());modal(`<h2>${id?'Story Archiveカード編集':'Story Archiveカード作成'}</h2><label>ID<input id="archiveId" value="${esc(card.id)}" ${id?'readonly':''}></label><label>カテゴリ<select id="archiveCategory" onchange="saveStoryArchiveDraftCategory('${esc(id)}')">${archiveV1CategoryOptions(card.category)}</select></label><label>タイトル<input id="archiveTitle" value="${esc(card.title)}"></label><label>本文<textarea id="archiveBody" rows="6">${esc(card.body)}</textarea></label>${archiveV1TemplateForm(card)}<label><input type="checkbox" id="archiveConfirmed" ${card.isConfirmed?'checked':''}> 確定済み</label><label>状態<select id="archiveStatus">${STORY_ARCHIVE_STATUSES.map(s=>`<option value="${esc(s)}" ${card.status===s?'selected':''}>${esc(s)}</option>`).join('')}</select></label><label>フォルダ<select id="archiveFolder">${archiveV1FolderOptions(card.folderId)}</select></label><label>親カード<select id="archiveParent"><option value="">なし</option>${storyArchiveCards().filter(c=>c.id!==card.id).map(c=>`<option value="${esc(c.id)}" ${card.parentId===c.id?'selected':''}>${esc(c.title)}</option>`).join('')}</select></label><label>時系列ラベル<input id="archiveTimelineAt" value="${esc(card.timelineAt)}" placeholder="例：第1話前半 / 1024年 春"></label><label>時系列の並び順<input id="archiveTimelineOrder" type="number" value="${esc(card.timelineOrder)}"></label><label>タグ（カンマ区切り）<input id="archiveTags" value="${esc(tagInputValue(card))}"></label><label>作品<select id="archiveProject">${state.projects.map(p=>`<option value="${esc(p.id)}" ${card.projectId===p.id?'selected':''}>${esc(p.title)}</option>`).join('')}</select></label><label>話数<select id="archiveEpisode">${state.episodes.map(e=>`<option value="${esc(e.id)}" ${card.episodeId===e.id?'selected':''}>${esc(storyArchiveProjectName(e.projectId))} / ${esc(e.numberLabel)}</option>`).join('')}</select></label>${archiveV1RelatedPicker(card)}${typeof archiveFormImages==='function'?archiveFormImages(card):''}<p class="meta">作成日時：${esc(card.createdAt)} / 更新日時：${esc(card.updatedAt)}</p><button class="primary-action" onclick="saveStoryArchiveCard('${esc(id)}')">保存</button><button class="secondary" onclick="closeModal()">キャンセル</button>`)}
function saveStoryArchiveDraftCategory(id){const select=$('#archiveCategory'); if(!select)return; const current=normalizeStoryArchiveCardV1(id?getStoryArchiveCard(id):newStoryArchiveCard()); current.category=select.value; closeModal(); setTimeout(()=>editStoryArchiveCard(id),0)}
