// Version 1.0.1 Scene command center: one-screen production route without data loss.
const SCENE_WORK_STATUSES=['未着手','制作中','完成'];
function ensureSceneCommandCenter(){(state.scenes||[]).forEach((s,i)=>{s.sceneTitle=s.sceneTitle||s.title||'';s.sceneOverview=s.sceneOverview||s.summary||'';s.productionStage=SCENE_WORK_STATUSES.includes(s.productionStage)?s.productionStage:(s.completion?.finalVideo||s.completion?.completedDate?'完成':(sceneCompletionRateFull&&sceneCompletionRateFull(s)>0?'制作中':'未着手'));s.doneChecklist=s.doneChecklist||{title:Boolean(s.title),overview:Boolean(s.summary),characters:Boolean((s.relatedCharacters||[]).length||s.charactersText),place:Boolean(s.location),archive:Boolean((s.storyArchiveCardIds||[]).length),image:Boolean((s.usedImageIds||[]).length||(s.illustrations||[]).length),video:Boolean((s.usedVideoIds||[]).length||(s.vidu?.generatedVideos||[]).length),vidu:Boolean(s.vidu?.japanesePrompt||s.viduPrompt)};s.storyArchiveCardIds=Array.isArray(s.storyArchiveCardIds)?s.storyArchiveCardIds:[];s.usedImageIds=Array.isArray(s.usedImageIds)?s.usedImageIds:[];s.usedVideoIds=Array.isArray(s.usedVideoIds)?s.usedVideoIds:[];if(!s.productionLink)s.productionLink={dashboardId:'',externalId:'',syncStatus:'local-only'};if(!s.sortOrder)s.sortOrder=i+1})}
function sceneCharactersLabel(s){const ids=new Set([...(s.relatedCharacters||[]),...(s.characterIds||[])]);const names=[...ids].map(id=>(state.characters||[]).find(c=>c.id===id)?.title).filter(Boolean);return names.join(', ')||s.charactersText||'未設定'}
function sceneArchiveCards(s){const ids=new Set([...(s.storyArchiveCardIds||[]),...(s.relatedIds||[])]);return (state.storyArchiveCards||[]).filter(c=>ids.has(c.id)||((c.relatedIds||[]).includes(s.id)))}
function sceneAssetImages(s){return [...(s.illustrations||[]).map(a=>({name:assetLabel(a),meta:a.adoptionStatus||a.status||'',id:a.id})),...(s.usedImageIds||[]).map(id=>({name:id,meta:'外部/Story Archive画像',id}))]}
function sceneAssetVideos(s){return [...(s.vidu?.generatedVideos||[]).map(v=>({name:assetLabel(v),meta:v.adoptionStatus||v.status||'',id:v.id})),...(s.usedVideoIds||[]).map(id=>({name:id,meta:'外部動画',id}))]}
function sceneChecklist(s){const keys=[['title','シーンタイトル'],['overview','シーン概要'],['characters','登場キャラクター'],['place','場所'],['archive','Story Archiveリンク'],['image','使用画像'],['video','使用動画'],['vidu','Viduプロンプト']];return keys.map(([k,l])=>`<label class="check-row"><input type="checkbox" ${s.doneChecklist?.[k]?'checked':''} onchange="toggleSceneCheck('${s.id}','${k}',this.checked)">${esc(l)}</label>`).join('')}
function toggleSceneCheck(id,key,val){const s=state.scenes.find(x=>x.id===id);if(!s)return;s.doneChecklist={...(s.doneChecklist||{}),[key]:val};touch(s);saveState(true);toast('完成チェックを更新しました')}
function storyArchiveOptions(selected=[]){return (state.storyArchiveCards||[]).map(c=>`<option value="${esc(c.id)}" ${(selected||[]).includes(c.id)?'selected':''}>${esc(c.title||c.id)}</option>`).join('')}
function characterOptions(selected=[]){return (state.characters||[]).filter(c=>!currentProject()||c.projectId===currentProject().id).map(c=>`<option value="${esc(c.id)}" ${(selected||[]).includes(c.id)?'selected':''}>${esc(c.title||c.name||c.id)}</option>`).join('')}
function openSceneDetail(id){ensureV07Production();ensureSceneCommandCenter();const s=state.scenes.find(x=>x.id===id);if(!s)return;nsOpenSceneId=id;recordLastLocation({sceneId:id});const scenes=state.scenes.filter(x=>x.episodeId===s.episodeId&&!x.isArchived).sort((a,b)=>(+a.sortOrder||0)-(+b.sortOrder||0));const i=scenes.findIndex(x=>x.id===id),prev=scenes[i-1],next=scenes[i+1],archive=sceneArchiveCards(s),imgs=sceneAssetImages(s),vids=sceneAssetVideos(s);modal(`<div class="scene-command"><div class="scene-command-head"><div><p class="eyebrow">Scene Command Center</p><h2>${esc(storyTitle('scenes',s))} <span class="ver">${sceneCompletionRateFull(s)}%</span></h2><p class="meta">Production Dashboard連携ID：${esc(s.productionLink?.dashboardId||'未設定')} / 同期：${esc(s.productionLink?.syncStatus||'local-only')}</p></div><div class="scene-status-box"><label>制作状況<select onchange="saveSceneStage('${s.id}',this.value)">${SCENE_WORK_STATUSES.map(x=>`<option ${s.productionStage===x?'selected':''}>${x}</option>`).join('')}</select></label></div></div><div class="scene-command-grid"><section><h3>基本</h3><dl class="scene-dl"><dt>シーンタイトル</dt><dd>${esc(s.sceneTitle||s.title||storyTitle('scenes',s))}</dd><dt>シーン概要</dt><dd>${esc(s.sceneOverview||s.summary||'未設定')}</dd><dt>登場キャラクター</dt><dd>${esc(sceneCharactersLabel(s))}</dd><dt>場所</dt><dd>${esc(s.location||'未設定')}</dd></dl></section><section><h3>Story Archiveカード</h3>${archive.map(c=>`<div class="row"><span>${esc(c.title||c.id)}<br><small>${esc(c.category||'')}</small></span><button onclick="openStoryArchiveDetail('${c.id}')">開く</button></div>`).join('')||'<p class="meta">リンクなし</p>'}</section><section><h3>使用画像</h3>${imgs.map(a=>`<div class="asset-chip"><b>${esc(a.name)}</b><small>${esc(a.meta)}</small></div>`).join('')||'<p class="meta">未登録</p>'}</section><section><h3>使用動画</h3>${vids.map(a=>`<div class="asset-chip"><b>${esc(a.name)}</b><small>${esc(a.meta)}</small></div>`).join('')||'<p class="meta">未登録</p>'}</section><section class="wide"><h3>Viduプロンプト</h3><p><b>日本語：</b>${esc(s.vidu?.japanesePrompt||s.viduPrompt||'未設定')}</p><p><b>English：</b>${esc(s.vidu?.englishPrompt||'')}</p></section><section><h3>完成チェック</h3><div class="check-grid">${sceneChecklist(s)}</div></section></div><div class="scene-actions"><button ${!prev?'disabled':''} onclick="openSceneDetail('${prev?.id||''}')">← 前のScene</button><button ${!next?'disabled':''} onclick="openSceneDetail('${next?.id||''}')">次のScene →</button><button onclick="editSceneCommand('${id}')">1画面編集</button><button onclick="duplicateScene('${id}')">複製</button><button class="danger" onclick="deleteScene('${id}')">削除</button></div></div>`)}
function saveSceneStage(id,value){const s=state.scenes.find(x=>x.id===id);if(!s)return;s.productionStage=value;if(value==='完成')s.completionRate=100;touch(s);saveState(true);openSceneDetail(id)}
function editSceneCommand(id){ensureSceneCommandCenter();const s=state.scenes.find(x=>x.id===id);modal(`<h2>Scene 1画面編集</h2><div class="scene-edit-grid"><label>シーンタイトル<input id="cmd_title" value="${esc(s.sceneTitle||s.title||'')}"></label><label>場所<input id="cmd_location" value="${esc(s.location||'')}"></label><label>制作状況<select id="cmd_stage">${SCENE_WORK_STATUSES.map(x=>`<option ${s.productionStage===x?'selected':''}>${x}</option>`).join('')}</select></label><label>Story Archiveカード<select id="cmd_archive" multiple>${storyArchiveOptions(s.storyArchiveCardIds)}</select></label><label>登場キャラクター<select id="cmd_chars" multiple>${characterOptions(s.relatedCharacters||[])}</select></label><label>使用画像ID（カンマ区切り）<input id="cmd_images" value="${esc((s.usedImageIds||[]).join(','))}"></label><label>使用動画ID（カンマ区切り）<input id="cmd_videos" value="${esc((s.usedVideoIds||[]).join(','))}"></label><label>Production Dashboard連携ID<input id="cmd_dash" value="${esc(s.productionLink?.dashboardId||'')}"></label><label class="wide">シーン概要<textarea id="cmd_overview">${esc(s.sceneOverview||s.summary||'')}</textarea></label><label class="wide">Viduプロンプト<textarea id="cmd_vidu">${esc(s.vidu?.japanesePrompt||s.viduPrompt||'')}</textarea></label></div><button class="primary-action" onclick="saveSceneCommand('${id}')">保存</button>`) }
function saveSceneCommand(id){const s=state.scenes.find(x=>x.id===id);const before=JSON.stringify(s);s.sceneTitle=$('#cmd_title').value;s.title=s.sceneTitle;s.location=$('#cmd_location').value;s.sceneOverview=$('#cmd_overview').value;s.summary=s.sceneOverview;s.productionStage=$('#cmd_stage').value;s.storyArchiveCardIds=selectedIds('cmd_archive');s.relatedCharacters=selectedIds('cmd_chars');s.usedImageIds=parseTags($('#cmd_images').value);s.usedVideoIds=parseTags($('#cmd_videos').value);s.vidu={...(s.vidu||{}),japanesePrompt:$('#cmd_vidu').value};s.productionLink={...(s.productionLink||{}),dashboardId:$('#cmd_dash').value,syncStatus:$('#cmd_dash').value?'ready':'local-only'};touch(s);recordHistory(s,before);saveState();openSceneDetail(id);toast('Sceneを保存しました')}
function duplicateScene(id){const s=state.scenes.find(x=>x.id===id);if(!s)return;const copy=structuredClone(s);copy.id=uid('scene');copy.title=(s.title||storyTitle('scenes',s))+' コピー';copy.sceneTitle=copy.title;copy.sortOrder=Math.max(0,...state.scenes.filter(x=>x.episodeId===s.episodeId).map(x=>+x.sortOrder||0))+1;copy.createdAt=now();copy.updatedAt=copy.createdAt;state.scenes.push(copy);saveState();closeModal();render();toast('Sceneを複製しました')}
function deleteScene(id){const s=state.scenes.find(x=>x.id===id);if(!s)return;if(state.settings?.confirmOnDelete&&!confirm('このSceneを削除しますか？既存データ保護のためアーカイブします。'))return;s.isArchived=true;touch(s);saveState();closeModal();render();toast('Sceneをアーカイブしました')}
function moveSceneOrder(id,dir){const s=state.scenes.find(x=>x.id===id);const list=state.scenes.filter(x=>x.episodeId===s.episodeId&&!x.isArchived).sort((a,b)=>(+a.sortOrder||0)-(+b.sortOrder||0));const i=list.findIndex(x=>x.id===id),j=i+dir;if(j<0||j>=list.length)return;[list[i].sortOrder,list[j].sortOrder]=[list[j].sortOrder,list[i].sortOrder];touch(list[i]);touch(list[j]);saveState();render()}
storyCollectionView=function(collection){ensureV07Production();ensureSceneCommandCenter();if(collection!=='scenes')return nsOldStoryCollectionView(collection);const p=currentProject();if(!p)return requireProject(collection);const items=applyFilters(collection,projectItems(collection)).sort((a,b)=>(+a.sortOrder||0)-(+b.sortOrder||0));return `<h1>シーン：${esc(p.title)}</h1><button class="primary-action" onclick="editStoryItem('scenes')">＋ シーンを追加</button>${filterBar('scenes')}<div class="scene-list">${items.map(s=>`<article class="card scene-list-card ${s.completion?.finalVideo?'complete-scene':''}"><h3>${esc(storyTitle('scenes',s))} ${s.productionStage==='完成'?'✅':''}</h3><div class="big-progress"><span style="width:${sceneCompletionRateFull(s)}%"></span></div><p>制作状況:${esc(s.productionStage)} / 完成率:${sceneCompletionRateFull(s)}%<br>場所:${esc(s.location||'未設定')} / 登場:${esc(sceneCharactersLabel(s))}<br>${metaLine(s)}</p><button onclick="openSceneDetail('${s.id}')">制作画面を開く</button><button onclick="moveSceneOrder('${s.id}',-1)">↑</button><button onclick="moveSceneOrder('${s.id}',1)">↓</button><button onclick="duplicateScene('${s.id}')">複製</button><button class="danger" onclick="deleteScene('${s.id}')">削除</button></article>`).join('')||emptyState(collection)}</div>`}
ensureSceneCommandCenter();saveState(true);render();

// Version 1.0.2 Enhanced Scene add/edit workspace: structured for Production Dashboard and Story Archive links.
const SCENE_WORK_STATUSES_V102=['未着手','画像制作中','動画制作中','編集中','完成'];
const SCENE_PRIORITIES_V102=['高','中','低'];
function sceneTextList(value){return Array.isArray(value)?value.join(', '):(value||'')}
function sceneListFromInput(id){return parseTags($('#'+id)?.value||'')}
function ensureSceneCommandCenterV102(){ensureSceneCommandCenter();(state.scenes||[]).forEach((s,i)=>{s.scenePurpose=s.scenePurpose||s.purpose||'';s.imageSetIds=Array.isArray(s.imageSetIds)?s.imageSetIds:[];s.audio={bgm:s.audio?.bgm||s.bgm||'',se:s.audio?.se||s.se||'',voice:s.audio?.voice||s.voice||''};s.production={status:SCENE_WORK_STATUSES_V102.includes(s.production?.status)?s.production.status:(SCENE_WORK_STATUSES_V102.includes(s.productionStage)?s.productionStage:(s.productionStage==='制作中'?'画像制作中':'未着手')),priority:SCENE_PRIORITIES_V102.includes(s.production?.priority||s.priority)?(s.production?.priority||s.priority):'中',assignee:s.production?.assignee||s.assignee||'',checklist:s.production?.checklist||s.doneChecklist||{}};s.productionStage=s.production.status;s.priority=s.production.priority;s.assignee=s.production.assignee;s.storyArchiveCardIds=Array.isArray(s.storyArchiveCardIds)?s.storyArchiveCardIds:[];s.relatedCharacters=Array.isArray(s.relatedCharacters)?s.relatedCharacters:(Array.isArray(s.characterIds)?s.characterIds:[]);s.usedImageIds=Array.isArray(s.usedImageIds)?s.usedImageIds:[];s.usedVideoIds=Array.isArray(s.usedVideoIds)?s.usedVideoIds:[];s.productionLink={dashboardId:s.productionLink?.dashboardId||'',externalId:s.productionLink?.externalId||'',syncStatus:s.productionLink?.syncStatus||'local-only',schema:'scene-production-v1'};if(!s.sortOrder)s.sortOrder=i+1})}
function sceneImageSetsLabel(s){const ids=s.imageSetIds||[];const cards=(state.storyArchiveCards||[]).filter(c=>ids.includes(c.id));return cards.map(c=>c.title||c.id).concat(ids.filter(id=>!cards.some(c=>c.id===id))).join(', ')||'未設定'}
function sceneAudioLine(s){const a=s.audio||{};return `<dt>BGM</dt><dd>${esc(a.bgm||'未設定')}</dd><dt>SE</dt><dd>${esc(a.se||'未設定')}</dd><dt>ボイス</dt><dd>${esc(a.voice||'未設定')}</dd>`}
function sceneChecklist(s){const keys=[['overview','シーン概要'],['purpose','シーンの目的'],['characters','登場キャラクター'],['archive','Story Archiveリンク'],['image','使用画像'],['imageSet','画像セット'],['video','使用動画'],['viduJa','Vidu日本語'],['viduEn','Vidu English'],['audio','音素材'],['edit','編集確認']];const list=s.production?.checklist||s.doneChecklist||{};return keys.map(([k,l])=>`<label class="check-row"><input type="checkbox" ${list[k]?'checked':''} onchange="toggleSceneCheck('${s.id}','${k}',this.checked)">${esc(l)}</label>`).join('')}
toggleSceneCheck=function(id,key,val){const s=state.scenes.find(x=>x.id===id);if(!s)return;s.production={...(s.production||{}),checklist:{...(s.production?.checklist||s.doneChecklist||{}),[key]:val}};s.doneChecklist=s.production.checklist;touch(s);saveState(true);toast('チェックリストを更新しました')}
function sceneStatusOptions(selected){return SCENE_WORK_STATUSES_V102.map(x=>`<option ${selected===x?'selected':''}>${x}</option>`).join('')}
function scenePriorityOptions(selected){return SCENE_PRIORITIES_V102.map(x=>`<option ${selected===x?'selected':''}>${x}</option>`).join('')}
openSceneDetail=function(id){ensureV07Production();ensureSceneCommandCenterV102();const s=state.scenes.find(x=>x.id===id);if(!s)return;nsOpenSceneId=id;recordLastLocation({sceneId:id});const scenes=state.scenes.filter(x=>x.episodeId===s.episodeId&&!x.isArchived).sort((a,b)=>(+a.sortOrder||0)-(+b.sortOrder||0));const i=scenes.findIndex(x=>x.id===id),prev=scenes[i-1],next=scenes[i+1],archive=sceneArchiveCards(s),imgs=sceneAssetImages(s),vids=sceneAssetVideos(s);const a=s.audio||{},p=s.production||{};modal(`<div class="scene-command"><div class="scene-command-head"><div><p class="eyebrow">Scene Command Center 1.0.2</p><h2>${esc(storyTitle('scenes',s))} <span class="ver">${sceneCompletionRateFull(s)}%</span></h2><p class="meta">Production Dashboard連携ID：${esc(s.productionLink?.dashboardId||'未設定')} / 同期：${esc(s.productionLink?.syncStatus||'local-only')} / 優先度：${esc(p.priority||'中')} / 担当：${esc(p.assignee||'未設定')}</p></div><div class="scene-status-box"><label>制作状況<select onchange="saveSceneStage('${s.id}',this.value)">${sceneStatusOptions(p.status||s.productionStage)}</select></label></div></div><div class="scene-command-grid"><section><h3>ストーリー</h3><dl class="scene-dl"><dt>シーン概要</dt><dd>${esc(s.sceneOverview||s.summary||'未設定')}</dd><dt>シーンの目的</dt><dd>${esc(s.scenePurpose||'未設定')}</dd><dt>登場キャラクター</dt><dd>${esc(sceneCharactersLabel(s))}</dd><dt>Story Archive</dt><dd>${archive.length}件リンク</dd></dl></section><section><h3>Story Archiveカード</h3>${archive.map(c=>`<div class="row"><span>${esc(c.title||c.id)}<br><small>${esc(c.category||'')}</small></span><button onclick="openStoryArchiveDetail('${c.id}')">開く</button></div>`).join('')||'<p class="meta">リンクなし</p>'}</section><section><h3>映像</h3><dl class="scene-dl"><dt>使用画像</dt><dd>${imgs.map(a=>esc(a.name)).join('<br>')||'未登録'}</dd><dt>画像セット</dt><dd>${esc(sceneImageSetsLabel(s))}</dd><dt>使用動画</dt><dd>${vids.map(a=>esc(a.name)).join('<br>')||'未登録'}</dd></dl></section><section><h3>音</h3><dl class="scene-dl">${sceneAudioLine(s)}</dl></section><section class="wide"><h3>Viduプロンプト</h3><p><b>日本語：</b>${esc(s.vidu?.japanesePrompt||s.viduPrompt||'未設定')}</p><p><b>English：</b>${esc(s.vidu?.englishPrompt||'未設定')}</p></section><section><h3>制作管理</h3><dl class="scene-dl"><dt>制作状況</dt><dd>${esc(p.status||s.productionStage)}</dd><dt>優先度</dt><dd>${esc(p.priority||'中')}</dd><dt>担当</dt><dd>${esc(p.assignee||'未設定')}</dd></dl></section><section><h3>チェックリスト</h3><div class="check-grid">${sceneChecklist(s)}</div></section><section class="wide"><h3>編集メモ</h3><p>${esc(s.memo||'未設定')}</p></section></div><div class="scene-actions"><button ${!prev?'disabled':''} onclick="openSceneDetail('${prev?.id||''}')">← 前のScene</button><button ${!next?'disabled':''} onclick="openSceneDetail('${next?.id||''}')">次のScene →</button><button onclick="editSceneCommand('${id}')">1画面編集</button><button onclick="moveSceneOrder('${s.id}',-1);openSceneDetail('${s.id}')">上へ並び替え</button><button onclick="moveSceneOrder('${s.id}',1);openSceneDetail('${s.id}')">下へ並び替え</button><button onclick="duplicateScene('${id}')">Scene複製</button><button class="danger" onclick="deleteScene('${id}')">Scene削除</button></div></div>`)}
saveSceneStage=function(id,value){const s=state.scenes.find(x=>x.id===id);if(!s)return;s.production={...(s.production||{}),status:value};s.productionStage=value;if(value==='完成')s.completionRate=100;touch(s);saveState(true);openSceneDetail(id)}
editSceneCommand=function(id){ensureSceneCommandCenterV102();const s=state.scenes.find(x=>x.id===id);const p=s.production||{},a=s.audio||{},v=s.vidu||{};modal(`<h2>Scene追加・編集</h2><p class="meta">ストーリー／映像／音／制作管理を1画面で保存します。既存の概要・メモ・Viduデータも保持します。</p><div class="scene-edit-grid"><label>シーンタイトル<input id="cmd_title" value="${esc(s.sceneTitle||s.title||'')}"></label><label>場所<input id="cmd_location" value="${esc(s.location||'')}"></label><label>制作状況<select id="cmd_stage">${sceneStatusOptions(p.status||s.productionStage)}</select></label><label>優先度<select id="cmd_priority">${scenePriorityOptions(p.priority||'中')}</select></label><label>担当<input id="cmd_assignee" value="${esc(p.assignee||'')}"></label><label>登場キャラクター<select id="cmd_chars" multiple>${characterOptions(s.relatedCharacters||[])}</select></label><label>Story Archiveカード<select id="cmd_archive" multiple>${storyArchiveOptions(s.storyArchiveCardIds)}</select></label><label>画像セット（カード/セットID）<input id="cmd_image_sets" value="${esc(sceneTextList(s.imageSetIds))}"></label><label>使用画像ID<input id="cmd_images" value="${esc(sceneTextList(s.usedImageIds))}"></label><label>使用動画ID<input id="cmd_videos" value="${esc(sceneTextList(s.usedVideoIds))}"></label><label>BGM<input id="cmd_bgm" value="${esc(a.bgm||'')}"></label><label>SE<input id="cmd_se" value="${esc(a.se||'')}"></label><label>ボイス<input id="cmd_voice" value="${esc(a.voice||'')}"></label><label>Production Dashboard連携ID<input id="cmd_dash" value="${esc(s.productionLink?.dashboardId||'')}"></label><label class="wide">シーン概要<textarea id="cmd_overview">${esc(s.sceneOverview||s.summary||'')}</textarea></label><label class="wide">シーンの目的<textarea id="cmd_purpose">${esc(s.scenePurpose||'')}</textarea></label><label class="wide">Viduプロンプト（日本語）<textarea id="cmd_vidu_ja">${esc(v.japanesePrompt||s.viduPrompt||'')}</textarea></label><label class="wide">Vidu Prompt（English）<textarea id="cmd_vidu_en">${esc(v.englishPrompt||'')}</textarea></label><label class="wide">メモ<textarea id="cmd_memo">${esc(s.memo||'')}</textarea></label></div><button class="primary-action" onclick="saveSceneCommand('${id}')">保存</button><button class="secondary" onclick="openSceneDetail('${id}')">戻る</button>`)}
saveSceneCommand=function(id){const s=state.scenes.find(x=>x.id===id);if(!s)return;const before=JSON.stringify(s);s.sceneTitle=$('#cmd_title').value;s.title=s.sceneTitle;s.location=$('#cmd_location').value;s.sceneOverview=$('#cmd_overview').value;s.summary=s.sceneOverview;s.scenePurpose=$('#cmd_purpose').value;s.purpose=s.scenePurpose;s.memo=$('#cmd_memo').value;s.production={...(s.production||{}),status:$('#cmd_stage').value,priority:$('#cmd_priority').value,assignee:$('#cmd_assignee').value,checklist:s.production?.checklist||s.doneChecklist||{}};s.productionStage=s.production.status;s.priority=s.production.priority;s.assignee=s.production.assignee;s.storyArchiveCardIds=selectedIds('cmd_archive');s.relatedCharacters=selectedIds('cmd_chars');s.characterIds=s.relatedCharacters;s.imageSetIds=sceneListFromInput('cmd_image_sets');s.usedImageIds=sceneListFromInput('cmd_images');s.usedVideoIds=sceneListFromInput('cmd_videos');s.audio={bgm:$('#cmd_bgm').value,se:$('#cmd_se').value,voice:$('#cmd_voice').value};s.vidu={...(s.vidu||{}),japanesePrompt:$('#cmd_vidu_ja').value,englishPrompt:$('#cmd_vidu_en').value};s.viduPrompt=s.vidu.japanesePrompt;s.productionLink={...(s.productionLink||{}),dashboardId:$('#cmd_dash').value,syncStatus:$('#cmd_dash').value?'ready':'local-only',schema:'scene-production-v1'};touch(s);recordHistory(s,before);saveState();openSceneDetail(id);toast('Sceneを保存しました')}
const storyCollectionViewV101=storyCollectionView;
storyCollectionView=function(collection){ensureV07Production();ensureSceneCommandCenterV102();if(collection!=='scenes')return nsOldStoryCollectionView(collection);const p=currentProject();if(!p)return requireProject(collection);const items=applyFilters(collection,projectItems(collection)).sort((a,b)=>(+a.sortOrder||0)-(+b.sortOrder||0));return `<h1>シーン：${esc(p.title)}</h1><button class="primary-action" onclick="editStoryItem('scenes')">＋ シーンを追加</button>${filterBar('scenes')}<div class="scene-list">${items.map(s=>`<article class="card scene-list-card ${s.production?.status==='完成'?'complete-scene':''}"><h3>${esc(storyTitle('scenes',s))} ${s.production?.status==='完成'?'✅':''}</h3><div class="big-progress"><span style="width:${sceneCompletionRateFull(s)}%"></span></div><p>制作状況:${esc(s.production?.status||s.productionStage)} / 優先度:${esc(s.production?.priority||'中')} / 担当:${esc(s.production?.assignee||'未設定')}<br>目的:${esc(s.scenePurpose||'未設定')}<br>登場:${esc(sceneCharactersLabel(s))}<br>${metaLine(s)}</p><button onclick="openSceneDetail('${s.id}')">制作画面を開く</button><button onclick="moveSceneOrder('${s.id}',-1)">↑</button><button onclick="moveSceneOrder('${s.id}',1)">↓</button><button onclick="duplicateScene('${s.id}')">複製</button><button class="danger" onclick="deleteScene('${s.id}')">削除</button></article>`).join('')||emptyState(collection)}</div>`}
