// Version 1.1.0 production flow integration layer
function activeScene(){const id=state.activeContext?.sceneId||state.lastLocation?.sceneId||nsOpenSceneId,s=(state.scenes||[]).find(x=>x.id===id),p=currentProject(),e=currentEpisode();return s&&(!p||s.projectId===p.id)&&(!e||s.episodeId===e.id)?s:null}
function productionFlowNav(){const s=activeScene();return `<section class="flow-guide" aria-label="制作フロー"><button onclick="setView('home')">ホーム</button><span>→</span><button onclick="setView('projects')">作品</button><span>→</span><button onclick="setView('episodes')">話数</button><span>→</span><button onclick="setView('scenes')">Scene</button><span>→</span><button onclick="openStoryArchive()">Story Archive</button><span>→</span><button onclick="openProductionDashboard()">Production Dashboard</button><span>→</span><button onclick="openApp('promptStudio')">Vidu Prompt</button><span>→</span><button ${s?'':'disabled'} onclick="${s?`openSceneDetail('${s.id}')`:''}">画像・動画管理</button><span>→</span><button ${s?'':'disabled'} onclick="${s?`openSceneDetail('${s.id}')`:''}">編集</button><span>→</span><button ${s?'':'disabled'} onclick="${s?`openSceneDetail('${s.id}')`:''}">完成</button></section>`}
const nova110Shell=shell;shell=function(main){const v=(location.hash||'#home').slice(1);nova110Shell(v==='home'?main:productionFlowNav()+main)};
function setActiveScene(sceneId){state.activeContext={...(state.activeContext||{}),sceneId,updatedAt:now()};saveState(true)}
function openLinkedScene(id){const s=(state.scenes||[]).find(x=>x.id===id);if(!s)return;selectContext(s.projectId,s.episodeId);setActiveScene(id);setView('scenes');setTimeout(()=>openSceneDetail(id),0)}
function scenesForArchiveCard(cardId){return (state.scenes||[]).filter(s=>(s.storyArchiveCardIds||[]).includes(cardId)||(s.relatedIds||[]).includes(cardId))}
function archiveBackToSceneLinks(cardId){const scenes=scenesForArchiveCard(cardId);return `<section><h3>関連Sceneへ戻る</h3>${scenes.map(s=>`<div class="row"><span>${esc(storyTitle('scenes',s))}<br><small>${esc(storyArchiveProjectName(s.projectId))} / ${esc(storyArchiveEpisodeName(s.episodeId))}</small></span><button onclick="openLinkedScene('${s.id}')">Sceneを開く</button></div>`).join('')||'<p class="meta">関連Sceneはまだありません。</p>'}</section>`}
const nova110OpenStoryArchiveDetail=openStoryArchiveDetail;openStoryArchiveDetail=function(id,mode='all'){nova110OpenStoryArchiveDetail(id,mode);const body=$('#modalBody');if(body)body.insertAdjacentHTML('beforeend',archiveBackToSceneLinks(id))};
const nova110OpenSceneDetail=openSceneDetail;openSceneDetail=function(id){setActiveScene(id);nova110OpenSceneDetail(id);const s=(state.scenes||[]).find(x=>x.id===id),body=$('#modalBody');if(!s||!body)return;body.querySelector('.scene-actions')?.insertAdjacentHTML('afterbegin',`<button class="primary-action" onclick="openProductionDashboardForScene('${id}')">Production Dashboardで開く</button><button class="secondary" onclick="setView('consult');setTimeout(genConsult,0)">ノヴァに相談</button>`)};
function openProductionDashboardForScene(sceneId){const s=(state.scenes||[]).find(x=>x.id===sceneId);if(s){selectContext(s.projectId,s.episodeId);setActiveScene(sceneId)}openProductionDashboard()}
const nova110BuildAppUrl=buildAppUrl;buildAppUrl=function(app){const url=nova110BuildAppUrl(app);try{const u=new URL(url||app.url,location.href),s=activeScene();if(s?.id)u.searchParams.set('scene',s.id);const cards=s?sceneArchiveCards(s).map(c=>c.id):[];if(cards.length)u.searchParams.set('storyArchiveCards',cards.join(','));return u.toString()}catch{return url}};
const nova110SelectContext=selectContext;selectContext=function(projectId,episodeId){state.activeContext={...(state.activeContext||{}),sceneId:''};nova110SelectContext(projectId,episodeId)};
const nova110StoryCollectionView=storyCollectionView;storyCollectionView=function(collection){const html=nova110StoryCollectionView(collection);if(collection!=='scenes')return html;return html.replace(/<button onclick="openSceneDetail\('([^']+)'\)">制作画面を開く<\/button>/g,(m,id)=>`${m}<button class="secondary" onclick="openProductionDashboardForScene('${id}')">Dashboard</button>`)};
const nova110ConsultView=consultView;consultView=function(){return nova110ConsultView()+`<section class="context-carry"><h2>自動引き継ぎコンテキスト</h2><pre>${esc(makeConsultText('現在の制作フローを相談',''))}</pre></section>`};
const nova110MakeConsultText=makeConsultText;makeConsultText=function(type,body){const s=activeScene(),archive=s?sceneArchiveCards(s):[];return nova110MakeConsultText(type,body)+`\n\n現在のScene：${s?storyTitle('scenes',s):''}\nScene ID：${s?.id||''}\nScene制作状況：${s?.production?.status||s?.productionStage||''}\n関連Story Archive：\n${archive.map(c=>`- ${c.title||c.id}（${c.id} / ${c.category||''}）`).join('\n')||'- なし'}\n\n制作フロー：ホーム → 作品 → 話数 → Scene → Story Archive → Production Dashboard → Vidu Prompt → 画像・動画管理 → 編集 → 完成`};
render();

// Version 1.1.1 ChatGPT JSON bulk import for Story Archive.
let chatGptArchiveImportDraft={raw:'',plan:null};
function chatGptImportCategory(value){const s=String(value||'').trim();const aliases={キャラ:'キャラクター',人物:'キャラクター',世界:'世界観',ロケーション:'場所',地名:'場所',設定:'概要',あらすじ:'ストーリー',物語:'ストーリー',道具:'アイテム'};const cat=aliases[s]||s;return STORY_ARCHIVE_V1_CATEGORIES.includes(cat)?cat:(STORY_ARCHIVE_CATEGORIES.includes(cat)?cat:'概要')}
function chatGptFindProject(title){return (state.projects||[]).find(p=>p.title===title||p.id===title)}
function chatGptFindEpisode(title,projectId){return (state.episodes||[]).find(e=>(!projectId||e.projectId===projectId)&&(e.numberLabel===title||e.title===title||e.subtitle===title||e.id===title))}
function chatGptFindArchiveByTitle(title,projectId,episodeId){return (state.storyArchiveCards||[]).find(c=>String(c.title||'').trim()===String(title||'').trim()&&(!projectId||c.projectId===projectId)&&(!episodeId||c.episodeId===episodeId))}
function chatGptRelatedInput(card){return [...(Array.isArray(card.relatedIds)?card.relatedIds:parseTags(card.relatedIds)),...(Array.isArray(card.relatedTitles)?card.relatedTitles:parseTags(card.relatedTitles)),...(Array.isArray(card.related)?card.related:parseTags(card.related))].filter(Boolean)}
function chatGptBuildImportPlan(raw,defaultAction='new'){let obj,errors=[];try{obj=JSON.parse(raw)}catch(e){return {valid:false,errors:[{index:'JSON',message:'JSONの構文を確認してください：'+e.message}],items:[]}};if(!obj||typeof obj!=='object')errors.push({index:'JSON',message:'ルートはオブジェクトにしてください'});if(!Array.isArray(obj?.cards))errors.push({index:'cards',message:'cards配列がありません'});const projectTitle=String(obj?.project?.title||currentProject()?.title||'').trim();const episodeTitle=String(obj?.episode?.title||currentEpisode()?.numberLabel||'').trim();const existingProject=chatGptFindProject(projectTitle);const projectId=existingProject?.id||uid('project');const existingEpisode=chatGptFindEpisode(episodeTitle,projectId);const episodeId=existingEpisode?.id||uid('episode');const seenTitles=new Set();const items=(obj.cards||[]).map((rawCard,index)=>{const rowErrors=[];const title=String(rawCard?.title||'').trim();if(!title)rowErrors.push('titleが空です');if(title&&seenTitles.has(title))rowErrors.push('同じJSON内に同名カードがあります');seenTitles.add(title);const category=chatGptImportCategory(rawCard?.category);const status=STORY_ARCHIVE_STATUSES.includes(rawCard?.status)?rawCard.status:(ITEM_STATUSES.includes(rawCard?.status)?rawCard.status:'仮設定');const duplicate=title?chatGptFindArchiveByTitle(title,projectId,episodeId):null;const action=duplicate?defaultAction:'new';return {index:index+1,raw:rawCard,title:title||`無題 ${index+1}`,category,status,body:String(rawCard?.body||rawCard?.content||rawCard?.memo||''),tags:Array.isArray(rawCard?.tags)?rawCard.tags:parseTags(rawCard?.tags),relatedInputs:chatGptRelatedInput(rawCard),duplicateId:duplicate?.id||'',action,errors:rowErrors}});items.forEach(item=>{item.relatedResolved=item.relatedInputs.map(x=>{const byId=(state.storyArchiveCards||[]).find(c=>c.id===x)||items.find(i=>i.raw?.id===x);const byTitle=(state.storyArchiveCards||[]).find(c=>c.title===x&&(!projectId||c.projectId===projectId))||items.find(i=>i.title===x);const found=byId||byTitle;return {input:x,id:found?.id||found?.raw?.id||'',title:found?.title||x,found:Boolean(found)}});item.errors.push(...item.relatedResolved.filter(r=>!r.found).map(r=>`関連カード「${r.input}」が見つかりません`))});return {valid:!errors.length&&!items.some(i=>i.errors.length),errors,items,project:{title:projectTitle,id:projectId,exists:Boolean(existingProject)},episode:{title:episodeTitle,id:episodeId,exists:Boolean(existingEpisode)},schemaVersion:obj.schemaVersion||'',defaultAction}}
function openChatGptArchiveImport(){chatGptArchiveImportDraft={raw:chatGptArchiveImportDraft.raw||'',plan:null};modal(`<h2>ChatGPT JSON一括登録</h2><p class="meta">ChatGPTが作成したNova Studio取込用JSONを貼り付けます。反映前に追加・更新内容を確認し、実行前に自動バックアップを書き出します。既存カードは削除しません。</p><label>取込用JSON<textarea id="chatGptArchiveJson" rows="14" placeholder='{"schemaVersion":"1.0","project":{"title":"作品名"},"episode":{"title":"第0話"},"cards":[...]}' oninput="chatGptArchiveImportDraft.raw=this.value">${esc(chatGptArchiveImportDraft.raw||'')}</textarea></label><label>同名カードがある場合<select id="chatGptImportDefaultAction"><option value="new">新規作成</option><option value="update">更新</option><option value="skip">スキップ</option></select></label><button class="primary-action" onclick="previewChatGptArchiveImport()">内容を確認</button><button class="secondary" onclick="closeModal()">閉じる</button>`)}
function previewChatGptArchiveImport(){const raw=$('#chatGptArchiveJson')?.value||'';const action=$('#chatGptImportDefaultAction')?.value||'new';const plan=chatGptBuildImportPlan(raw,action);chatGptArchiveImportDraft={raw,plan};const globalErrors=plan.errors.map(e=>`<li>${esc(e.index)}：${esc(e.message)}</li>`).join('');modal(`<h2>一括登録プレビュー</h2><p class="meta">作品：${esc(plan.project?.title||'未設定')}（${plan.project?.exists?'既存':'新規作成'}） / 話数：${esc(plan.episode?.title||'未設定')}（${plan.episode?.exists?'既存':'新規作成'}） / schemaVersion：${esc(plan.schemaVersion||'')}</p>${globalErrors?`<div class="import-error"><b>JSON全体のエラー</b><ul>${globalErrors}</ul></div>`:''}<div class="bulk-import-list">${(plan.items||[]).map(item=>chatGptImportPreviewRow(item)).join('')||'<p class="empty-note">カードがありません。</p>'}</div><p class="meta">エラーがある項目は実行前に修正してください。関連カードはIDまたはタイトルで自動リンクします。</p><button class="primary-action" ${plan.valid?'':'disabled'} onclick="applyChatGptArchiveImport()">自動バックアップして反映</button><button class="secondary" onclick="openChatGptArchiveImport()">戻って修正</button>`)}
function chatGptImportPreviewRow(item){const errors=item.errors.map(e=>`<li>${esc(e)}</li>`).join('');const rel=item.relatedResolved.map(r=>`<span class="tag ${r.found?'':'import-missing'}">${esc(r.title)}${r.found?'':' ⚠'}</span>`).join('')||'<span class="meta">関連なし</span>';return `<article class="bulk-import-row ${errors?'has-error':''}"><div><b>${esc(item.index)}. ${esc(item.title)}</b><p class="meta">${esc(item.category)} / 状態：${esc(item.status)} / ${item.duplicateId?'同名あり：'+esc(item.duplicateId):'新規候補'}</p></div><label>処理<select onchange="chatGptSetImportAction(${item.index},this.value)" ${item.duplicateId?'':'disabled'}><option value="new" ${item.action==='new'?'selected':''}>新規作成</option><option value="update" ${item.action==='update'?'selected':''}>更新</option><option value="skip" ${item.action==='skip'?'selected':''}>スキップ</option></select></label><p>${esc(item.body).slice(0,180)}</p><div>${rel}</div>${errors?`<div class="import-error"><b>この項目のエラー</b><ul>${errors}</ul></div>`:''}</article>`}
function chatGptSetImportAction(index,action){const item=chatGptArchiveImportDraft.plan?.items?.find(i=>i.index===index);if(item)item.action=action}
function chatGptEnsureProjectEpisode(plan){let p=state.projects.find(x=>x.id===plan.project.id)||chatGptFindProject(plan.project.title);if(!p){p=project(plan.project.id,plan.project.title||'無題作品',(state.projects||[]).length+1);state.projects.push(p)}let e=state.episodes.find(x=>x.id===plan.episode.id)||chatGptFindEpisode(plan.episode.title,p.id);if(!e){e=episode(plan.episode.id,p.id,plan.episode.title||'未分類',(state.episodes||[]).filter(x=>x.projectId===p.id).length+1);state.episodes.push(e)}return {p,e}}
function applyChatGptArchiveImport(){const plan=chatGptArchiveImportDraft.plan;if(!plan||!plan.valid)return toast('エラーがあるため反映できません');exportBackup(true);const {p,e}=chatGptEnsureProjectEpisode(plan);const idByTitle=new Map((state.storyArchiveCards||[]).map(c=>[c.title,c.id]));let added=0,updated=0,skipped=0;plan.items.forEach(item=>{if(item.action==='skip'){skipped++;return}const current=item.duplicateId?getStoryArchiveCard(item.duplicateId):null;const id=item.action==='update'&&current?current.id:(item.raw.id||uid('archive'));idByTitle.set(item.title,id)});plan.items.forEach(item=>{if(item.action==='skip'){return}const current=item.action==='update'&&item.duplicateId?getStoryArchiveCard(item.duplicateId):null;const relatedIds=item.relatedResolved.map(r=>r.id||idByTitle.get(r.input)||idByTitle.get(r.title)).filter(Boolean);const card=normalizeStoryArchiveCardV1({...(current||{}),id:current?.id||item.raw.id||idByTitle.get(item.title)||uid('archive'),title:item.title,body:item.body,category:item.category,templateCategory:item.category,status:item.status,isConfirmed:item.status==='確定',tags:item.tags,projectId:p.id,episodeId:e.id,relatedIds:[...new Set(relatedIds)],createdAt:current?.createdAt||now(),updatedAt:now(),templateData:current?.templateData||{},changeLog:current?.changeLog||[],images:current?.images||[],imageSets:current?.imageSets||[]});saveNormalizedArchiveCard(card);archiveSyncBacklinks(card.id,card.relatedIds);current?updated++:added++});selectContext(p.id,e.id);state.backupStatus.lastImportedAt=now();state.importCenter.history.unshift({id:uid('import'),importedAt:now(),fileName:'ChatGPT Story Archive JSON',kind:`追加${added}件 / 更新${updated}件 / スキップ${skipped}件`});saveState(true);closeModal();render();toast(`一括登録完了：追加${added}件、更新${updated}件、スキップ${skipped}件`)}
