// Version 1.2.4 Memory Sync stage 1: safe JSON import, diff review, decisions, backups, and history.
const MEMORY_SYNC_CATEGORIES=['概要','世界観','キャラクター','場所','用語','アイテム','ストーリー','タイムライン','アイデア','没案'];
const MEMORY_SYNC_STATUSES=['相談中','提案','確定','保留','没'];
let memorySyncDraft={raw:'',plan:null};
function ensureMemorySyncState(){state.memorySync=state.memorySync||{};state.memorySync.history=Array.isArray(state.memorySync.history)?state.memorySync.history:[];state.memorySync.backups=Array.isArray(state.memorySync.backups)?state.memorySync.backups:[];return state.memorySync}
function memorySyncInitConstants(){MEMORY_SYNC_STATUSES.forEach(s=>{if(!STORY_ARCHIVE_STATUSES.includes(s))STORY_ARCHIVE_STATUSES.push(s);if(!ITEM_STATUSES.includes(s))ITEM_STATUSES.push(s)});MEMORY_SYNC_CATEGORIES.forEach(c=>{if(!STORY_ARCHIVE_CATEGORIES.includes(c))STORY_ARCHIVE_CATEGORIES.push(c);if(typeof STORY_ARCHIVE_V1_CATEGORIES!=='undefined'&&!STORY_ARCHIVE_V1_CATEGORIES.includes(c))STORY_ARCHIVE_V1_CATEGORIES.push(c)})}
function memorySyncCategory(v){const s=String(v||'').trim();const aliases={時系列:'タイムライン',年表:'タイムライン',キャラ:'キャラクター',人物:'キャラクター',ロケーション:'場所',地名:'場所',世界:'世界観',道具:'アイテム',ボツ:'没案'};const c=aliases[s]||s;return MEMORY_SYNC_CATEGORIES.includes(c)?c:(STORY_ARCHIVE_CATEGORIES.includes(c)?c:'概要')}
function memorySyncStatus(v){const s=String(v||'').trim();const aliases={検討中:'相談中',仮設定:'提案',要確認:'相談中',採用:'確定'};return MEMORY_SYNC_STATUSES.includes(aliases[s]||s)?(aliases[s]||s):'提案'}
function memorySyncParse(raw){const obj=typeof raw==='string'?JSON.parse(raw):raw;if(!obj||typeof obj!=='object')throw Error('JSONのルートはオブジェクトにしてください');if(!Array.isArray(obj.projects))throw Error('projects配列がありません');return obj}
function memorySyncFindProject(title){return (state.projects||[]).find(p=>p.title===title||p.id===title)}
function memorySyncFindEpisode(title,projectId){return (state.episodes||[]).find(e=>(!projectId||e.projectId===projectId)&&(e.numberLabel===title||e.title===title||e.subtitle===title||e.id===title))}
function memorySyncFindMatches(card,projectId,episodeId){const cards=state.storyArchiveCards||[];if(card.id){const byId=cards.find(c=>c.id===card.id);if(byId)return [byId]}const title=String(card.title||'').trim(),cat=memorySyncCategory(card.category);return cards.filter(c=>c.projectId===projectId&&(!episodeId||c.episodeId===episodeId)&&c.category===cat&&String(c.title||'').trim()===title)}
function memorySyncFieldMap(card){return {...(card.fields||{}),body:card.body||'',status:memorySyncStatus(card.status),category:memorySyncCategory(card.category),tags:Array.isArray(card.tags)?card.tags:[],images:Array.isArray(card.images)?card.images:[]}}
function memorySyncComparable(card){return memorySyncFieldMap(card)}
function memorySyncDiff(current,card){const incoming=memorySyncComparable(card),cur=current?{...(current.templateData||{}),body:current.body||'',status:current.status||'',category:current.category||'',tags:current.tags||[],images:current.images||[]}:{};return Object.keys(incoming).map(k=>({field:k,before:JSON.stringify(cur[k]??''),after:JSON.stringify(incoming[k]??'')})).filter(d=>d.before!==d.after)}
function buildMemorySyncPlan(raw){let obj;try{obj=memorySyncParse(raw)}catch(e){return{valid:false,error:e.message,items:[],raw}}const items=[];obj.projects.forEach((p,pi)=>{const projectTitle=String(p.title||`作品 ${pi+1}`).trim(),project=memorySyncFindProject(projectTitle),projectId=project?.id||uid('project');(p.episodes||[{title:'作品全体',cards:p.cards||[]}]).forEach((ep,ei)=>{const episodeTitle=String(ep.title||ep.numberLabel||`話数 ${ei+1}`).trim(),episode=memorySyncFindEpisode(episodeTitle,projectId),episodeId=episode?.id||uid('episode');(ep.cards||[]).forEach((card,ci)=>{const title=String(card.title||`無題 ${ci+1}`).trim(),matches=memorySyncFindMatches(card,projectId,episodeId),current=matches.length===1?matches[0]:null,diffs=memorySyncDiff(current,card);const kind=matches.length>1?'conflict':(!current?'add':(diffs.length?'update':'same'));items.push({id:uid('msitem'),projectTitle,projectId,projectExists:!!project,episodeTitle,episodeId,episodeExists:!!episode,index:ci+1,raw:card,title,category:memorySyncCategory(card.category),status:memorySyncStatus(card.status),currentId:current?.id||'',matchIds:matches.map(x=>x.id),kind,diffs,decision:kind==='same'?'skip':'adopt'});})})});return{valid:true,schemaVersion:obj.schemaVersion||'',syncId:obj.syncId||uid('memorySync'),createdAt:obj.createdAt||now(),items,raw}}
function openMemorySync(){ensureMemorySyncState();modal(`<h2>Memory Sync（メモリー同期）</h2><p class="meta">ChatGPTが作成したJSONを取り込み、現在のStory Archiveカードとの差分を確認してから反映します。第1段階では削除は行いません。</p><label>Memory Sync用JSON<textarea id="memorySyncJson" rows="14" placeholder='{"schemaVersion":"2.0","projects":[...]}' oninput="memorySyncDraft.raw=this.value">${esc(memorySyncDraft.raw||'')}</textarea></label><label class="file">JSONファイルを読み込む<input type="file" accept="application/json,.json" onchange="memorySyncReadFile(this.files[0])"></label><button class="primary-action" onclick="previewMemorySync()">差分を確認</button><button class="secondary" onclick="closeModal()">閉じる</button>`)}
function memorySyncReadFile(file){if(!file)return;const r=new FileReader();r.onload=()=>{memorySyncDraft.raw=String(r.result||'');openMemorySync();toast('JSONファイルを読み込みました')};r.onerror=()=>toast('JSONファイルの読み込みに失敗しました');r.readAsText(file)}
function previewMemorySync(){const raw=$('#memorySyncJson')?.value||memorySyncDraft.raw||'',plan=buildMemorySyncPlan(raw);memorySyncDraft={raw,plan};if(!plan.valid)return modal(`<h2>Memory Sync エラー</h2><div class="import-error">${esc(plan.error)}</div><button onclick="openMemorySync()">戻る</button>`);modal(memorySyncPreviewHtml(plan))}
function memorySyncPreviewHtml(plan){const groups=['add','update','same','conflict','delete'].map(k=>[k,plan.items.filter(i=>i.kind===k)]);return `<h2>Memory Sync 差分確認</h2><p class="meta">syncId：${esc(plan.syncId)} / schemaVersion：${esc(plan.schemaVersion)} / 対象：${plan.items.length}件。項目ごとに採用・保留・スキップを選べます。</p>${groups.map(([k,items])=>`<section class="memory-sync-group"><h3>${esc(memorySyncKindLabel(k))} ${items.length}件</h3>${items.map(memorySyncRowHtml).join('')||'<p class="empty-note">なし</p>'}</section>`).join('')}<button class="primary-action" onclick="applyMemorySync()">自動バックアップして反映</button><button class="secondary" onclick="openMemorySync()">戻って修正</button>`}
function memorySyncKindLabel(k){return {add:'追加',update:'更新',same:'変更なし',conflict:'競合',delete:'削除候補'}[k]||k}
function memorySyncRowHtml(item){const diffs=item.diffs.map(d=>`<tr><td>${esc(d.field)}</td><td>${esc(d.before)}</td><td>${esc(d.after)}</td></tr>`).join('')||'<tr><td colspan="3">差分なし</td></tr>';return `<article class="memory-sync-row ${item.kind}"><div class="section-head"><div><b>${esc(item.category)}：${esc(item.title)}</b><p class="meta">${esc(item.projectTitle)} / ${esc(item.episodeTitle)} / ${memorySyncKindLabel(item.kind)}${item.matchIds.length>1?' / 同名候補：'+esc(item.matchIds.join(', ')):''}</p></div><label>判断<select onchange="memorySyncSetDecision('${item.id}',this.value)"><option value="adopt" ${item.decision==='adopt'?'selected':''}>採用</option><option value="hold" ${item.decision==='hold'?'selected':''}>保留</option><option value="skip" ${item.decision==='skip'?'selected':''}>スキップ</option></select></label></div><table class="memory-sync-diff"><thead><tr><th>項目</th><th>現在</th><th>変更後</th></tr></thead><tbody>${diffs}</tbody></table></article>`}
function memorySyncSetDecision(id,decision){const item=memorySyncDraft.plan?.items?.find(x=>x.id===id);if(item)item.decision=decision}
function memorySyncBackup(raw){ensureMemorySyncState();const b={id:uid('memoryBackup'),createdAt:now(),data:JSON.parse(JSON.stringify(state))};try{localStorage.setItem(`${STORAGE_KEY}_memory_sync_backup_${b.id}`,JSON.stringify(b))}catch(e){toast('自動バックアップ保存に失敗しました。localStorage容量を確認してください');throw e}state.memorySync.backups.unshift({id:b.id,createdAt:b.createdAt});state.memorySync.backups=state.memorySync.backups.slice(0,20);return b.id}
function memorySyncEnsureProjectEpisode(item){let p=state.projects.find(x=>x.id===item.projectId)||memorySyncFindProject(item.projectTitle);if(!p){p=project(item.projectId,item.projectTitle,(state.projects||[]).length+1);state.projects.push(p)}let e=state.episodes.find(x=>x.id===item.episodeId)||memorySyncFindEpisode(item.episodeTitle,p.id);if(!e){e=episode(item.episodeId,p.id,item.episodeTitle,(state.episodes||[]).filter(x=>x.projectId===p.id).length+1);state.episodes.push(e)}return{p,e}}
function applyMemorySync(){const plan=memorySyncDraft.plan;if(!plan?.valid)return toast('先に差分を確認してください');let backupId;try{backupId=memorySyncBackup(plan.raw)}catch(e){return}let added=0,updated=0,held=0,skipped=0;plan.items.forEach(item=>{if(item.decision==='hold'){held++;return}if(item.decision==='skip'||item.kind==='same'||item.kind==='conflict'){skipped++;return}const {p,e}=memorySyncEnsureProjectEpisode(item),current=item.currentId?getStoryArchiveCard(item.currentId):null,fields=memorySyncFieldMap(item.raw);const card=normalizeStoryArchiveCardV1({...(current||{}),id:current?.id||item.raw.id||uid('archive'),title:item.title,category:item.category,templateCategory:item.category,status:item.status,isConfirmed:item.status==='確定',projectId:p.id,episodeId:e.id,body:fields.body,tags:fields.tags,templateData:{...(current?.templateData||{}),...(item.raw.fields||{})},images:fields.images,createdAt:current?.createdAt||now(),updatedAt:now()});saveNormalizedArchiveCard(card);current?updated++:added++});ensureMemorySyncState().history.unshift({id:uid('memorySync'),syncId:plan.syncId,appliedAt:now(),projectTitles:[...new Set(plan.items.map(i=>i.projectTitle))],episodeTitles:[...new Set(plan.items.map(i=>i.episodeTitle))],added,updated,held,skipped,backupId,importedJson:plan.raw});state.memorySync.history=state.memorySync.history.slice(0,50);state.backupStatus.lastImportedAt=now();saveState(true);closeModal();render();toast(`Memory Sync完了：追加${added}件、更新${updated}件、保留${held}件`)}
function memorySyncHistoryRows(){const h=ensureMemorySyncState().history;return h.map(x=>`<div class="row"><span><b>${esc(x.appliedAt)}</b><br><small>作品：${esc((x.projectTitles||[]).join(', '))} / 話数：${esc((x.episodeTitles||[]).join(', '))} / 追加${x.added} 更新${x.updated} 保留${x.held} / backup:${esc(x.backupId)}</small></span></div>`).join('')||'<p class="empty-note">Memory Sync履歴はまだありません。</p>'}
const memorySyncOldStoryArchiveView=storyArchiveView;
storyArchiveView=function(){memorySyncInitConstants();const html=memorySyncOldStoryArchiveView();return html.replace('<button class="primary-action" onclick="editStoryArchiveCard()">＋カード作成</button>','<button class="primary-action" onclick="editStoryArchiveCard()">＋カード作成</button><button class="secondary" onclick="openMemorySync()">Memory Sync</button>')+`<section><h2>Memory Sync履歴</h2>${memorySyncHistoryRows()}</section>`}
const memorySyncOldConsultView=consultView;
consultView=function(){return memorySyncOldConsultView()+`<section class="memory-sync-consult"><h2>Memory Sync連携</h2><button onclick="copyMemorySyncJson(false)">Memory Sync用JSONとしてコピー</button><button onclick="openMemorySync()">ChatGPTから戻す</button><button onclick="openMemorySync()">差分を確認</button><label><input type="checkbox" id="memorySyncIncludeDraft">相談中の設定も含める</label><button onclick="copyMemorySyncJson(!$('#memorySyncIncludeDraft')?.checked)">確定設定だけ送る</button></section>`}
function copyMemorySyncJson(confirmedOnly=false){const cards=(state.storyArchiveCards||[]).filter(c=>!confirmedOnly||c.status==='確定');const p=currentProject(),e=currentEpisode();const obj={schemaVersion:'2.0',syncId:uid('memorySyncExport'),createdAt:new Date().toISOString(),projects:[{title:p?.title||'',episodes:[{title:e?.numberLabel||'',cards:cards.filter(c=>(!p||c.projectId===p.id)&&(!e||!c.episodeId||c.episodeId===e.id)).map(c=>({id:c.id,title:c.title,category:c.category,status:c.status,fields:c.templateData||{},body:c.body||'',tags:c.tags||[],relatedTitles:[],images:c.images||[]}))}]}]};const text=JSON.stringify(obj,null,2);navigator.clipboard?.writeText(text).then(()=>toast('Memory Sync用JSONをコピーしました')).catch(()=>{modal(`<h2>Memory Sync用JSON</h2><textarea rows="18" readonly>${esc(text)}</textarea>`)});}
memorySyncInitConstants();ensureMemorySyncState();render();

// Version 0.2.9 requested final override: keep the Story Archive image-first UI active after later integrations.
function archiveDetailBasicSection(card){
  const folder=(state.storyArchiveFolders||[]).find(f=>f.id===card.folderId)?.name||'未分類';
  return `<section><h3>基本設定・本文</h3><p><span class="type-pill">${esc(card.category||'未分類')}</span> <b>状態：</b>${esc(card.status||'仮設定')} / <b>確定：</b>${card.isConfirmed?'はい':'いいえ'} / <b>フォルダ：</b>${esc(folder)} / <b>時系列：</b>${esc(card.timelineAt||'未設定')}</p><p>${esc(card.body||'本文は未入力です。')}</p>${typeof archiveV1TemplateForm==='function'?archiveV1TemplateForm({...card,templateData:card.templateData||{}}).replaceAll('<textarea','<textarea readonly'):''}</section>`;
}
function archiveDetailGallerySection(card,mode='all'){
  return `<section class="archive-gallery-panel"><div class="section-head"><div><h3>画像ギャラリー</h3><p class="meta">画像を押すと大きな表示で確認できます。フィルターで正式採用、Vidu参照、種類、角度、状態、画像セット、旧案、没案を絞り込めます。</p></div><div class="archive-image-actions"><button class="primary-action" onclick="editArchiveImage('${card.id}')">画像追加</button><button class="secondary" onclick="editArchiveImageSet('${card.id}')">画像セット管理</button></div></div><div class="gallery-tabs">${archiveGalleryTabs(card.id)}<button class="vidu-one-tap" onclick="openArchiveViduReferences()">全カードのVidu参照</button></div>${mode==='set'?'':archiveImageControls(card,mode)}<div class="archive-bulk-bar"><button class="secondary" onclick="document.querySelectorAll('[data-archive-image-select=&quot;${card.id}&quot;]').forEach(x=>x.checked=true)">全選択</button><button class="secondary" onclick="document.querySelectorAll('[data-archive-image-select=&quot;${card.id}&quot;]').forEach(x=>x.checked=false)">選択解除</button><button class="primary-action" onclick="openArchiveBulkEdit('${card.id}')">選択画像を一括編集</button></div><div id="archiveImageResults_${card.id}">${['type','angle','state'].includes(mode)?archiveGroupedGallery(card,mode):archiveImageGallery(card,mode)}</div>${archiveImageDropZone(card.id)}</section>`;
}
openStoryArchiveDetail=function(id,mode='all'){
  const card=normalizeStoryArchiveCardV1(getStoryArchiveCard(id));if(!card)return;
  modal(`<article class="archive-detail"><h2>${esc(card.title)}</h2>${archiveRepresentativeHero(card)}${archiveDetailGallerySection(card,mode)}${archiveDetailBasicSection(card)}<section><h3>関連カード</h3>${archiveRelatedLinks(card)}</section>${archiveManagementDetails(card)}<button onclick="editStoryArchiveCard('${id}')">カード編集</button><button class="secondary" onclick="closeModal()">閉じる</button></article>`);
};
storyArchiveView=function(){
  memorySyncInitConstants?.();
  const cards=storyArchiveCards().map(normalizeStoryArchiveCardV1),q=($('#archiveSearch')?.value||'').toLowerCase();
  const filtered=q?cards.filter(c=>[c.title,c.category,c.status,c.updatedAt,c.timelineAt,(c.tags||[]).join(' '),archiveRelatedIds(c).map(id=>getStoryArchiveCard(id)?.title||'').join(' ')].join(' ').toLowerCase().includes(q)):cards;
  const byCat=Object.groupBy?Object.groupBy(filtered,c=>c.category||'未分類'):filtered.reduce((a,c)=>((a[c.category||'未分類']=a[c.category||'未分類']||[]).push(c),a),{});
  return `<section class="hero archive-hero"><h1>Story Archive</h1><p>制作資料を画像中心に確認するカード一覧です。 <span class="ver">Version ${NOVA_VERSION}</span></p><div class="archive-hero-actions"><button class="primary-action" onclick="editStoryArchiveCard()">＋カード作成</button><button class="secondary" onclick="openMemorySync()">Memory Sync</button><button class="secondary vidu-one-tap" onclick="openArchiveViduReferences()">Vidu参照画像だけ表示（${archiveViduReferenceImages().length}）</button></div><input id="archiveSearch" placeholder="タイトル・カテゴリ・状態・タグ・関連カードを検索" value="${esc($('#archiveSearch')?.value||'')}" oninput="render()"></section><section><div class="archive-category-grid image-first-archive-grid">${archiveListCategories(filtered).map(cat=>`<article class="archive-category image-first-category"><h3>${esc(cat)} <span class="meta">${(byCat[cat]||[]).length}件</span></h3>${(byCat[cat]||[]).map(c=>`<article class="archive-card image-first-card" role="button" tabindex="0" onclick="openStoryArchiveDetail('${c.id}')" onkeydown="if(event.key==='Enter'||event.key===' ')openStoryArchiveDetail('${c.id}')">${archiveCardListImage(c)}${archiveCardListMeta(c)}<div class="archive-card-actions"><button onclick="event.stopPropagation();editStoryArchiveCard('${c.id}')">編集</button><button class="danger" onclick="event.stopPropagation();deleteStoryArchiveCard('${c.id}')">削除</button></div></article>`).join('')||'<p class="empty-note">カードなし</p>'}</article>`).join('')}</div></section><section><h2>Memory Sync履歴</h2>${memorySyncHistoryRows()}</section>`;
};
render();

/* Version 1.2.5 Nova atelier home redesign */
function novaOrbIcon(cls=''){
  return `<span class="nova-orb-icon ${cls}" aria-hidden="true"><span></span></span>`;
}
function novaLineIcon(name){return `<span class="line-icon ${name}" aria-hidden="true"></span>`}
function homeAppAction(id,title,desc,action,variant=''){
  return `<article class="home-studio-card ${variant}" role="button" tabindex="0" onclick="${action}" onkeydown="if(event.key==='Enter'||event.key===' ')${action}"><div class="home-studio-icon">${id==='consult'?novaOrbIcon('small'):novaLineIcon(id)}</div><div><h3>${esc(title)}</h3><p>${esc(desc)}</p></div><button class="secondary" onclick="event.stopPropagation();${action}">開く</button></article>`;
}
function homeFeaturedEpisode(p,e){
  return state.episodes.find(x=>x.projectId===p?.id&&x.numberLabel==='第0話')||e;
}
function openFeaturedEpisode(){
  const p=currentProject(),e=homeFeaturedEpisode(p,currentEpisode());
  if(p?.id&&e?.id)selectContext(p.id,e.id);
  openLastLocation();
}
function currentProductionInfo(p,e){
  const featured=homeFeaturedEpisode(p,e),episodeLabel=featured?.numberLabel||'話数未選択';
  return `<section class="home-current-production" aria-label="第0話 制作中"><p>ティア・ノヴァのAIアニメ制作日誌</p><h2>${esc(episodeLabel)} 制作中</h2></section>`;
}
function backupSettingsCard(){
  return `<section class="home-footer-actions" aria-label="管理"><button class="link-action" onclick="setView('settings')">設定</button><button class="link-action" onclick="setView('backup')">バックアップ</button></section>`;
}
function homeView(){
  const p=currentProject(),e=currentEpisode();
  return `<div class="home-minimal"><section class="nova-guide" aria-label="ノヴァの案内"><div class="nova-portrait">${novaOrbIcon('large')}</div><div class="nova-message"><p class="nova-quote">「おかえり、ティア。<br>今日は第0話の続きを作る？」</p></div></section>${currentProductionInfo(p,e)}<section class="home-studio-main" role="button" tabindex="0" onclick="openFeaturedEpisode()" onkeydown="if(event.key==='Enter'||event.key===' ')openFeaturedEpisode()"><h2>続きを作る</h2></section><section class="nova-consult-card" role="button" tabindex="0" onclick="setView('consult')" onkeydown="if(event.key==='Enter'||event.key===' ')setView('consult')"><h2>💙 ノヴァに相談</h2></section><section class="home-studio-stack" aria-label="制作機能">${homeAppAction('story','Story Archive','','openStoryArchive()','priority')}${homeAppAction('dashboard','Production Dashboard','','openProductionDashboard()')}${homeAppAction('prompt','Prompt Studio','',"openApp('promptStudio')")}${homeAppAction('universe','Universe','',"setView('universe')")}${homeAppAction('import','Import Center','',"setView('importCenter')")}</section>${backupSettingsCard()}</div>`;
}
const nova125ShellBase=shell;
shell=function(main){
  nova125ShellBase(main);
  document.querySelectorAll('header button, nav button, .bottom button').forEach(b=>{b.innerHTML=b.innerHTML.replace(/[💬💾⚙🏠🧰🗂📚🎬🎞👤🌍📖🕰💡🔎📝🌌✅📈🎥]/gu,'').trim()});
  document.querySelectorAll('button[onclick="setView(\'consult\')"]').forEach(b=>{if(!b.closest('.nova-consult-card'))b.innerHTML=`${novaOrbIcon('tiny')}<span>ノヴァ</span>`});
};
const nova125RenderBase=render;
render=function(){const v=(location.hash||'#home').slice(1);if(v==='home')return shell(homeView());nova125RenderBase()};
render();

/* Version 1.2.6 official character atelier home */
const HOME_CHARACTER_IMAGE_PATHS={
  logo:'./assets/images/home/NovaStudio_Logo_Film.png',
  background:'./assets/images/home/glass_fantasy_ui_background.jpg',
  novaHappy:'./assets/images/home/Nova_Happy.png',
  tiaWelcome:'./assets/images/home/Tia_Chibi_Welcome.png',
  tiaThinking:'./assets/images/home/Tia_Chibi_Thinking.png',
  storyArchive:'./assets/images/home/Nova_Thinking.png',
  productionDashboard:'./assets/images/home/Nova_Stand.png',
  promptStudio:'./assets/images/home/Nova_Sparkle.png',
  musicStudio:'./assets/images/home/Nova_Joy.png',
  universe:'./assets/images/home/Nova_Flying.png'
};
const HOME_CHARACTER_FALLBACK_PATHS={
  logo:'./assets/images/home/tia-mini-front.png',
  novaHappy:'./assets/images/home/chick-front.png',
  tiaWelcome:'./assets/images/home/tia-mini-front.png',
  tiaThinking:'./assets/images/home/tia-mini-side.png',
  storyArchive:'./assets/images/home/chick-front-v2.png',
  productionDashboard:'./assets/images/home/chick-back-v2.png',
  promptStudio:'./assets/images/home/chick-front.png',
  musicStudio:'./assets/images/home/chick-back.png',
  universe:'./assets/images/home/tia-mini-back.png'
};
function homeCharacterImage(key,cls,label=''){
  const src=HOME_CHARACTER_IMAGE_PATHS[key];
  const alt=label||({logo:'Nova Studioロゴ',novaHappy:'ノヴァ',tiaWelcome:'ティア',tiaThinking:'考え中のティア',storyArchive:'考え中のノヴァ',productionDashboard:'立っているノヴァ',promptStudio:'きらめくノヴァ',musicStudio:'喜ぶノヴァ',universe:'飛ぶノヴァ'}[key]||'ホーム画像');
  const fallback=HOME_CHARACTER_FALLBACK_PATHS[key]||'';
  return `<figure class="home-character ${cls}" data-character="${esc(key)}"><img src="${src}" alt="${esc(alt)}" loading="eager" decoding="async" data-fallback-src="${fallback}" onerror="if(this.dataset.fallbackSrc&&!this.dataset.fallbackUsed){this.dataset.fallbackUsed='true';this.src=this.dataset.fallbackSrc}else{this.closest('.home-character')?.classList.add('image-missing')}"></figure>`;
}
function homeStudioAction(id,title,desc,action,variant=''){
  return `<article class="atelier-action ${variant}" role="button" tabindex="0" onclick="${action}" onkeydown="if(event.key==='Enter'||event.key===' ')${action}">${homeCharacterImage(id,'action-character',title)}<div class="atelier-action-copy"><h3>${esc(title)}</h3><p>${esc(desc)}</p></div><button class="secondary" onclick="event.stopPropagation();${action}">開く</button></article>`;
}
function homeFeaturedEpisode(p,e){
  return state.episodes.find(x=>x.projectId===p?.id&&x.numberLabel==='第0話')||e;
}
function openFeaturedEpisode(){
  const p=currentProject(),e=homeFeaturedEpisode(p,currentEpisode());
  if(p?.id&&e?.id)selectContext(p.id,e.id);
  openLastLocation();
}
function homeProductionStatus(p,e){
  const featured=homeFeaturedEpisode(p,e);
  return {project:p?.title||'作品未選択',episode:featured?.numberLabel||e?.numberLabel||'話数未選択',status:featured?.productionStatus||featured?.production?.status||p?.productionStatus||featured?.status||p?.status||'制作中'};
}
function homeRecentSummary(){
  const recent=homeRecentItems().slice(0,3);
  return recent.length?recent.map(r=>`<button class="atelier-mini-row" onclick="openHomeRecent('${r.id||''}','${r.collection||''}','${r.item?.id||''}')"><b>${esc(r.title)}</b><small>${esc(TYPE_LABELS[r.type]||typeLabel(r.type)||r.type||'項目')} / ${esc(r.updatedAt||'')}</small></button>`).join(''):'<p class="atelier-empty">最近開いた作品はまだありません。</p>';
}
function homeTaskSummary(){
  const tasks=typeof tasksForProject==='function'?tasksForProject().filter(t=>!t.completed).slice(0,3):[];
  return tasks.length?tasks.map(t=>`<div class="atelier-mini-row static"><b>${esc(t.title||t.body||'タスク')}</b><small>${esc(t.priority||'中')} / ${esc(t.dueDate||'期限なし')}</small></div>`).join(''):'<p class="atelier-empty">今日やることはありません。</p>';
}
function homeSaveSummary(){
  const auto=state.settings?.autoSave?'自動保存オン':'自動保存オフ';
  const saved=state.lastSavedAt||state.updatedAt||'ローカル保存';
  return `<div class="atelier-mini-row static"><b>${esc(auto)}</b><small>${esc(saved)}</small></div>`;
}
function homeBackupSummary(){
  const exported=state.backupStatus?.lastExportedAt||'書き出し履歴なし';
  const imported=state.backupStatus?.lastImportedAt||'読み込み履歴なし';
  return `<button class="atelier-mini-row" onclick="setView('backup')"><b>バックアップ</b><small>書き出し：${esc(exported)} / 読み込み：${esc(imported)}</small></button>`;
}
function homeFooterPanel(title,body,action=''){
  return `<section class="atelier-footer-panel"><div class="section-head"><h2>${esc(title)}</h2>${action}</div>${body}</section>`;
}
homeView=function(){
  const p=currentProject(),e=currentEpisode(),info=homeProductionStatus(p,e);
  return `<main class="atelier-home home-only" aria-label="Nova Studio"><header class="home-logo-bar">${homeCharacterImage('logo','home-logo','Nova Studioロゴ')}</header><section class="atelier-hero" aria-label="ティアへの挨拶"><div class="atelier-hero-copy"><p class="eyebrow">Creative Atelier</p><h1>おかえり、ティア。</h1><p class="atelier-lead">今日は何から始めようか？</p></div><div class="atelier-hero-characters" aria-label="ノヴァとティアのイラスト">${homeCharacterImage('tiaWelcome','tia-welcome','ティア')}${homeCharacterImage('novaHappy','nova-happy','ノヴァ')}</div></section><section class="atelier-continue" role="button" tabindex="0" onclick="openFeaturedEpisode()" onkeydown="if(event.key==='Enter'||event.key===' ')openFeaturedEpisode()"><div><p class="eyebrow">Continue</p><h2>制作を続ける</h2><dl><div><dt>作品名</dt><dd>${esc(info.project)}</dd></div><div><dt>話数</dt><dd>${esc(info.episode)}</dd></div><div><dt>制作状況</dt><dd>${esc(info.status)}</dd></div></dl></div>${homeCharacterImage('tiaThinking','tia-thinking','考え中のティア')}</section><section class="atelier-actions" aria-label="制作メニュー">${homeStudioAction('storyArchive','Story Archive','物語の記憶と設定カードを開く','openStoryArchive()','priority')}${homeStudioAction('productionDashboard','Production Dashboard','作品と話数の進行を確認する','openProductionDashboard()')}${homeStudioAction('promptStudio','Prompt Studio','映像生成プロンプトを整える',"openApp('promptStudio')")}${homeStudioAction('musicStudio','Music Studio','音楽と音の制作へ進む',"openApp('musicStudio')")}${homeStudioAction('universe','Universe','作品世界のつながりを見る',"setView('universe')")}</section><section class="atelier-footer-grid" aria-label="ホーム概要">${homeFooterPanel('最近開いた作品',homeRecentSummary())}${homeFooterPanel('今日やること',homeTaskSummary(),'<button class="secondary" onclick="editTask()">追加</button>')}${homeFooterPanel('保存状況',homeSaveSummary())}${homeFooterPanel('バックアップ',homeBackupSummary())}</section></main>`;
};
render=function(){const v=(location.hash||'#home').slice(1);if(v==='home'){document.querySelector('#app').innerHTML=homeView();return;}nova125RenderBase();};
render();
